/* BASE DE DATOS COMPLETA: 485 PREGUNTAS - SISTEMAS DE MEDIDA Y REGULACIÓN */
const EXAM_DATA = [
    { u: "SMYR T1", q: "¿A dónde se remontan los primeros sistemas de control registrados, como el reloj de agua?", opts: ["A la prehistoria, en el periodo Paleolítico.", "A la Antigua Grecia, con invenciones como la clepsidra.", "A la Edad Moderna, con los primeros telares mecánicos.", "A principios del siglo XX, con la industrialización."], ans: 1, exp: "Los primeros sistemas de control con realimentación registrados datan de la Antigua Grecia, como la clepsidra." },
    { u: "SMYR T1", q: "¿Qué función tiene un sistema de medida en un automatismo?", opts: ["Medir distancias lineales y angulares de las piezas.", "Captar la información de una magnitud física del proceso.", "Recibir y amplificar señales eléctricas de alta potencia.", "Interrumpir el suministro eléctrico ante una sobrecarga."], ans: 1, exp: "Su función es captar y traducir la magnitud física a una señal que el sistema pueda entender." },
    { u: "SMYR T1", q: "El sistema de regulación:", opts: ["Regula mecánicamente la cantidad de caudal que deja pasar.", "Toma decisiones de forma arbitraria sin evaluar el proceso.", "Toma decisiones basándose en la información de la medida.", "Toma decisiones preprogramadas sin evaluar la realimentación."], ans: 2, exp: "El regulador o controlador compara la medida con la consigna para tomar decisiones." },
    { u: "SMYR T1", q: "Indica cuál se corresponde con una DESVENTAJA de un sistema de lazo cerrado con respecto a un lazo abierto:", opts: ["Provocan oscilaciones en el proceso si no se ajustan adecuadamente.", "Incrementan el error en estado estacionario de forma exponencial.", "Se pueden usar cuando es muy caro o difícil medir el valor de la salida.", "Requieren de calibraciones manuales periódicas para evitar el desfase."], ans: 0, exp: "Si la realimentación no está bien ajustada (PID mal sintonizado), el sistema puede volverse inestable u oscilar." },
    { u: "SMYR T1", q: "Indica cuál se corresponde con una DESVENTAJA de un sistema de lazo abierto con respecto a un lazo cerrado:", opts: ["Disminuyen drásticamente el ancho de banda del sistema de control.", "Provocan oscilaciones en el proceso si no se ajustan adecuadamente.", "Requieren calibraciones manuales periódicas para mantener el valor deseado.", "Son mucho más costosos de implementar debido al exceso de sensores."], ans: 2, exp: "Al no medir la salida, el sistema no sabe si está cometiendo errores, exigiendo recalibraciones manuales." },
    { u: "SMYR T1", q: "Indica cuál se corresponde con una VENTAJA de un sistema de lazo cerrado con respecto a un lazo abierto:", opts: ["Incremento notable en la rapidez de respuesta y anchura de banda.", "Simplifican enormemente la programación de los microcontroladores.", "Permiten operar sin la necesidad de sensores físicos en la planta.", "Evitan cualquier tipo de oscilación mecánica durante el arranque."], ans: 0, exp: "El lazo cerrado mejora la precisión, rechaza perturbaciones y aumenta el ancho de banda del sistema." },
    { u: "SMYR T1", q: "Indica cuál se corresponde con una VENTAJA de un sistema de lazo abierto con respecto a un lazo cerrado:", opts: ["Rechazan de manera automática todas las perturbaciones externas.", "Garantizan una estabilidad absoluta sin importar el desgaste.", "Son útiles cuando resulta muy caro o difícil medir el valor de salida.", "Eliminan por completo la necesidad de realizar recalibraciones."], ans: 2, exp: "Al ser más simples y no requerir sensores en la salida, son útiles si la medición es costosa o inviable." },
    { u: "SMYR T1", q: "Indica cuál de los siguientes parámetros NO se utiliza para clasificar los sistemas de control:", opts: ["La presencia o ausencia del bucle de retroalimentación.", "La condición de linealidad o no linealidad de un sistema.", "El tipo de señales de control, ya sean continuas o discretas.", "El tipo de fluido que circula por las tuberías del proceso."], ans: 3, exp: "El fluido es parte del proceso físico, pero no define la teoría de control del sistema." },
    { u: "SMYR T1", q: "Indica qué sistemas de control se utilizan principalmente para el control de procesos continuos:", opts: ["Sistemas de comunicación por bus de campos.", "Reguladores PID de uso industrial estándar.", "Arquitecturas de control basadas íntegramente en PC.", "Autómatas programables o controladores lógicos."], ans: 1, exp: "Los PID son el estándar para variables continuas como temperatura, presión o caudal." },
    { u: "SMYR T1", q: "Indica qué sistemas de control se utilizan principalmente para el control de procesos secuenciales:", opts: ["Sistemas de comunicación por bus de campos.", "Reguladores PID de uso industrial estándar.", "Arquitecturas de control basadas íntegramente en PC.", "Autómatas programables o controladores lógicos."], ans: 3, exp: "Los PLCs (Autómatas programables) están diseñados para lógica de estados y eventos secuenciales." },
    { u: "SMYR T1", q: "¿En qué año implementó Watt los reguladores centrífugos en las máquinas de vapor?", opts: ["En el año 1782.", "En el año 1868.", "En el año 1788.", "En el año 1912."], ans: 2, exp: "James Watt adaptó el regulador centrífugo a la máquina de vapor en 1788." },
    { u: "SMYR T1", q: "¿Qué científico presentó en 1868 el criterio de estabilidad para sistemas lineales dinámicos e invariantes?", opts: ["Pierre-Simon Laplace.", "Jean-Baptiste Fourier.", "James Clerk Maxwell.", "Augustin-Louis Cauchy."], ans: 2, exp: "J.C. Maxwell publicó un análisis matemático formal sobre la estabilidad de los reguladores." },
    { u: "SMYR T1", q: "¿Quién recibió el premio Nobel en 1912 por su estudio de reguladores automáticos para balizas luminosas?", opts: ["James Watt.", "Gustaf Dalén.", "Werner von Siemens.", "Isaac Newton."], ans: 1, exp: "Gustaf Dalén inventó la válvula solar que automatizaba el encendido de los faros." },
    { u: "SMYR T1", q: "¿Qué conflicto bélico fomentó el desarrollo del control de tiro automatizado y el seguimiento de blancos?", opts: ["La Primera Guerra Mundial.", "El periodo de la Guerra Fría.", "La Segunda Guerra Mundial.", "La Guerra de Vietnam."], ans: 2, exp: "La II Guerra Mundial impulsó enormemente los servomecanismos y sistemas de control clásicos." },
    { u: "SMYR T1", q: "En un sistema de lazo cerrado, ¿qué función cumple el bucle de realimentación?", opts: ["Aislar completamente la señal de salida de la señal de entrada.", "Permitir que la salida influya sobre la acción del controlador.", "Reducir significativamente el coste del mantenimiento del sistema.", "Eliminar por completo la necesidad de utilizar sensores de medida."], ans: 1, exp: "Retroalimentar es llevar el valor real a la entrada para compararlo con el deseado." },
    { u: "SMYR T1", q: "¿Qué caracteriza a los sistemas de control discreto?", opts: ["Transmiten información codificada mediante pulsos o formato digital.", "Basan su funcionamiento en señales de tipo continuo en el tiempo.", "Requieren de sistemas exclusivamente analógicos para su procesado.", "Presentan una arquitectura más sencilla que los sistemas continuos."], ans: 0, exp: "En tiempo discreto, la información se actualiza en intervalos (muestreo) y suele ser digital." },
    { u: "SMYR T1", q: "Un sistema que permanece estacionario en el tiempo mientras opera se denomina:", opts: ["Sistema de comportamiento variante.", "Sistema invariante respecto al tiempo.", "Sistema de características no lineales.", "Sistema operado mediante lazo abierto."], ans: 1, exp: "Si sus parámetros físicos (masa, resistencia) no cambian con el tiempo, es invariante." },
    { u: "SMYR T1", q: "¿Por qué una aeronave a velocidad constante es técnicamente un sistema variante con el tiempo?", opts: ["Debido a las alteraciones constantes en su rumbo de navegación.", "Debido a que su masa total varía conforme consume combustible.", "Debido a las perturbaciones generadas por las corrientes de aire.", "Debido a que opera sin un sistema de control de lazo cerrado."], ans: 1, exp: "Al ir perdiendo masa (combustible), las ecuaciones dinámicas del avión cambian." },
    { u: "SMYR T1", q: "En el ámbito industrial, ¿cómo se define a cualquier sistema que deba controlarse (ej. reactor químico)?", opts: ["Elemento controlador principal.", "Dispositivo actuador mecánico.", "Planta física del proceso.", "Sensor de medición óptica."], ans: 2, exp: "La 'planta' es el equipo físico o proceso cuyo comportamiento se quiere controlar." },
    { u: "SMYR T1", q: "Los sistemas que tienen una sola variable de control y una sola variable manipulable se llaman:", opts: ["Sistemas de arquitectura MIMO.", "Sistemas de respuesta lineal.", "Sistemas de arquitectura SISO.", "Sistemas de estado estacionario."], ans: 2, exp: "SISO significa Single Input Single Output (Una entrada, una salida)." },
    { u: "SMYR T1", q: "¿Qué son las variables de control?", opts: ["Variables ambientales que afectan al proceso pero no son controlables.", "Variables manipuladas sobre las que se actúa para regular el sistema.", "Variables de salida que se intentan mantener en un valor deseado.", "Variables temporales que determinan la velocidad de respuesta del sistema."], ans: 2, exp: "Es la variable de salida que queremos estabilizar o dirigir (ej. la temperatura de la sala)." },
    { u: "SMYR T1", q: "¿Qué son las variables manipuladas?", opts: ["Variables de salida que se desean mantener estables en un valor exacto.", "Factores externos e incontrolables que alteran el estado del proceso.", "Magnitudes físicas que son medidas directamente por los sensores del sistema.", "Variables sobre las que el sistema actúa físicamente para regular el proceso."], ans: 3, exp: "Son las variables que el controlador modifica físicamente (ej. el flujo de gas)." },
    { u: "SMYR T1", q: "¿Mediante qué elementos se interfiere físicamente en las variables manipuladas?", opts: ["Mediante el uso de sensores analógicos.", "Mediante el uso de dispositivos actuadores.", "Mediante el uso de circuitos comparadores.", "Mediante el uso de equipos transductores."], ans: 1, exp: "El actuador es el 'músculo' del sistema de control." },
    { u: "SMYR T1", q: "Las perturbaciones se definen como:", opts: ["Variables externas que el sistema puede predecir con gran exactitud.", "Variables que afectan al proceso y escapan a nuestro control directo.", "Señales de error que son generadas internamente en el bloque controlador.", "Alteraciones intencionadas que se introducen en el valor de la consigna."], ans: 1, exp: "Son influencias externas no deseadas (ej. abrir una ventana en una sala con calefacción)." },
    { u: "SMYR T1", q: "¿Qué herramienta matemática convierte el dominio del tiempo en el dominio de la variable compleja 's'?", opts: ["El desarrollo matemático en Serie de Fourier.", "La aplicación de la Transformada de Laplace.", "La formulación de la Ecuación de Newton.", "La simplificación mediante el Álgebra de Boole."], ans: 1, exp: "La Transformada de Laplace simplifica las ecuaciones diferenciales algebraicas." },
    { u: "SMYR T1", q: "Según la tabla de transformadas de Laplace, ¿cuál es la transformada de la función f(t)=1?", opts: ["Su equivalente en Laplace es 1 / s^2.", "Su equivalente en Laplace es la variable s.", "Su equivalente en Laplace es la fracción 1 / s.", "Su equivalente en Laplace es e^(-st)."], ans: 2, exp: "La transformada de la función escalón unitario constante es 1/s." },
    { u: "SMYR T1", q: "¿A qué equivale la integral en el dominio de Laplace?", opts: ["Al producto escalar de la variable s por F(s).", "A la división matemática de la función F(s) entre s.", "Al cálculo de la raíz cuadrada de la función F(s).", "A la derivación directa del polinomio de F(s)."], ans: 1, exp: "Integrar en el tiempo equivale a dividir por 's' en Laplace." },
    { u: "SMYR T1", q: "El orden de un modelo de control viene representado por:", opts: ["La cantidad total de variables de salida del bloque.", "El mayor grado de la derivada en la ecuación principal.", "La suma matemática de las perturbaciones del sistema.", "El tiempo exacto de estabilización de la respuesta libre."], ans: 1, exp: "El orden del sistema define el número de polos de su función de transferencia." },
    { u: "SMYR T1", q: "El estándar de comunicación industrial que busca dar transparencia y datos en tiempo real es:", opts: ["La red de interconexión AS-i Interface.", "El bus de campo de arquitectura Profibus.", "El protocolo industrial conocido como Ethernet.", "El sistema de instrumentación óptica FIPIO."], ans: 2, exp: "Industrial Ethernet se ha convertido en la red estándar para control a tiempo real." },
    { u: "SMYR T1", q: "¿Qué dispositivo convierte una magnitud física en señal eléctrica utilizable en un sistema de control?", opts: ["El dispositivo actuador de potencia.", "El controlador lógico programable.", "El equipo transductor de señales.", "El bloque comparador de errores."], ans: 2, exp: "El transductor traduce la energía de un dominio físico a un dominio eléctrico (señal)." },
    { u: "SMYR T1", q: "¿Qué plataforma online permite simular circuitos electrónicos y programar Arduino para aprender sistemas de control?", opts: ["El software de cálculo avanzado Matlab.", "El entorno de simulación abierta Scilab.", "La plataforma online de diseño Tinkercad.", "El programa de diseño paramétrico AutoCAD."], ans: 2, exp: "Tinkercad ofrece simulación visual de electrónica y microcontroladores." },
    { u: "SMYR T1", q: "¿Qué matemático terminó de asentar las bases de la transformación matemática poco después de Laplace y Fourier?", opts: ["El físico escocés James Clerk Maxwell.", "El matemático francés Augustin-Louis Cauchy.", "El científico británico Sir Isaac Newton.", "El ingeniero industrial sueco Gustaf Dalén."], ans: 1, exp: "Augustin-Louis Cauchy formalizó el cálculo con variables complejas." },
    { u: "SMYR T1", q: "En el sistema de regulación del siglo II AC para una lámpara de aceite, ¿qué ocurría cuando el nivel de aceite bajaba?", opts: ["Se activaba una alarma sonora rudimentaria para advertir del bajo nivel.", "Ingresaba aire a un depósito secundario que suministraba más aceite.", "Un contrapeso apagaba la llama automáticamente por razones de seguridad.", "Un operario encargado debía intervenir y rellenar el tanque manualmente."], ans: 1, exp: "El aire actuaba como un primitivo mecanismo de control de flujo por presión." },
    { u: "SMYR T1", q: "¿Cuál es una causa común de la 'saturación' que provoca comportamientos no lineales en la práctica?", opts: ["La inyección continua de señales de entrada de muy baja amplitud.", "La operación prolongada del sistema en condiciones de vacío absoluto.", "La presencia de rozamiento o desajustes mecánicos en los engranajes.", "La total ausencia de perturbaciones externas durante el funcionamiento."], ans: 2, exp: "El roce, la histéresis y la holgura en los engranajes son fuentes de no-linealidad." },
    { u: "SMYR T1", q: "¿Con qué objetivo se introducen a veces características no lineales de forma intencionada en un sistema?", opts: ["Para incrementar de forma artificial la complejidad matemática del modelo.", "Para reducir drásticamente el coste de instalación limitando los sensores.", "Para mejorar el desempeño y la efectividad general del sistema de control.", "Para prescindir definitivamente del uso de la Transformada de Laplace."], ans: 2, exp: "A veces el control 'on-off' (todo o nada) es más efectivo y económico que uno lineal continuo." },
    { u: "SMYR T1", q: "Según la tabla de transformadas, ¿cuál es la expresión para f(t)=e^(at)?", opts: ["Equivale a la expresión de 1 / (s + a).", "Equivale a la expresión de 1 / (s - a).", "Equivale a la expresión de s / (s - a).", "Equivale a la expresión de n! / s^(n+1)."], ans: 1, exp: "La exponencial en el tiempo desplaza el polo en el plano complejo s." },
    { u: "SMYR T1", q: "¿Cuál es la transformada de Laplace de la función f(t)=sen(ωt)?", opts: ["Se representa con la expresión s / (s^2 + ω^2).", "Se representa con la expresión ω / (s^2 + ω^2).", "Se representa con la expresión fraccionaria 1 / s^2.", "Se representa con la expresión fraccionaria ω / s."], ans: 1, exp: "El seno genera un par de polos imaginarios puros." },
    { u: "SMYR T1", q: "En el dominio de Laplace, ¿qué propiedad indica que la suma de funciones en el tiempo es igual a la suma de sus transformadas?", opts: ["El teorema relativo a la propiedad de estabilidad absoluta.", "El principio fundamental dictado por la propiedad de linealidad.", "El teorema aplicado a la propiedad matemática de la derivación.", "El principio establecido dentro de la propiedad de convolución."], ans: 1, exp: "Es el pilar fundamental que permite superponer respuestas en sistemas lineales." },
    { u: "SMYR T1", q: "Dentro de un transductor, ¿cuál es la función específica del 'transmisor'?", opts: ["Ejecutar la medición física directa de las variables del proceso.", "Transformar la información captada en una señal computable estandarizada.", "Calcular de forma continua la diferencia entre la salida y la referencia.", "Ejecutar una acción de fuerza directa sobre la válvula de control principal."], ans: 1, exp: "El transmisor estandariza la señal (ej. 4-20mA) para ser enviada al controlador." },
    { u: "SMYR T1", q: "¿Cuál de los siguientes es un ejemplo directo de un 'actuador'?", opts: ["Un sensor de temperatura termoeléctrico conocido como termopar.", "Una sonda de precisión fabricada mediante resistencia de platino.", "Un dispositivo de intercambio térmico o una bomba de propulsión.", "Un bloque de cálculo lógico utilizado para la comparación de señales."], ans: 2, exp: "Las bombas y motores ejecutan el esfuerzo físico en la planta." },
    { u: "SMYR T1", q: "En el ejemplo de la caldera, si el agua sale más fría de lo normal, ¿sobre qué variable actúa el serpentín térmico?", opts: ["Modifica directamente el comportamiento de la variable de control.", "Actúa mecánicamente para compensar la perturbación externa limitante.", "Ejerce su acción de corrección sobre la variable principal manipulada.", "Altera el valor de la referencia de temperatura programada por el usuario."], ans: 2, exp: "El serpentín modifica el calor aportado, que es la variable manipulada." },
    { u: "SMYR T1", q: "¿Cuál es el primer paso recomendado para simplificar y resolver una ecuación diferencial de control?", opts: ["Resolver cálculos de tipo algebraico operando en el dominio del tiempo.", "Transformar la ecuación matemática al dominio complejo de Laplace.", "Suprimir de forma manual todas las perturbaciones térmicas del sistema.", "Registrar el comportamiento oscilatorio utilizando un sensor digital."], ans: 1, exp: "Las integrales y derivadas se vuelven simples divisiones y multiplicaciones por 's'." },
    { u: "SMYR T1", q: "¿Para qué se utiliza específicamente el bus 'AS-i Interface'?", opts: ["Para interconectar estaciones de trabajo orientadas a la gestión informática.", "Para vincular de forma directa captadores y accionadores del tipo todo o nada.", "Para procesar operaciones matemáticas complejas sobre señales analógicas.", "Para reemplazar completamente la estructura clásica de los reguladores PID."], ans: 1, exp: "Actuator Sensor Interface (AS-i) es para conectar dispositivos binarios simples." },
    { u: "SMYR T1", q: "Los buses de campo como Profibus e Interbus se clasifican como:", opts: ["Redes informáticas dedicadas al nivel de gestión administrativa.", "Redes industriales orientadas al nivel de célula y de campo operativo.", "Sistemas de interconexión concebidos para señales puramente analógicas.", "Protocolos de comunicación de uso común en redes de área local y ocio."], ans: 1, exp: "Son redes industriales para interconectar sensores complejos y controladores." },
    { u: "SMYR T1", q: "¿Qué ejemplo corresponde a un sistema de lazo abierto?", opts: ["Una lavadora programada por tiempo que no detecta el nivel de suciedad.", "Un regulador de tipo PID controlando la temperatura interna de un horno.", "Un sistema de calefacción guiado mediante un termostato de pared clásico.", "Un ascensor automatizado que cuenta con sensores de posición por planta."], ans: 0, exp: "Al no tener un 'sensor de suciedad', la máquina funciona a ciegas (lazo abierto)." },
    { u: "SMYR T1", q: "¿Qué caracteriza a una señal digital en sistemas de control?", opts: ["Posee la capacidad inherente de adoptar infinitos valores intermedios.", "Opera exclusivamente utilizando los estados lógicos fundamentales cero y uno.", "Presenta una mayor precisión bruta comparada con una señal analógica sin filtrar.", "Carece de la arquitectura necesaria para codificar información de alta complejidad."], ans: 1, exp: "La señal digital pura es binaria (Todo/Nada)." },
    { u: "SMYR T1", q: "¿Qué caracteriza a una señal digital en sistemas de control?", opts: ["Puede tomar infinitos valores.", "Solo toma valores 0 y 1.", "Siempre es más precisa que una analógica sin procesar.", "No puede codificar información compleja."], ans: 1, exp: "La señal digital pura es binaria (Todo/Nada)." },
    { u: "SMYR T2", q: "En el Puente de Wheatstone, si se busca el valor de Rx para que el centro sea nulo, la fórmula es:", opts: ["Rx = (R1+R2)/R3", "Rx = (R2/R1)*R3", "Rx = (R1*R2)/R3", "Rx = R1/(R2*R3)"], ans: 1, exp: "El puente se equilibra cuando la relación de resistencias cruzadas se iguala." },
    { u: "SMYR T2", q: "¿Qué sensor de temperatura se basa en un material semiconductor cuya resistencia varía con la temperatura y no es lineal?", opts: ["El sensor RTD basado en hilo de platino puro.", "El termistor fabricado con material semiconductor.", "El pirómetro de captación de radiación óptica.", "El termopar de tipo K con metales estándar."], ans: 1, exp: "Los termistores (NTC y PTC) son semiconductores con una curva de resistencia muy pronunciada y no lineal." },
    { u: "SMYR T2", q: "¿Qué mide un pirómetro de radiación?", opts: ["El diferencial de voltaje generado entre dos metales.", "La intensidad principal de radiación electromagnética.", "La variación de presión estática en una tubería.", "El nivel volumétrico de sólidos en un depósito."], ans: 1, exp: "Mide la radiación infrarroja que emite un cuerpo a distancia para determinar su temperatura." },
    { u: "SMYR T2", q: "¿Qué tipo de transductor de presión se recomienda cuando se requiere una precisión muy elevada?", opts: ["El transductor de tipo puramente mecánico.", "El transductor de tipo electromecánico piezoeléctrico.", "El transductor de estado sólido totalmente electrónico.", "El transductor basado en fuelles de tipo neumático."], ans: 2, exp: "Los transductores de presión electrónicos ofrecen la mayor precisión del mercado actual." },
    { u: "SMYR T2", q: "Un caudalímetro de 'fuerza o impacto' calcula el caudal mediante:", opts: ["La diferencia de presión en un estrechamiento calibrado.", "La fuerza que ejerce el fluido al chocar contra un elemento.", "La desviación de un haz de luz láser en el flujo laminar.", "El rebote térmico de los pulsos ultrasónicos emitidos."], ans: 1, exp: "El fluido choca físicamente contra un elemento mecánico (como una turbina) haciendo que gire." },
    { u: "SMYR T2", q: "En un control Proporcional (P), si la función de transferencia es de primer grado, ¿por qué el sistema nunca alcanza el valor de consigna?", opts: ["Porque el exceso de potencia del actuador genera sobreoscilaciones.", "Porque el sistema se estaciona en un valor distinto (error u offset).", "Porque la transformada de Laplace no contempla inercias térmicas.", "Porque existen errores en el muestreo de las señales digitales."], ans: 1, exp: "El control P puro necesita un error persistente para mantener la salida, dejando un error permanente." },
    { u: "SMYR T2", q: "¿Qué término se define como el tiempo que tarda el sistema en alcanzar el punto de consigna en un control PI?", opts: ["El parámetro de tiempo derivativo (Td).", "El parámetro de tiempo integral (Ti).", "El parámetro de ganancia proporcional (Kp).", "El parámetro de brecha diferencial (Bd)."], ans: 1, exp: "El tiempo integral (Ti) determina la velocidad con la que la acción integral anula el error." },
    { u: "SMYR T2", q: "¿Qué empresa desarrolla microprocesadores específicos destinados a la regulación y control de motores eléctricos?", opts: ["La corporación tecnológica Analog Devices.", "El conglomerado industrial nipón Hitachi.", "La pionera en semiconductores Texas Instruments.", "El gigante de automatización europea Siemens."], ans: 2, exp: "Texas Instruments es pionera en microcontroladores DSP para control de motores." },
    { u: "SMYR T2", q: "La estabilidad absoluta de un sistema se puede analizar viendo los exponentes de la función del tiempo. El sistema es estable si:", opts: ["Todos los exponentes calculados son menores que cero.", "Todos los exponentes calculados son mayores que cero.", "Al menos uno de los exponentes tiende a infinito.", "La constante temporal se aproxima asintóticamente a cero."], ans: 0, exp: "Los exponentes deben ser negativos para que la respuesta transitoria decaiga y el sistema se estabilice." },
    { u: "SMYR T2", q: "¿Qué mide la 'estabilidad relativa'?", opts: ["El error permanente en estado estacionario del ciclo.", "La rapidez y oscilación hacia un régimen permanente.", "La energía eléctrica total consumida por el actuador.", "La frecuencia natural con la que resuena el motor."], ans: 1, exp: "Indica cómo de rápido y con cuánta oscilación llega el sistema a su estado de equilibrio." },
    { u: "SMYR T2", q: "¿Cuál es la unidad del Sistema Internacional (SI) para la Intensidad Luminosa?", opts: ["La unidad fundamental Amperio.", "La unidad fundamental Mol.", "La unidad fundamental Candela.", "La unidad fundamental Kelvin."], ans: 2, exp: "La Candela es la unidad fundamental de intensidad luminosa en el SI." },
    { u: "SMYR T2", q: "En unidades de presión, ¿qué relación es correcta?", opts: ["1 bar equivale matemáticamente a 1 Pascal.", "100.000 Pascales equivalen exactamente a 1 bar.", "1 MegaPascal representa exactamente 1 bar.", "1 kiloPascal corresponde exactamente a 10 bares."], ans: 1, exp: "1 bar equivale exactamente a cien mil Pascales." },
    { u: "SMYR T2", q: "¿Qué sucede en un amplificador operacional cuando se usa como 'comparador de ventana'?", opts: ["Un elemento pasivo limita drásticamente la tensión.", "Dos comparadores vigilan el rango entre un máximo y mínimo.", "El circuito convierte la señal analógica en binaria digital.", "La etapa amplifica desproporcionadamente el ruido base."], ans: 1, exp: "Genera una señal lógica válida si el valor de entrada se encuentra dentro de una 'ventana' de tensión." },
    { u: "SMYR T2", q: "¿Qué es la 'brecha diferencial' en un control Todo-Nada?", opts: ["El tiempo de retardo mecánico del pulsador operativo.", "El rango entre dos valores antes de conmutar por histéresis.", "La desviación estática medida entre actuador y planta.", "El factor de error derivativo presente en el bloque PID."], ans: 1, exp: "Evita el encendido y apagado continuo del actuador cuando la medida está muy cerca de la consigna." },
    { u: "SMYR T2", q: "La fórmula de la presión es P=F/S. ¿Qué unidades forman el Pascal (Pa)?", opts: ["Unidades fundamentales compuestas por kg · m/s", "Unidades fundamentales compuestas por kg / (m · s^2)", "Unidades fundamentales compuestas por N · m / s", "Unidades fundamentales compuestas por m^2 / kg"], ans: 1, exp: "Como Newton = kg·m/s^2, al dividir entre m^2 queda kg / (m·s^2)." },
    { u: "SMYR T2", q: "¿Qué se entiende por 'Luz Monocromática' en los sensores láser?", opts: ["Un haz compuesto por la mezcla de todas las frecuencias.", "Un haz con componentes de un solo color y longitud de onda.", "Un espectro que varía su frecuencia en función del entorno.", "Una fuente lumínica invisible perteneciente al ultravioleta."], ans: 1, exp: "El láser emite una luz coherente de una única longitud de onda." },
    { u: "SMYR T2", q: "El efecto de un termopar donde se genera voltaje por diferencia de temperatura se conoce como:", opts: ["Fenómeno físico conocido como Efecto Doppler.", "Fenómeno físico conocido como Efecto Seebeck.", "Fenómeno físico conocido como Efecto Hall.", "Fenómeno físico conocido como Efecto Joule."], ans: 1, exp: "El efecto Seebeck es el principio físico que permite medir temperatura con dos metales distintos." },
    { u: "SMYR T2", q: "En un sistema de lazo cerrado, ¿cuál es el objetivo de reducir la 'sensitividad'?", opts: ["Hacer que el sistema deje de responder a perturbaciones útiles.", "Volver el diseño más tolerante a variaciones en sus componentes.", "Incrementar intencionadamente el margen de error estacionario.", "Restringir el ancho de banda del bloque amplificador digital."], ans: 1, exp: "Un sistema robusto debe mantener su funcionamiento aunque sus piezas envejezcan o cambien levemente." },
    { u: "SMYR T2", q: "¿Qué magnitud física fundamental tiene como unidad el Amperio (A)?", opts: ["La medida de cantidad de sustancia química.", "El registro de intensidad de corriente eléctrica.", "La magnitud absoluta de intensidad luminosa.", "La inercia derivada del aumento de la masa."], ans: 1, exp: "El Amperio es la unidad del Sistema Internacional para la corriente." },
    { u: "SMYR T2", q: "¿Cuál es el rango de temperatura para un termopar tipo T (Cobre-Constantán)?", opts: ["El rango operativo comprende de -190 a 1371 ºC.", "El rango operativo comprende de -200 a 400 ºC.", "El rango operativo comprende de 0 a 1600 ºC.", "El rango operativo comprende de 0 a 1800 ºC."], ans: 1, exp: "Es el termopar recomendado para mediciones de baja temperatura, llegando hasta 400 ºC." },
    { u: "SMYR T2", q: "¿Cuál de los siguientes no se corresponde con un elemento de control?", opts: ["El bloque principal del amplificador.", "El mecanismo de fuerza o actuador.", "El ser humano actuando como operario.", "El equipo intermedio de transductor."], ans: 2, exp: "En un sistema de control automático, el operario humano no forma parte del bucle de control." },
    { u: "SMYR T2", q: "¿Cuál de los siguientes sistemas no sirve para medir el nivel?", opts: ["La arquitectura de sensor capacitivo.", "El dispositivo de fuerza o impacto dinámico.", "El instrumento basado en ondas de ultrasonidos.", "El mecanismo perimetral óptico e infrarrojo."], ans: 1, exp: "Los sistemas de fuerza o impacto (como las turbinas) miden caudal, no nivel." },
    { u: "SMYR T2", q: "¿Por qué un semáforo es un ejemplo de lazo abierto?", opts: ["Porque actúa sin medir el estado del tráfico existente.", "Porque está limitado a mostrar tres salidas visuales.", "Porque depende de una tarjeta lógica no realimentada.", "Porque utiliza detectores de peso bajo el asfalto."], ans: 0, exp: "El semáforo funciona por tiempo programado, ignorando si hay o no coches esperando." },
    { u: "SMYR T2", q: "El puente de Wheatstone se utiliza típicamente como:", opts: ["Dispositivo de medición y transductor termopar activo.", "Sensor capacitivo empleado en la medición de nivel.", "Regulador de lazo cerrado para velocidad angular.", "Acondicionador para transductores resistivos o de temperatura."], ans: 3, exp: "A menudo se utiliza condicionado para traducir mediciones de temperatura de RTDs o termistores." },
    { u: "SMYR T2", q: "El termopar obtiene la señal eléctrica a partir:", opts: ["De la inyección de tensión en una resistencia disipadora.", "De la variación de resistencia de un compuesto cerámico.", "De la diferencia térmica entre dos uniones de metales.", "De la absorción directa de radiación espectral lumínica."], ans: 2, exp: "Funciona uniendo dos metales distintos (Efecto Seebeck)." },
    { u: "SMYR T2", q: "La estabilidad de un sistema es un factor imprescindible para:", opts: ["Evitar la degradación térmica en los disipadores.", "Reducir a cero el error de régimen permanente.", "Inhibir las señales de control proporcional o integral.", "Prevenir oscilaciones y acotar la salida generada."], ans: 3, exp: "Un sistema estable no oscila infinitamente y devuelve una salida controlada y finita." },
    { u: "SMYR T2", q: "La existencia de un bucle de retroalimentación (bucle cerrado):", opts: ["Dificulta el diseño al anular la acción del bloque integral.", "Estabiliza el sistema independientemente de los ajustes PID.", "Genera oscilaciones irremediables en los servomecanismos.", "Aumenta la exactitud y amortigua perturbaciones si se ajusta bien."], ans: 3, exp: "Aunque mejora casi todo, si se diseña mal, el sistema de lazo cerrado se vuelve inestable." },
    { u: "SMYR T2", q: "La ventaja de un controlador PID es:", opts: ["Mejorar el régimen transitorio evaluando la rapidez de variación del error.", "Anular el bloque derivativo para reducir el desgaste en el actuador final.", "Excluir factores temporales para evitar retrasos en el microcontrolador.", "Eliminar el error permanente prescindiendo del cálculo de la integral."], ans: 0, exp: "La parte derivativa (D) reacciona a la velocidad de cambio, mejorando la respuesta transitoria." },
    { u: "SMYR T2", q: "Un controlador PI tiene las funciones:", opts: ["Exclusivamente la de compensación matemática Proporcional.", "Las combinadas de acción Proporcional y acción Integral.", "La triple rutina algorítmica de Proporcional, Integral y Derivativo.", "El ajuste discreto e histérico propio de un mando Todo-Nada."], ans: 1, exp: "PI significa Proporcional e Integral." },
    { u: "SMYR T2", q: "¿Qué componente de la cadena de medida se encarga de percibir directamente la magnitud física?", opts: ["El módulo transmisor secundario.", "El bloque operacional amplificador.", "El sensor o detector primario.", "El puente acondicionador resistivo."], ans: 2, exp: "El sensor capta la información de primera mano en la planta." },
    { u: "SMYR T2", q: "¿Cuál es la función principal del 'Transmisor' en un proceso de regulación?", opts: ["Comparar la señal entrante con la referencia de consigna.", "Convertir el valor censado a una señal eléctrica normalizada.", "Elevar el voltaje bruto para excitar motores de alto consumo.", "Calcular de forma autónoma el factor de corrección de error."], ans: 1, exp: "El transmisor envía la señal a grandes distancias mediante estándares como 4-20mA." },
    { u: "SMYR T2", q: "En un sistema de lazo cerrado, ¿qué elemento calcula la diferencia (error) entre la referencia y la salida?", opts: ["La unidad de fuerza y actuación.", "El bloque lógico o comparador.", "El elemento de lectura o sensor.", "El módulo puente y amplificador."], ans: 1, exp: "El comparador halla el error (Error = Consigna - Medida real)." },
    { u: "SMYR T2", q: "¿Qué caracteriza fundamentalmente a un sistema de lazo abierto?", opts: ["La salida corrige constantemente cualquier variación inesperada.", "Carece de una realimentación que mida e influya en el control.", "Ofrece un margen de estabilidad superior frente a ruidos.", "Requiere invariablemente un bucle de corriente normalizado."], ans: 1, exp: "El sistema no comprueba si ha realizado bien la tarea encomendada." },
    { u: "SMYR T2", q: "¿Qué componente se utiliza para aumentar la intensidad de la señal y facilitar la detección de errores?", opts: ["El módulo de transducción óptica.", "El acondicionador digital básico.", "El amplificador de instrumentación.", "El circuito selector multiplexor."], ans: 2, exp: "Es muy común usar amplificadores a la salida de sensores que generan señales muy débiles." },
    { u: "SMYR T2", q: "¿Qué es un transductor según la definición técnica de la unidad?", opts: ["Un conjunto que genera enormes cantidades de energía residual.", "Un sensor exclusivamente especializado en gradientes térmicos.", "Un mecanismo capaz de transformar un tipo de energía en otro.", "Un protocolo de transmisión por cableado de red industrial."], ans: 2, exp: "Traduce una magnitud física a una magnitud eléctrica interpretable." },
    { u: "SMYR T2", q: "En los encoders integrales (ópticos), ¿de qué depende la precisión de la medida?", opts: ["Del rango frecuencial de la luz del emisor.", "De la cantidad total de ranuras del disco.", "Del par límite y velocidad angular del motor.", "De las pérdidas por resistencia en el cableado."], ans: 1, exp: "Cuantas más marcas o ranuras tenga el disco, mejor será su resolución angular." },
    { u: "SMYR T2", q: "¿Qué tipo de luz utiliza un sensor láser para medir distancias?", opts: ["Una fuente lumínica mixta o luz policromática blanca.", "Un haz estrecho compuesto por luz pura y monocromática.", "Un foco difusor térmico basado en óptica infrarroja.", "Un emisor focalizado de ráfagas ultravioletas de pulso."], ans: 1, exp: "El láser tiene una sola longitud de onda, lo que evita que el haz se disperse." },
    { u: "SMYR T2", q: "¿Qué ventaja principal tienen las resistencias de platino (como la PT100) sobre los termistores?", opts: ["Ofrecen un coste de adquisición significativamente menor.", "Garantizan una relación lineal entre resistencia y calor.", "Embarcan electrónica interna de acondicionamiento de red.", "Consisten en chips semiconductores exentos de desgaste."], ans: 1, exp: "Su curva es prácticamente una línea recta, facilitando mucho su lectura." },
    { u: "SMYR T2", q: "El 'efecto Seebeck' es el principio de funcionamiento de:", opts: ["Las resistencias variables PTC y NTC.", "Los hilos captadores de platino PT100.", "Las uniones metálicas tipo termopar.", "Las lentes infrarrojas del pirómetro."], ans: 2, exp: "La unión de metales distintos a distinta temperatura genera una tensión eléctrica." },
    { u: "SMYR T2", q: "¿Qué transductor de presión se recomienda para obtener una precisión muy elevada?", opts: ["Los diseños tradicionales fundamentados en la flexión mecánica.", "Los equipos de instrumentación avanzados puramente electrónicos.", "Los modelos de arquitectura híbrida y respuesta electromecánica.", "Los dispositivos analógicos calibrados por diferencial de columna."], ans: 1, exp: "Son los más exactos al no tener desgaste mecánico." },
    { u: "SMYR T2", q: "Los caudalímetros que utilizan la ley de inducción de Faraday (electromagnéticos) tienen la ventaja de ser:", opts: ["Sistemas fabricados con polímeros y de extremada economía.", "Instrumentos que operan sin invadir u obstruir la tubería.", "Aparatos concebidos exclusivamente para flujos de gas licuado.", "Mecanismos que detectan variaciones de presión diferencial."], ans: 1, exp: "Miden mediante campos magnéticos, sin estrechar la tubería." },
    { u: "SMYR T2", q: "¿Qué sistema de medición de nivel es más adecuado para productos granulados o en polvo?", opts: ["La arquitectura electromecánica del interruptor de boya o flotador.", "La medición fundamentada en las placas de un sistema capacitivo.", "La detección de tiempos de vuelo efectuada por ondas ultrasonidos.", "La evaluación estática comparada a través de presión diferencial."], ans: 1, exp: "Los flotadores se hundirían o bloquearían; el capacitivo detecta el cambio de masa." },
    { u: "SMYR T2", q: "¿En qué se basan habitualmente los comparadores eléctricos?", opts: ["En compuertas controladas exclusivamente por estados lógicos binarios.", "En la distribución lograda por circuitos puente y divisor de tensión.", "En sistemas informáticos complejos regidos mediante lógica difusa.", "En parches piezorresistivos aplicados como galgas extensiométricas."], ans: 1, exp: "Los puentes de resistencias comparan voltajes analógicos de manera fiable." },
    { u: "SMYR T2", q: "¿Qué función cumple un 'comparador de ventana'?", opts: ["Verifica si un parámetro fluctúa acotado entre un margen definido.", "Establece el límite máximo permisible en canales de flujo de aire.", "Atenúa ruidos de alta frecuencia procedentes de los medidores.", "Traduce una entrada analógica continua a una salida hexadecimal."], ans: 0, exp: "Actúa solo si la señal está entre un 'mínimo' y un 'máximo' determinados." },
    { u: "SMYR T2", q: "En un controlador Todo-Nada (On-Off), ¿qué sucede cuando la variable de salida alcanza el valor de referencia?", opts: ["El algoritmo rebaja la potencia siguiendo una función decreciente.", "El actuador de la instalación conmuta cambiando su estado lógico.", "El compensador asegura de inmediato un error estacionario nulo.", "El bucle integral asume la estabilización de los desvíos menores."], ans: 1, exp: "Un control Todo-Nada solo tiene dos niveles de actuación (0% o 100%)." },
    { u: "SMYR T2", q: "¿Cuál es el principal inconveniente de un control puramente Proporcional (P)?", opts: ["Provoca ineludiblemente inestabilidad por oscilación persistente.", "Incapacita al automatismo para cancelar el error en régimen permanente.", "Perjudica de manera drástica el factor de respuesta ante perturbaciones.", "Requiere forzosamente componentes electrónicos de altísimo procesamiento."], ans: 1, exp: "El control P no puede anular por completo el error porque necesita que exista para actuar." },
    { u: "SMYR T2", q: "¿Qué acción de control se añade para eliminar el error en régimen permanente?", opts: ["El parámetro corrector evaluado mediante la Acción Proporcional.", "El parámetro de anticipación propio de la Acción Derivativa.", "La ponderación de tiempos implementada por la Acción Integral.", "El sistema de estados binarios perteneciente al control Todo-Nada."], ans: 2, exp: "Acumula el error en el tiempo, obligando al sistema a corregir esa pequeña desviación residual." },
    { u: "SMYR T2", q: "La acción derivativa en un PID tiene como objetivo principal:", opts: ["Cerrar el lazo asumiendo la eliminación del error estacional definitivo.", "Atajar la evolución rápida para pulir la respuesta dinámica transitoria.", "Aminorar la huella energética reduciendo la fricción del equipo motor.", "Subsanar los desajustes no lineales causados por envejecimiento térmico."], ans: 1, exp: "Frena la respuesta del sistema si este se está acercando demasiado rápido a la consigna." },
    { u: "SMYR T2", q: "¿Cuáles son los rangos de señales analógicas normalizadas más comunes en la industria?", opts: ["El intervalo acotado de 0 a 5 V o su equivalente en red de 0 a 20 mA.", "El intervalo acotado de 0 a 10 V o su equivalente en red de 4 a 20 mA.", "El intervalo acotado de 1 a 5 V o su equivalente en red de 0 a 100 mA.", "El intervalo acotado de 4 a 20 V o su equivalente en red de 0 a 10 mA."], ans: 1, exp: "El estándar industrial global para transmitir medidas a distancia." },
    { u: "SMYR T2", q: "¿Qué caracteriza a una señal digital en sistemas de control?", opts: ["Muestra capacidad operativa para fluctuar en todo su rango continuo.", "Desarrolla su comportamiento físico bajo la condición de dos únicos estados.", "Presenta anomalías que la hacen altamente susceptible al ruido estático.", "Carece de integración para operar en entornos gestionados por autómatas."], ans: 1, exp: "Las señales digitales son binarias." },
    { u: "SMYR T2", q: "Técnicamente, ¿cuándo se considera que un sistema es estable?", opts: ["En el momento que las variables de entrada y salida son exactamente idénticas.", "Si sometido a una variable de entrada limitada se obtiene una salida finita.", "Solo cuando opera bajo aislamiento de perturbaciones ambientales acústicas.", "En aquellos escenarios donde es regulado por potentes arquitecturas PID."], ans: 1, exp: "Criterio de estabilidad BIBO: Una entrada finita no debe producir una salida infinita." },
    { u: "SMYR T2", q: "¿Qué parámetro define el error de un sistema cuando este trabaja en régimen permanente?", opts: ["El coeficiente dinámico relativo.", "El vector temporal de seguimiento.", "El índice final de exactitud o precisión.", "El valor numérico derivativo."], ans: 2, exp: "Un sistema preciso es aquel que se estabiliza exactamente en el punto deseado." },
    { u: "SMYR T2", q: "¿Cuál es la unidad fundamental de temperatura en el Sistema Internacional (SI)?", opts: ["El Grado centígrado o Celsius.", "El Grado imperial o Fahrenheit.", "La magnitud absoluta de Kelvin.", "La magnitud americana de Rankine."], ans: 2, exp: "El Kelvin es la base termodinámica de temperatura." },
    { u: "SMYR T2", q: "La presión se define como el cociente entre:", opts: ["La variable masa y la variable de volumen.", "La variable fuerza y la variable de área o superficie.", "La variable energía y la variable absoluta de tiempo.", "La variable inercia y la variable de aceleración física."], ans: 1, exp: "P = Fuerza / Área." },
    { u: "SMYR T2", q: "¿A cuántos Pascales (Pa) equivale aproximadamente 1 bar?", opts: ["A la equivalencia estándar de 1.000 Pa.", "A la equivalencia estándar de 10.000 Pa.", "A la equivalencia estándar de 100.000 Pa.", "A la equivalencia estándar de 1.000.000 Pa."], ans: 2, exp: "1 bar son cien mil Pascales o 100 kPa." },
    { u: "SMYR T2", q: "¿Qué magnitud física fundamental tiene el 'Amperio (A)' como unidad?", opts: ["La carga residual del campo eléctrico.", "La diferencia de potencial de un tendido.", "La intensidad portadora de corriente eléctrica.", "La oposición del medio resistivo conductor."], ans: 2, exp: "El Amperio mide la intensidad de corriente que circula por un conductor." },
    { u: "SMYR T2", q: "¿Qué caracteriza a un sistema de lazo cerrado?", opts: ["El actuador descarta por completo las lecturas proporcionadas a la salida.", "El proceso suprime de su configuración física la instrumentación sensora.", "El bucle recurre a una comprobación retrospectiva para mitigar desviaciones.", "El diseño simplifica la topología resultando infinitamente más económico."], ans: 2, exp: "La realimentación toma la lectura real y la devuelve al controlador." },
    { u: "SMYR T2", q: "¿Cuál es una ventaja principal de los sistemas de lazo abierto?", opts: ["Brindan soluciones con tolerancias mínimas o errores nulos.", "Destacan por sus arquitecturas sencillas y gastos inferiores.", "Generan correcciones instantáneas frente a picos transitorios.", "Poseen un elevado índice de inmunidad contra interferencias."], ans: 1, exp: "Al no tener sensores ni lazo de realimentación, son muy baratos de fabricar." },
    { u: "SMYR T2", q: "En un sistema de control, ¿qué son las variables manipuladas?", opts: ["Los valores de consigna que determinan el estado ideal permanente del equipo.", "Los eventos fortuitos producidos por variaciones impredecibles externas.", "Los registros analógicos obtenidos por medio de la electrónica del transductor.", "Los parámetros físicos que modificamos para poder estabilizar todo el proceso."], ans: 3, exp: "Son las que el actuador modifica (como la válvula de gas de una caldera)." },
    { u: "SMYR T2", q: "¿Qué dispositivo convierte una magnitud física en señal eléctrica utilizable en un sistema de control?", opts: ["La bomba o motor de tipo actuador.", "El autómata o procesador controlador.", "El módulo codificador de tipo transductor.", "El elemento evaluador de tipo comparador."], ans: 2, exp: "El transductor es el encargado de traducir magnitudes físicas a eléctricas." },
    { u: "SMYR T2", q: "¿Qué ejemplo corresponde a un sistema de lazo abierto?", opts: ["Una lavadora que funciona con tiempos fijos asumiendo que la prenda quedará limpia.", "Una temperatura industrial gestionada con algoritmos de sintonía integral derivativa.", "Una estufa convencional que monitoriza el aire circundante con un sensor empotrado.", "Una plataforma elevadora dotada de interruptores ópticos para detectar cada piso."], ans: 0, exp: "Funciona por un tiempo fijo sin medir si ha cumplido el objetivo final." },
    { u: "SMYR T2", q: "¿Qué tipo de sensor es un termopar?", opts: ["Un conjunto de metales dispares que generan voltaje ante un diferencial térmico.", "Un filamento cerámico de coeficiente variable en base a la concentración óptica.", "Un emisor acústico capaz de inferir magnitudes registrando ecos rebotados.", "Un diafragma flexible de láminas pensado para registrar choques neumáticos."], ans: 0, exp: "Unión de dos metales diferentes que por el efecto Seebeck genera mV." },
    { u: "SMYR T3", q: "¿Cuál es la parte inmóvil del motor y está formada por láminas de hierro ferromagnético?", opts: ["El estator, compuesto por un núcleo de chapa magnética.", "El rotor bobinado, encargado de la transmisión de potencia.", "El rotor de jaula de ardilla, con barras en cortocircuito.", "El cojinete de fricción, que soporta el eje de rotación."], ans: 0, exp: "El estator es la parte fija del motor que contiene los devanados conectados a la red eléctrica." },
    { u: "SMYR T3", q: "¿De qué están compuestos fundamentalmente los motores eléctricos?", opts: ["Exclusivamente de un sistema de válvulas y un eje de transmisión mecánica.", "Principalmente de un rotor interno móvil y un estator fijo con devanados.", "Únicamente de un bloque de cilindros neumáticos y un presostato.", "De un conjunto de relés de estado sólido y resistencias calefactoras."], ans: 1, exp: "Los motores eléctricos se componen fundamentalmente de una parte fija (Estator) y una parte móvil (Rotor)." },
    { u: "SMYR T3", q: "¿Por qué parte de la válvula fluye el fluido que establece el tipo de apertura y clase de fluidos de trabajo?", opts: ["A través del actuador de mando neumático.", "A través del cuerpo principal de la válvula.", "A través del rotor de jaula de ardilla.", "A través del estator de chapa magnética."], ans: 1, exp: "El cuerpo de la válvula es el componente que está en contacto directo con el fluido." },
    { u: "SMYR T3", q: "¿Qué pasos hay que seguir para regular una resistencia calefactora usando modulación por ancho de pulso?", opts: ["Ajustar el tiempo del ciclo total y variar el duty cycle según la necesidad térmica.", "Modificar la frecuencia de conmutación de la red sin alterar el ciclo de trabajo.", "Mantener el ciclo total fijo y variar la tensión de alimentación del circuito.", "Aumentar indefinidamente la intensidad nominal del relé de estado sólido."], ans: 0, exp: "El control PWM (Modulación por ancho de pulso) juega con el Duty Cycle y el ciclo total para regular la temperatura." },
    { u: "SMYR T3", q: "¿Qué válvulas se utilizan cuando hay un fluido con partículas en suspensión o corrosivo?", opts: ["Las válvulas de bola con asiento de teflón.", "Las válvulas de diafragma con aislamiento interno.", "Las válvulas de mariposa de accionamiento rápido.", "Las válvulas de globo para regulación de caudal."], ans: 1, exp: "Las válvulas de diafragma aíslan el mecanismo interno, siendo ideales para fluidos sucios o corrosivos." },
    { u: "SMYR T3", q: "El actuador que consta de una electrobomba de aceite se denomina:", opts: ["Actuador de accionamiento puramente eléctrico.", "Actuador de tipo electrohidráulico proporcional.", "Actuador de compresión puramente neumático.", "Actuador basado en solenoides electromagnéticos."], ans: 1, exp: "Al combinar la electricidad (electrobomba) con el aceite (hidráulica) se denomina electrohidráulico." },
    { u: "SMYR T3", q: "Existen dos tipos principales de relés de estado sólido (SSR):", opts: ["De accionamiento lineal y de accionamiento rotativo de precisión.", "De conexión en estrella y de conexión en configuración triángulo.", "De regulación proporcional y de regulación mediante histéresis.", "De conmutación instantánea y de conmutación al paso por cero."], ans: 3, exp: "Los SSR pueden ser de conmutación instantánea (cargas inductivas) o de paso por cero (cargas resistivas)." },
    { u: "SMYR T3", q: "La cavitación de las válvulas ocurre cuando...", opts: ["Se generan campos electromagnéticos parásitos en el actuador principal.", "La caída de presión en la vena contracta forma burbujas de vapor destructivas.", "Se produce un efecto térmico exclusivo de las válvulas operadas por motor-reductor.", "Se conecta el sistema neumático a una presión superior a la nominal estipulada."], ans: 1, exp: "La cavitación ocurre cuando el fluido pasa por un estrechamiento (vena contracta) y la caída de presión forma burbujas destructivas." },
    { u: "SMYR T3", q: "La potencia que consume un motor se representa mediante:", opts: ["La nomenclatura Rm, referida a la resistencia.", "La nomenclatura Pe, referida a la potencia eléctrica.", "La nomenclatura Pm, referida a la potencia mecánica.", "La nomenclatura X1, referida a la reactancia inducida."], ans: 1, exp: "Se representa mediante Pe (Potencia eléctrica consumida de la red)." },
    { u: "SMYR T3", q: "En un sistema de control, los dispositivos que pueden actuar como actuadores son:", opts: ["Exclusivamente las válvulas de control de caudal de fluidos.", "Únicamente las bombas hidráulicas de engranajes de alta presión.", "Solo los elevadores mecánicos utilizados para tareas de posicionamiento.", "Diversos dispositivos como válvulas, bombas, motores y elevadores."], ans: 3, exp: "Cualquier dispositivo que altere la variable manipulada del proceso físico se considera actuador." },
    { u: "SMYR T3", q: "¿Qué componente del motor eléctrico es la parte móvil encargada de transmitir el par mecánico?", opts: ["El estator, que aloja las bobinas principales del circuito.", "El rotor, que gira en el interior transmitiendo la potencia.", "La carcasa, que protege los elementos magnéticos internos.", "El devanado, responsable de generar el campo magnético."], ans: 1, exp: "El rotor es el elemento móvil que gira dentro del estator y transmite el par mecánico al eje." },
    { u: "SMYR T3", q: "¿Cuál es la parte inmóvil del motor compuesta por láminas de hierro ferromagnético?", opts: ["El conjunto magnético fijo denominado estator.", "El bloque rotativo de transmisión conocido como inducido.", "El sistema de contacto rozante llamado escobilla.", "El cilindro longitudinal de transmisión denominado eje."], ans: 0, exp: "Es la parte fija del motor, compuesta por un núcleo de láminas de hierro ferromagnético." },
    { u: "SMYR T3", q: "El rotor de 'jaula de ardilla' se caracteriza por:", opts: ["Incluir devanados de cobre conectados a una serie de anillos rozantes.", "Estar compuesto por barras conductoras cortocircuitadas en sus extremos.", "Limitar su aplicación exclusivamente a los motores de corriente continua.", "Requerir obligatoriamente el funcionamiento del equipo sin carga mecánica acoplada."], ans: 1, exp: "Estas barras están cortocircuitadas por dos anillos metálicos en los extremos, asemejando una jaula." },
    { u: "SMYR T3", q: "¿Qué define a un motor asíncrono o de inducción?", opts: ["El rotor se desplaza exactamente a la misma velocidad que el campo magnético.", "Existe una velocidad relativa llamada deslizamiento entre el rotor y el campo.", "Carece completamente de devanados de excitación en la estructura fija del estator.", "Está diseñado desde su origen para operar exclusivamente con corriente continua."], ans: 1, exp: "En estos motores, la velocidad del rotor siempre es menor que la de sincronismo para que exista inducción." },
    { u: "SMYR T3", q: "En un motor asíncrono, la diferencia entre la velocidad de sincronismo y la del rotor se llama:", opts: ["Par motor electromagnético de diseño.", "Histéresis ferromagnética del núcleo.", "Deslizamiento rotórico del equipo.", "Reactancia inductiva del devanado."], ans: 2, exp: "Se define como la diferencia entre la velocidad de sincronismo del campo y la de rotación del rotor." },
    { u: "SMYR T3", q: "¿Qué conexión de motor se utiliza habitualmente para reducir la corriente de arranque en grandes cargas?", opts: ["La configuración de devanados en Estrella.", "La configuración de devanados en Triángulo.", "La configuración de acoplamiento en Serie.", "La configuración de acoplamiento Mixto cruzado."], ans: 0, exp: "Se utiliza para el arranque de motores de gran potencia con el fin de reducir la intensidad inicial consumida." },
    { u: "SMYR T3", q: "En la conexión Triángulo:", opts: ["La tensión aplicada a cada fase es la tensión de red dividida por la raíz de tres.", "La tensión que recibe cada devanado de fase es exactamente igual a la tensión de la línea.", "Esta configuración de bornero se restringe únicamente a motores de potencia muy fraccionaria.", "La corriente total consumida de la red es tres veces inferior respecto a la conexión en estrella."], ans: 1, exp: "En esta configuración, cada devanado recibe la tensión completa que proporciona la línea eléctrica." },
    { u: "SMYR T3", q: "¿Qué dispositivo se utiliza para variar la velocidad de un motor asíncrono actuando sobre la frecuencia?", opts: ["El contactor electromagnético trifásico de potencia.", "El relé térmico de protección contra sobrecargas.", "El convertidor de estado sólido o variador de frecuencia.", "La resistencia de disipación térmica y frenado dinámico."], ans: 2, exp: "Los variadores de frecuencia (VFD) alteran la frecuencia de la red para modificar la velocidad de sincronismo." },
    { u: "SMYR T3", q: "El par motor se define como:", opts: ["La energía eléctrica total consumida medida por el vatímetro.", "El momento de fuerza o esfuerzo de torsión ejercido sobre el eje.", "La impedancia equivalente de los devanados del bloque estator.", "La configuración geométrica y física de los polos magnéticos."], ans: 1, exp: "Representa la fuerza de rotación producida por el motor para mover la carga." },
    { u: "SMYR T3", q: "Los motores con rotor de anillos rozantes permiten:", opts: ["Prescindir de la instalación de un estator de chapa magnética.", "Conectar resistencias externas para regular el par durante el arranque.", "Operar directamente conectados a fuentes de corriente continua pura.", "Reducir significativamente el tamaño respecto al rotor de jaula de ardilla."], ans: 1, exp: "La conexión de resistencias al rotor permite limitar la corriente y controlar el par de arranque de manera suave." },
    { u: "SMYR T3", q: "¿Cuáles son las dos partes fundamentales de una válvula de proceso?", opts: ["El conjunto del motor de inducción y el eje de transmisión.", "La estructura del cuerpo principal y el mecanismo actuador.", "El dispositivo solenoide y el relé de maniobra eléctrica.", "El módulo de filtrado de partículas y la bomba de impulsión."], ans: 1, exp: "Son los dos elementos fundamentales que componen una válvula de control." },
    { u: "SMYR T3", q: "La parte de la válvula por la que fluye el fluido y establece el tipo de apertura es:", opts: ["El módulo de actuación externa o servomotor.", "El cuerpo principal de retención y paso.", "El posicionador electroneumático acoplado.", "El muelle de retroceso o retorno por falla."], ans: 1, exp: "Es la sección por la que circula el fluido y donde se alojan el obturador y los asientos." },
    { u: "SMYR T3", q: "¿Qué componente de la válvula transmite la acción mecánica al obturador para abrir o cerrar?", opts: ["El volante de accionamiento manual de emergencia.", "El cuerpo principal de fundición acerada.", "El actuador o servomotor de mando del proceso.", "El prensaestopas de estanqueidad del vástago."], ans: 2, exp: "El actuador se encarga de transformar la señal de mando en movimiento físico para posicionar el obturador." },
    { u: "SMYR T3", q: "Las válvulas de 'asiento' se clasifican como válvulas de:", opts: ["Desplazamiento longitudinal o movimiento lineal.", "Giro sobre su propio eje o movimiento rotativo.", "Conmutación instantánea pura o de acción rápida.", "Protección contra sobrepresiones o válvulas de seguridad."], ans: 0, exp: "Estas válvulas desplazan el obturador en línea recta perpendicular al asiento." },
    { u: "SMYR T3", q: "¿Qué tipo de válvula es ideal para interrumpir el flujo pero no para regularlo debido a su diseño constructivo?", opts: ["El diseño de asiento propio de la válvula de globo.", "El diseño de guillotina de la válvula de compuerta.", "El diseño cilíndrico perforado de la válvula de jaula.", "El diseño mezclador característico de la válvula de tres vías."], ans: 1, exp: "Su diseño interno de cuña no es adecuado para la regulación continua, solo para apertura o cierre total." },
    { u: "SMYR T3", q: "Una válvula de 'mariposa' se caracteriza por:", opts: ["Integrar un disco rotativo que gira 90 grados sobre su eje transversal.", "Utilizar un vástago de movimiento lineal para desplazar el obturador.", "Estar diseñada exclusivamente para soportar presiones extremadamente altas.", "Disponer de un elemento de cierre macizo en forma de cuña descendente."], ans: 0, exp: "Es una válvula rotativa muy compacta cuyo elemento de cierre es un disco." },
    { u: "SMYR T3", q: "¿Qué tipo de válvula lineal es la más utilizada en la industria para el control preciso del caudal?", opts: ["El modelo de aislamiento o desplazamiento de compuerta.", "El modelo clásico de obturador de globo o de asiento.", "El modelo de aislamiento polimérico por diafragma flexible.", "El modelo rotatorio provisto de una esfera o bola perforada."], ans: 1, exp: "La válvula de globo es la más común para tareas donde se exige una regulación precisa de caudal." },
    { u: "SMYR T3", q: "Las válvulas de 'tres vías' se utilizan habitualmente para:", opts: ["Actuar como multiplicadores de presión en el circuito hidráulico.", "Realizar labores de mezcla de fluidos o desviación de trayectorias.", "Funcionar como medidores precisos de caudal másico y volumétrico.", "Prevenir el fenómeno destructivo de cavitación en la tubería principal."], ans: 1, exp: "Tienen tres conexiones para gestionar fluidos de distintas procedencias, mezclándolos o desviándolos." },
    { u: "SMYR T3", q: "Un actuador neumático de 'acción directa' funciona:", opts: ["Inyectando aire a presión para cerrar el paso y dejando que el muelle la abra.", "Inyectando aire a presión para abrir el paso y dejando que el muelle la cierre.", "Funcionando de forma exclusiva mediante señales eléctricas analógicas de 4-20mA.", "Prescindiendo completamente del uso de muelles mecánicos de retroceso interno."], ans: 0, exp: "En configuración de acción directa, la presión del aire empuja el vástago para cerrar el paso." },
    { u: "SMYR T3", q: "¿Qué dispositivo mejora la precisión de la válvula asegurando que el vástago esté en la posición exacta pedida por el controlador?", opts: ["El manómetro de presión diferencial analógico.", "El posicionador electroneumático de montaje exterior.", "El termostato de seguridad térmica del actuador.", "El relé de conmutación instantánea para bloqueo."], ans: 1, exp: "Es un dispositivo auxiliar que ajusta mecánicamente el vástago para eliminar cualquier error de posición." },
    { u: "SMYR T3", q: "El parámetro 'Cv' de una válvula representa:", opts: ["El nivel de voltaje límite necesario para el sistema de control.", "El coeficiente de flujo o capacidad nominal de paso de la válvula.", "La velocidad terminal máxima del aire comprimido de pilotaje.", "El par de torsión máximo que puede suministrar el actuador rotativo."], ans: 1, exp: "Define el caudal de agua que pasa por la válvula bajo una caída de presión de 1 psi en condiciones estándar." },
    { u: "SMYR T3", q: "Las válvulas de 'bola' son muy populares en entornos industriales por:", opts: ["Garantizar una altísima precisión durante la regulación de caudal continuo.", "Proporcionar un cierre estanco de actuación rápida con un simple giro de 90 grados.", "Incorporar un cuerpo elástico de diafragma resistente a fuertes compuestos químicos.", "Operar de manera completamente pasiva sin la necesidad de integrar un actuador."], ans: 1, exp: "Su esfera perforada permite un sellado muy eficiente con un tiempo de respuesta mínimo." },
    { u: "SMYR T3", q: "El control de potencia en resistencias industriales suele hacerse mediante:", opts: ["La modulación por ancho de pulso, comúnmente conocida como señal PWM.", "La alteración directa del nivel de voltaje suministrado por la línea eléctrica.", "La modificación paramétrica de la frecuencia base de la red trifásica general.", "El uso de grandes botoneras o interruptores electromecánicos operados a mano."], ans: 0, exp: "El PWM es la técnica electrónica estándar para regular de forma eficiente la potencia entregada a la resistencia." },
    { u: "SMYR T3", q: "¿Qué ventaja principal tienen los relés de estado sólido (SSR) frente a los relés electromagnéticos?", opts: ["Presentan un coste de adquisición significativamente menor en el mercado actual.", "Cuentan con una vida útil casi ilimitada debido a la ausencia de partes móviles.", "Soportan de manera mucho más eficiente los picos de tensión y cortocircuitos severos.", "Facilitan el diagnóstico técnico visual al permitir observar el arco eléctrico interno."], ans: 1, exp: "Al ser puramente electrónicos y basarse en semiconductores, no sufren desgaste mecánico." },
    { u: "SMYR T3", q: "Los SSR de 'paso por cero' se utilizan principalmente para:", opts: ["Disminuir el ruido electromagnético protegiendo fundamentalmente cargas resistivas.", "Efectuar el control de velocidad y par exclusivamente en motores de corriente continua.", "Realizar desconexiones inmediatas y seguras en elementos altamente inductivos.", "Favorecer la generación de campos magnéticos potentes en los núcleos del estator."], ans: 0, exp: "Conectan cuando la tensión alterna cruza por cero voltios, minimizando transitorios y ruidos en la red." },
    { u: "SMYR T3", q: "Un SSR de 'conmutación instantánea' es especialmente adecuado para:", opts: ["El accionamiento exclusivo de bancos de calentamiento y cargas resistivas lineales.", "El manejo de cargas inductivas puras que requieren un control de fase preciso.", "La integración en sistemas térmicos cerrados que no toleran disipación de calor.", "El reemplazo directo de contactores mecánicos en válvulas de aislamiento de bola."], ans: 1, exp: "A diferencia del paso por cero, permiten la desconexión inmediata en cualquier momento del ciclo de fase." },
    { u: "SMYR T3", q: "¿Cuál es una desventaja notable de los relés de estado sólido (SSR)?", opts: ["Producen un elevado ruido de tipo acústico y mecánico durante su conmutación.", "Disipan calor por su caída de tensión interna y exigen forzosamente el uso de disipadores.", "Presentan una frecuencia de conmutación excesivamente baja para aplicaciones rápidas.", "Tienen prohibida por estricta normativa su instalación dentro de armarios de control."], ans: 1, exp: "La pequeña resistencia interna del semiconductor genera una caída de tensión que se traduce en calor residual continuo." },
    { u: "SMYR T3", q: "¿Cuál es la diferencia fundamental entre la neumática y la hidráulica?", opts: ["La neumática emplea aire compresible, mientras que la hidráulica usa fluidos incompresibles.", "La hidráulica resulta inherentemente más limpia y adecuada para entornos estériles.", "La neumática tiene la capacidad arquitectónica de generar mucha mayor fuerza motriz.", "No existen diferencias estructurales reales, ambos operan con gases a alta presión."], ans: 0, exp: "La compresibilidad del aire frente a la incompresibilidad del aceite dicta el comportamiento físico de ambos sistemas." },
    { u: "SMYR T3", q: "¿Qué sistema es técnica y comercialmente más adecuado para mover cargas muy pesadas con enorme fuerza?", opts: ["El sistema basado en actuadores y cilindros de presión neumática.", "El sistema basado en cilindros y motores de tecnología hidráulica.", "El sistema integrado exclusivamente por grandes husillos eléctricos.", "El sistema gestionado de manera artesanal mediante engranajes manuales."], ans: 1, exp: "Los fluidos incompresibles (aceite hidráulico) permiten transmitir fuerzas de empuje muchísimo mayores que el aire." },
    { u: "SMYR T3", q: "Los sistemas neumáticos son habitualmente preferidos cuando se requiere:", opts: ["Movimientos de muy alta velocidad operativa en un entorno que requiera gran limpieza.", "La aplicación constante y controlada de fuerzas extremas superiores a varias toneladas.", "Una operación mecánica silenciosa que garantice la ausencia total de ruido ambiental.", "Condiciones operativas severas donde el actuador deba funcionar en un vacío absoluto."], ans: 0, exp: "El aire comprimido permite accionamientos más rápidos y, en caso de fuga, no contamina gravemente el producto." },
    { u: "SMYR T3", q: "Una 'electroválvula proporcional' instalada en un circuito de control permite:", opts: ["Ejecutar de manera exclusiva las posiciones extremas de apertura total o cierre total.", "Ajustar la presión y el caudal fluido en proporción directa a una señal de control analógica.", "Registrar las oscilaciones térmicas del flujo de aire mediante una termocupla integrada.", "Conmutar la polaridad de las fases eléctricas para invertir el sentido de giro de la bomba."], ans: 1, exp: "Es el componente base de los sistemas proporcionales, variando el paso de fluido según la tensión recibida." },
    { u: "SMYR T3", q: "¿Qué es un 'husillo' en el ámbito de la mecánica de máquinas y robótica?", opts: ["Una variante constructiva de las válvulas rotativas de accionamiento ultra rápido.", "Un mecanismo basado en un tornillo empleado para desplazar linealmente componentes.", "Un dispositivo transductor de campo destinado a la monitorización térmica del proceso.", "La envoltura protectora externa de acero que recubre el núcleo principal del estator."], ans: 1, exp: "Suele ser un eje roscado largo y de precisión que convierte el giro de un motor en un avance lineal suave." },
    { u: "SMYR T3", q: "En un sistema de control clásico, el actuador interviene de forma directa sobre:", opts: ["Las magnitudes físicas que conforman e influyen en el estado del proceso.", "El lazo de retroalimentación interna asociado al circuito del comparador.", "Los parámetros lógicos de ajuste que definen el valor de la señal de referencia.", "El protocolo de comunicaciones utilizado por el autómata lógico programable."], ans: 0, exp: "El actuador ejecuta la acción física sobre la planta o sistema controlado, modificando el entorno." },
    { u: "SMYR T3", q: "¿Qué software de Schneider Electric se menciona para el diseño asistido de cuadros eléctricos?", opts: ["La plataforma genérica de diseño gráfico y modelado AutoCAD 3D.", "El entorno especializado eDesign Terciario desarrollado por Schneider.", "El complejo software de automatización y control TIA Portal de Siemens.", "El programa de edición visual vectorial de gran precisión Adobe Illustrator."], ans: 1, exp: "Es una herramienta de software específica mencionada en la teoría para planificar armarios y cuadros eléctricos." },
    { u: "SMYR T3", q: "Un motor asíncrono de 4 polos (2 pares) conectado a una red de 50 Hz tiene una velocidad de sincronismo teórica de:", opts: ["El campo magnético giratorio alcanza una velocidad de sincronismo de 1500 rpm.", "El campo magnético giratorio alcanza una velocidad de sincronismo de 3000 rpm.", "El campo magnético giratorio alcanza una velocidad de sincronismo de 1000 rpm.", "El campo magnético giratorio alcanza una velocidad de sincronismo de 750 rpm."], ans: 0, exp: "Aplicando la fórmula n = (60 * f) / p, para 50Hz y 2 pares de polos el resultado es exactamente 1500 rpm." },
    { u: "SMYR T3", q: "El 'aislante' incorporado en las ranuras del estator de un motor sirve principalmente para:", opts: ["Favorecer activamente la disipación térmica generada durante el funcionamiento del motor.", "Prevenir cortocircuitos garantizando el aislamiento entre conductores y el núcleo de hierro.", "Proporcionar soporte y sujeción mecánica al conjunto rotativo del eje de transmisión.", "Incrementar los niveles de inducción magnética para lograr un mayor par durante el arranque."], ans: 1, exp: "Asegura la integridad eléctrica del estator evitando derivaciones de corriente a la masa de la máquina." },
    { u: "SMYR T3", q: "¿Qué sucede matemáticamente si el deslizamiento de un motor asíncrono es igual a cero?", opts: ["El campo no corta las barras del rotor, por lo que deja de generarse par electromagnético.", "El devanado entra en resonancia destructiva y el motor termina quemándose por sobreintensidad.", "El rotor alcanza su rendimiento mecánico óptimo y el motor logra desarrollar su máxima potencia.", "El variador detecta una anomalía de rotación crítica y procede a activar el sistema de frenado."], ans: 0, exp: "Si el rotor iguala la velocidad del campo, no hay variación de flujo (inducción), por lo que el par motor desaparece." },
    { u: "SMYR T3", q: "Las válvulas de 'diafragma' son constructivamente ideales para:", opts: ["Circuitos de distribución que operan sometidos a regímenes de altísima presión de vapor.", "Aplicaciones industriales con fluidos altamente corrosivos o con gran cantidad de sólidos.", "Sistemas de regulación de caudal concebidos exclusivamente para redes de aire comprimido.", "Líneas de impulsión y bombeo diseñadas para aceites de extremadamente alta viscosidad."], ans: 1, exp: "El diafragma flexible de polímero aísla completamente el delicado mecanismo interno del fluido peligroso o sucio." },
    { u: "SMYR T3", q: "¿Cuál es el objetivo principal y crítico de instalar disipadores térmicos en los relés SSR?", opts: ["Mejorar la distribución espacial y el acabado estético general dentro del cuadro de distribución.", "Prevenir la destrucción térmica y el fallo del semiconductor debido al exceso de calor generado.", "Optimizar la conductividad del contacto y disminuir el consumo total de potencia eléctrica de la red.", "Actuar como etapas multiplicadoras de tensión estáticas para lograr elevar el voltaje de salida final."], ans: 1, exp: "Es absolutamente crítico para su funcionamiento, ya que los SSR generan calor al conmutar y sin disipación se queman." },
    { u: "SMYR T3", q: "¿Qué sistema de control es mecánicamente más 'elástico' y permite absorber golpes o picos de carga?", opts: ["La tecnología de control neumático, aprovechando la naturaleza compresible del aire a presión.", "La tecnología de control hidráulico, utilizando el aceite mineral como transmisor incompresible.", "La tecnología de tracción mecánica, fundamentada en el desplazamiento lineal preciso por husillo.", "La tecnología de tracción electromecánica, basada en un tren de engranajes de piñón y cremallera."], ans: 0, exp: "Esta 'elasticidad' o 'colchón de aire' actúa como un amortiguador natural frente a impactos mecánicos muy fuertes." },
    { u: "SMYR T3", q: "¿Qué componente fundamental del motor aloja los devanados conectados directamente a la red eléctrica trifásica?", opts: ["La corona fija construida con láminas magnéticas que conforma el estator.", "El conjunto rotativo y estructuralmente cerrado del rotor de jaula de ardilla.", "Los bloques de contacto deslizante o anillos rozantes conocidos como escobillas.", "La barra cilíndrica central de acero endurecido que conforma el eje de transmisión."], ans: 0, exp: "El estator contiene el devanado fijo que, al recibir la corriente trifásica, crea el campo magnético giratorio." },
    { u: "SMYR T3", q: "Las válvulas industriales conocidas como de 'pistón' se clasifican dentro de la familia de:", opts: ["Las válvulas de regulación fundamentadas en el movimiento lineal de su obturador cilíndrico.", "Las válvulas de aislamiento grueso basadas en el movimiento rotativo rápido sobre su propio eje.", "Las válvulas de alivio de red diseñadas para garantizar la seguridad mecánica frente a sobrepresiones.", "Los dispositivos electrónicos de acondicionamiento de señal técnica catalogados como preactuadores."], ans: 0, exp: "Son válvulas de asiento lineal en las que el obturador tiene forma de pistón cilíndrico para soportar mayor presión." },
    { u: "SMYR T3", q: "En la disciplina neumática, las válvulas de distribución suelen ser accionadas físicamente por:", opts: ["Sistemas mecánicos básicos restringidos al uso de palancas y grandes volantes manuales de cierre.", "Señales de bajo consumo electromagnéticas mediante solenoides o mediante líneas de aire piloto.", "Acoplamientos mecánicos directos a pequeños motores rotativos de combustión interna portátiles.", "Sistemas de contrapeso asimétricos que aprovechan exclusivamente la fuerza gravitacional de la tierra."], ans: 1, exp: "Las electroválvulas neumáticas industriales usan un pequeño solenoide interno para dejar pasar el aire piloto que mueve la válvula principal." },
    { u: "SMYR T3", q: "El término 'Duty Cycle' (Ciclo de Trabajo) en el control electrónico de resistencias se refiere a:", opts: ["La fracción porcentual del tiempo de ciclo total durante la cual el componente se encuentra recibiendo energía.", "El valor absoluto en vatios de la potencia máxima que el equipo electrónico es capaz de suministrar a la planta.", "El límite térmico superior de seguridad que define el umbral de temperatura de fusión del elemento calefactor.", "La secuencia de relés de conexión temporal requerida para habilitar correctamente las tres fases del motor."], ans: 0, exp: "Define la potencia media entregada (ej. un duty cycle del 50% significa que la resistencia está encendida la mitad del tiempo del ciclo)." },
    { u: "SMYR T3", q: "Los motores asíncronos trifásicos de uso industrial estándar tienen habitualmente:", opts: ["Un cuadro de empalmes eléctrico de diseño compacto provisto únicamente de 2 bornes de conexión.", "Una regleta de terminación en la caja de bornes equipada constructivamente con 6 terminales principales.", "Un cableado de alimentación directo y sellado de fábrica que dispone exclusivamente de conexión a tierra.", "Un módulo integrado en la tapa de la carcasa con puerto USB dedicado a realizar diagnósticos preventivos."], ans: 1, exp: "Los 6 bornes permiten a los técnicos realizar externamente las conexiones en estrella o en triángulo dependiendo de la tensión de la red." },
    { u: "SMYR T3", q: "¿Qué tipo de actuador final es el más común y extendido en los sistemas de ventilación industrial?", opts: ["Los motores eléctricos de inducción acoplados directamente al eje de aspas giratorias.", "Las válvulas neumáticas proporcionales equipadas con membranas elásticas de diafragma.", "Los bancos de conmutación de potencia configurados mediante relés de estado sólido.", "Los actuadores lineales de precisión construidos sobre la base de husillos mecánicos."], ans: 0, exp: "El motor eléctrico moviendo las aspas de un ventilador es la aplicación directa y elemental para desplazar grandes masas de aire." },
    { u: "SMYR T3", q: "El fenómeno de la 'histéresis' presente en el comportamiento de una válvula de control es:", opts: ["El desfase de posición de la válvula para un mismo valor de señal dependiendo de si se está abriendo o cerrando.", "La tolerancia estructural o presión nominal máxima que puede soportar el cuerpo principal sin llegar a deformarse.", "El estándar de acoplamiento mecánico y el tipo específico de rosca que se emplean en los bornes del actuador.", "El retardo temporal de propagación o tiempo de respuesta que tarda el aire a presión en llegar hasta el actuador."], ans: 0, exp: "Este desfase de lectura se debe principalmente al rozamiento de los sellos, la holgura de los engranajes y la resistencia mecánica propia de la válvula." },
    { u: "SMYR T3", q: "¿Cuál es el fluido de trabajo estándar utilizado en un sistema hidráulico proporcional de maquinaria pesada?", opts: ["El aire comprimido atmosférico sometido previamente a un riguroso proceso de secado, enfriado y filtrado.", "El vapor de agua a alta presión generado en circuitos cerrados de calderas a elevadas temperaturas de trabajo.", "El aceite mineral derivado del petróleo o fluidos sintéticos diseñados específicamente para ser incompresibles.", "El gas inerte de nitrógeno inyectado a presión constante en circuitos frigoríficos de refrigeración industrial."], ans: 2, exp: "El aceite mineral hidráulico es el medio de transmisión de fuerza por excelencia debido a su incompresibilidad y propiedades lubricantes." },
    { u: "SMYR T3", q: "La estructura exterior o carcasa de un motor eléctrico tiene como función principal y primaria:", opts: ["Salvaguardar los elementos internos de la suciedad e integrar aletas externas para lograr disipar el calor radiante.", "Crear el entorno electromagnético aislado estrictamente necesario para confinar el campo magnético rotativo central.", "Proporcionar soporte físico para los puentes metálicos macizos requeridos para efectuar la conexión en estrella.", "Acoplarse solidariamente de forma mecánica al rotor interno para conseguir incrementar la inercia total del sistema."], ans: 0, exp: "Cumple una doble función ineludible: proteger el devanado contra impactos o polvo, y disipar el calor al ambiente a través de sus aletas de refrigeración." },
    { u: "SMYR T3", q: "Dentro de la jerarquía de un sistema de automatización, ¿qué dispositivo industrial se considera técnicamente un 'preactuador'?", opts: ["Elementos intermedios de mando y amplificación de potencia como los relés, contactores electromagnéticos o variadores.", "Máquinas eléctricas rotativas concebidas para transformar energía como el motor trifásico estándar de jaula de ardilla.", "Dispositivos finales de estrangulación del flujo de proceso como la válvula industrial de asiento también llamada de globo.", "Actuadores lineales de potencia extrema diseñados para elevar grandes cargas como el cilindro de alta presión hidráulica."], ans: 0, exp: "Los preactuadores son los encargados de recibir la señal débil del PLC o controlador y conmutar la alta potencia que alimenta al actuador final (el motor o la válvula)." },
    { u: "SMYR T3", q: "¿Qué parámetro de una válvula de control representa la diferencia de posición entre la carrera de apertura y la de cierre para una misma señal de mando analógica?", opts: ["El concepto técnico limitante conocido como banda muerta del circuito del servomotor.", "La especificación operativa definida en la placa de características como rango de acción.", "El fenómeno físico y mecánico de rozamiento dinámico comúnmente denominado histéresis.", "El índice cualitativo de respuesta ante variaciones bruscas catalogado como sensibilidad térmica."], ans: 2, exp: "Esa diferencia o desfase producido principalmente por el rozamiento mecánico de la estopada y holguras internas se denomina histéresis direccional." },
    { u: "SMYR T3", q: "¿Cuál es el componente específico de la estructura del estator que se encarga de alojar los conductores aislados del devanado trifásico?", opts: ["La estructura protectora externa de aluminio o hierro fundido comúnmente llamada carcasa de refrigeración.", "Las cavidades mecanizadas y asiladas dispuestas a lo largo de toda la chapa magnética llamadas ranuras.", "La barra longitudinal y maciza de acero forjado mecanizado conocida en ingeniería como eje central.", "El receptáculo externo de polímero aislante o material termoplástico ignífugo denominado caja de bornes."], ans: 1, exp: "Las ranuras del núcleo laminado de hierro son el canal físico estandarizado donde se asientan e inmovilizan las bobinas del estator." },
    { u: "SMYR T3", q: "En un motor asíncrono, si los instrumentos indican que el nivel de deslizamiento se encuentra en el 100%, ¿en qué estado físico se encuentra el motor?", opts: ["El motor está desarrollando su máxima velocidad nominal asumiendo que no tiene ninguna carga acoplada en el eje.", "El motor se halla en estado de reposo absoluto, es decir, representa el preciso momento inicial del arranque.", "El motor está girando exactamente a la misma velocidad teórica de sincronismo generada por el campo magnético.", "El motor ha entrado en condición de avería permanente con los devanados completamente fundidos o quemados."], ans: 1, exp: "Al estar totalmente parado, el rotor tiene una velocidad física de 0 rpm, lo que matemáticamente significa un 100% de deslizamiento respecto a la velocidad del campo del estator." },
    { u: "SMYR T3", q: "¿Qué tipo de válvula rotativa utiliza como elemento de interrupción un obturador principal con forma geométrica de esfera?", opts: ["La válvula rotativa de disco plano y accionamiento de cuarto de vuelta, también conocida comúnmente como mariposa.", "La válvula rotativa que emplea un núcleo en forma de esfera perforada en su centro, habitualmente llamada de bola.", "La válvula clásica de asiento con desplazamiento de movimiento lineal del vástago, denominada formalmente válvula de globo.", "La válvula de guillotina concebida para el aislamiento grueso de fluidos sucios, tradicionalmente conocida como compuerta."], ans: 1, exp: "La válvula de bola utiliza una esfera de acero inoxidable atravesada por un orificio pasante que, al girar, se alinea o se bloquea con el paso del tubo." },
    { u: "SMYR T3", q: "¿Qué ventaja directa ofrece arrancar un motor en la configuración de conexión en Estrella frente a la conexión en Triángulo?", opts: ["Permite que el conjunto del motor desarrolle una mayor potencia mecánica final útil en el eje acoplado a la máquina.", "Incrementa notablemente y de forma transitoria el par motor disponible para lograr arrancar cargas altamente pesadas.", "Reduce significativamente la intensidad pico de corriente eléctrica que el estator exige a la red consumida durante el arranque.", "Aumenta la velocidad final de giro nominal modificando artificialmente la respuesta del deslizamiento asíncrono natural."], ans: 2, exp: "Al usar la conexión Estrella para el arranque de la máquina, la tensión por fase disminuye, lo que hace que la intensidad consumida de la red eléctrica sea 3 veces menor que si arrancase directamente en Triángulo." },
    { u: "SMYR T4", q: "¿A qué puede deberse un error en régimen permanente?", opts: ["Señal de referencia", "Características del sistema", "Errores de modelado", "Todas las respuestas son correctas"], ans: 3, exp: "El error en régimen permanente puede originarse tanto por la naturaleza de la señal de referencia, como por la propia dinámica del sistema o imprecisiones en el modelo." },
    { u: "SMYR T4", q: "¿Cómo conocemos a la cantidad de amplitud que habría que añadir a una señal para que su sistema sea inestable?", opts: ["Margen de fase", "Margen de ganancia", "Margen angular", "Margen de desfase"], ans: 1, exp: "El margen de ganancia es el incremento de ganancia (en dB) que llevaría al sistema a la inestabilidad (cruzar los 0 dB cuando la fase es -180°)." },
    { u: "SMYR T4", q: "¿Cómo conocemos al ángulo mínimo que habría que introducir a la señal de un sistema para que este pase de ser un sistema estable a uno inestable?", opts: ["Margen de fase", "Margen de ganancia", "Margen angular", "Margen de desfase"], ans: 0, exp: "El margen de fase es la diferencia entre la fase actual y -180° cuando la ganancia cruza por 0 dB." },
    { u: "SMYR T4", q: "¿Cómo denominamos a los sistemas en los que se posicionan de manera paralela dos sistemas de primer orden?", opts: ["Sistemas de primer orden compuestos", "Sistemas de segundo orden", "Sistemas de orden superior", "Ninguna de las anteriores es correcta"], ans: 1, exp: "Un sistema de segundo orden puede interpretarse frecuentemente como la combinación de dos sistemas de primer orden." },
    { u: "SMYR T4", q: "¿Cuál de los siguientes no es un objetivo a cumplir al realizar la regulación de un sistema?", opts: ["Que la señal de salida llegue a la consigna que se establece de la manera más rápida y directa posible", "Que la señal de salida ya establecida en la consigna tenga una gran estabilidad a lo largo del tiempo sin grandes fluctuaciones", "Que la señal de entrada sea analógica", "Todas son objetivos a cumplir"], ans: 2, exp: "Que la señal sea analógica no es un objetivo del control; de hecho, hoy en día se trabaja mucho con señales digitales." },
    { u: "SMYR T4", q: "¿Cuál es el controlador más habitual que se incorpora hoy en día en los PLC?", opts: ["Control proporcional", "Control proporcional + integral", "Control proporcional + integral + derivativo", "Ninguna de las anteriores"], ans: 2, exp: "El controlador PID (Proporcional, Integral, Derivativo) es el estándar industrial en la inmensa mayoría de PLCs." },
    { u: "SMYR T4", q: "¿Cuál es el problema más habitual que podemos encontrar en un controlador al implementar el término derivativo?", opts: ["Que perdamos control en el régimen transitorio", "Que se deje de controlar la señal de error desde el PI", "Que tengamos una señal con mucho ruido", "Todas las respuestas son correctas"], ans: 2, exp: "La acción derivativa reacciona a la velocidad de cambio, por lo que amplifica drásticamente cualquier ruido de alta frecuencia del sensor." },
    { u: "SMYR T4", q: "¿Cuál es el valor con el que se compara la señal de salida?", opts: ["Valor de inicio", "Valor de reset", "Valor de referencia", "Valor original"], ans: 2, exp: "La señal de salida se resta al 'Valor de referencia' (consigna o Setpoint) para obtener el error del sistema." },
    { u: "SMYR T4", q: "¿Qué representan las gráficas del diagrama de Bode?", opts: ["El cambio de amplitud y de desfase entre señales de entrada y salida", "El cambio de amplitud y de desfase entre señales de entrada y de referencia", "El cambio de periodo y longitud de onda entre señales de entrada y salida", "Ninguna de las respuestas es correcta"], ans: 0, exp: "Bode representa la respuesta en frecuencia de un sistema: ganancia (amplitud) y fase (desfase) de la salida respecto a la entrada." },
    { u: "SMYR T4", q: "¿Qué tipos de estabilidad diferenciamos?", opts: ["Estabilidad absoluta y parcial", "Estabilidad total y parcial", "Estabilidad absoluta y relativa", "Estabilidad total y relativa"], ans: 2, exp: "Se diferencia entre estabilidad absoluta (si el sistema es estable o no) y relativa (cuánto de estable es, márgenes)." },
    { u: "SMYR T4", q: "¿En qué se basa el control en sistemas de lazo abierto?", opts: ["En la comparación continua entre la salida y la referencia.", "Únicamente en la entrada al sistema, suponiendo que es perfecto y sin perturbaciones.", "En la realimentación de la señal de salida.", "En el uso exclusivo de controladores PID."], ans: 1, exp: "El lazo abierto asume que todo va a funcionar bien sin medir el resultado real." },
    { u: "SMYR T4", q: "¿Qué concepto define a los sistemas de lazo cerrado para corregir errores?", opts: ["Control predictivo.", "Modelado diferencial.", "Realimentación de la salida del sistema.", "Identificación en frecuencia."], ans: 2, exp: "La realimentación toma la salida, la devuelve y la compara con la entrada para ver si hay error." },
    { u: "SMYR T4", q: "En un diagrama de bloques de lazo cerrado, ¿cómo se define matemáticamente el error E(s)?", opts: ["E(s) = R(s) + Y(s)", "E(s) = R(s) * Y(s)", "E(s) = R(s) - Y(s)", "E(s) = Y(s) / R(s)"], ans: 2, exp: "El error es siempre la Resta entre la Referencia R(s) y la Salida Y(s)." },
    { u: "SMYR T4", q: "¿Cuál es la fórmula de la función de transferencia en lazo cerrado T(s)?", opts: ["T(s) = (G(s)C(s)) / (1 - G(s)C(s))", "T(s) = (G(s)C(s)) / (1 + G(s)C(s))", "T(s) = 1 + G(s)C(s)", "T(s) = G(s) / C(s)"], ans: 1, exp: "Es la fórmula clásica para reducir un lazo cerrado con realimentación negativa unitaria." },
    { u: "SMYR T4", q: "¿Qué resultado se obtiene siempre al sumar la función de sensibilidad S(s) y la sensibilidad complementaria T(s)?", opts: ["0", "Infinito.", "1.", "La ganancia estática."], ans: 2, exp: "Matemáticamente S(s) + T(s) = 1 siempre en un sistema de control." },
    { u: "SMYR T4", q: "¿Qué define la constante K_est en un sistema de primer orden?", opts: ["El tiempo de respuesta.", "La relación entre la entrada y la salida en régimen permanente.", "La estabilidad absoluta.", "El desfase en el diagrama de Bode."], ans: 1, exp: "K_estática define el valor final en el que se estabiliza el sistema ante una entrada escalón." },
    { u: "SMYR T4", q: "En un sistema de primer orden, ¿qué representa la constante de tiempo τ (tau)?", opts: ["El tiempo total de apagado.", "El tiempo que tarda el sistema en llegar al 63,2% de su valor final ante un escalón.", "El tiempo de sobrepico.", "El número de polos en el origen."], ans: 1, exp: "Tau es la métrica de velocidad de respuesta en sistemas de primer orden (63,2%)." },
    { u: "SMYR T4", q: "¿Qué sucede con el tiempo de estabilización de un sistema si la constante τ aumenta?", opts: ["El sistema se estabiliza más rápido.", "No hay cambios en el tiempo de estabilización.", "El sistema tarda más tiempo en estabilizarse.", "El sistema se vuelve automáticamente inestable."], ans: 2, exp: "Un tau más grande significa que el sistema es más lento o 'perezoso'." },
    { u: "SMYR T4", q: "¿A qué tipo de sistema pertenece un tanque con una válvula proporcional reguladora de nivel?", opts: ["Segundo orden.", "Orden superior.", "Primer orden.", "Lazo abierto puro."], ans: 2, exp: "El llenado/vaciado de un tanque simple responde a una dinámica de primer orden." },
    { u: "SMYR T4", q: "¿Cuál es la estructura típica de la función de transferencia de un sistema de primer orden?", opts: ["G(s) = A / (s^2 + Bs + A)", "G(s) = K_est / (τs + 1)", "G(s) = K_p * e(s)", "G(s) = s + 1"], ans: 1, exp: "Es la forma normalizada canónica para un sistema de 1º orden." },
    { u: "SMYR T4", q: "¿Cómo se puede definir conceptualmente un sistema de segundo orden?", opts: ["Como un sistema sin polos.", "Como dos sistemas de primer orden posicionados de manera paralela o concatenados.", "Como un sistema con tres variables de estado.", "Como un sistema que solo responde a rampas."], ans: 1, exp: "Se puede formar mediante la combinación matemática de dos de primer orden." },
    { u: "SMYR T4", q: "¿Qué ejemplo físico es típico de un sistema de segundo orden?", opts: ["Un sensor de temperatura simple.", "El control de velocidad de un motor eléctrico de CC con carga mecánica.", "Un interruptor de luz.", "Una resistencia eléctrica pura."], ans: 1, exp: "El motor DC incluye una parte eléctrica (1º orden) y una mecánica (1º orden), sumando un 2º orden." },
    { u: "SMYR T4", q: "Para que un sistema de segundo orden tenga su 'forma típica', ¿cómo debe estar la variable s^2?", opts: ["Multiplicada por la constante de tiempo.", "Sin ninguna variable que la modifique (coeficiente unidad).", "En el numerador.", "Igualada a cero."], ans: 1, exp: "En la ecuación normalizada, s^2 debe estar sola (multiplicada por 1)." },
    { u: "SMYR T4", q: "¿Qué son los sistemas de orden superior?", opts: ["Sistemas con un solo polo en el semiplano derecho.", "Concatenaciones en paralelo de sistemas de primer y segundo orden.", "Sistemas que no se pueden modelar con Laplace.", "Sistemas de lazo abierto con gran ruido."], ans: 1, exp: "Se modelan uniendo matemáticamente sistemas más simples." },
    { u: "SMYR T4", q: "En el modelado de un sistema térmico, ¿qué representa el coeficiente α?", opts: ["El calor generado por la resistencia.", "El tiempo de respuesta.", "La pérdida de calor a través de las paredes (coeficiente de transmisión).", "La temperatura exterior."], ans: 2, exp: "Alfa representa la fugacidad térmica del habitáculo o recipiente." },
    { u: "SMYR T4", q: "¿Qué característica curiosa tienen los sistemas lineales ante una entrada senoidal?", opts: ["La salida es una señal escalón.", "La salida es otra señal senoidal de igual frecuencia.", "La salida siempre desaparece en régimen permanente.", "La salida dobla la frecuencia de entrada."], ans: 1, exp: "La frecuencia nunca cambia, solo puede alterarse la amplitud y el desfase." },
    { u: "SMYR T4", q: "¿Qué representan las dos gráficas de un diagrama de Bode?", opts: ["Tiempo vs Error.", "Amplitud (en dB) y Desfase (en grados) frente a la frecuencia angular.", "Polos vs Ceros.", "Voltaje vs Corriente."], ans: 1, exp: "Bode evalúa la magnitud y la fase en función de la frecuencia del sistema." },
    { u: "SMYR T4", q: "¿Qué unidad se utiliza en el diagrama de amplitud de Bode según el texto?", opts: ["Segundos.", "Grados.", "Decibelios (dB).", "Voltios."], ans: 2, exp: "Nota: el documento especifica la 'Amplitud' en el eje Y medida en decibelios (dB)." },
    { u: "SMYR T4", q: "¿Cuál es la utilidad de los diagramas de Bode en el análisis de sistemas?", opts: ["Solo sirven para sistemas de primer orden.", "Permiten identificar la función de transferencia a partir de la respuesta en frecuencia.", "Eliminan la necesidad de usar controladores.", "Miden la temperatura de la planta."], ans: 1, exp: "A partir de la curva de ganancia y fase podemos deducir polos, ceros y márgenes del sistema." },
    { u: "SMYR T4", q: "¿Qué eje del diagrama de desfase de Bode utiliza la frecuencia angular (rad/s)?", opts: ["El eje de abscisas.", "El eje de ordenadas.", "Ambos ejes.", "Ninguno, se usa hertzios."], ans: 0, exp: "El eje de abscisas (X) es siempre la frecuencia en escala logarítmica." },
    { u: "SMYR T4", q: "¿Cuáles son los dos objetivos principales al realizar una regulación automática?", opts: ["Que la señal no llegue nunca a la consigna.", "Que la salida llegue rápido a la consigna y mantenga una gran estabilidad en ella.", "Que el error aumente con el tiempo.", "Que los sensores no midan nada."], ans: 1, exp: "Velocidad de respuesta y estabilidad absoluta en el estado estacionario." },
    { u: "SMYR T4", q: "Según la estabilidad absoluta, ¿cuándo es estable un sistema f(t)?", opts: ["Cuando alguno de los exponentes a_m es menor que cero.", "Cuando todos los exponentes a_m son menores o iguales a cero (NOTA: Corregido teóricamente a parte real negativa).", "Cuando la salida tiende a infinito.", "Cuando no tiene polos en el origen."], ans: 1, exp: "Todos los polos del sistema deben estar en el semiplano izquierdo (exponenciales negativas)." },
    { u: "SMYR T4", q: "¿Qué indica que un sistema sea inestable según su estabilidad absoluta?", opts: ["Que sus polos están en el semiplano izquierdo.", "Que algún término del denominador tiene coeficiente negativo o raíces en semiplano derecho.", "Que la señal tiene poco ruido.", "Que la ganancia es muy baja."], ans: 1, exp: "Cualquier raíz positiva en el denominador indica que la señal crecerá hasta infinito." },
    { u: "SMYR T4", q: "¿Cómo se define la estabilidad relativa?", opts: ["Como el error de posición.", "Como la rapidez a la que un sistema llega a estabilizarse en el tiempo y su oscilación.", "Como la ganancia del controlador P.", "Como el ángulo de desfase a 0 dB."], ans: 1, exp: "Mide cuán lejos estamos de la inestabilidad (Márgenes de Fase y Ganancia)." },
    { u: "SMYR T4", q: "¿Qué efecto tiene un sobrepico excesivo en una señal?", opts: ["Indica que el sistema es muy estable.", "No tiene influencia en la estabilidad.", "Indica que el sistema es más inestable.", "Reduce el tiempo de establecimiento."], ans: 2, exp: "Un sobrepico alto significa un bajo margen de fase y tendencia a oscilar." },
    { u: "SMYR T4", q: "¿Qué es el margen de fase?", opts: ["La amplitud a -180°.", "El ángulo mínimo a introducir para que un sistema pase de estable a inestable cuando la magnitud es 0 dB.", "El tiempo que tarda en oscilar.", "La diferencia entre entrada y salida."], ans: 1, exp: "Mide cuántos grados de fase 'sobran' antes de llegar a -180º." },
    { u: "SMYR T4", q: "¿Qué es el margen de ganancia?", opts: ["La amplitud necesaria para que el sistema sea inestable cuando el desfase es de -180°.", "La ganancia estática K_est.", "El sobrepico máximo.", "El error en régimen permanente."], ans: 0, exp: "Mide cuántos decibelios 'sobran' antes de cruzar 0 dB cuando la fase es -180º." },
    { u: "SMYR T4", q: "¿Qué sucede con la estabilidad de un sistema si sus polos se acercan al semiplano derecho del eje de coordenadas?", opts: ["El sistema se vuelve más estable.", "El sistema se vuelve más inestable.", "No afecta a la estabilidad.", "Los polos desaparecen."], ans: 1, exp: "Cuanto más cerca del lado derecho (positivo), más oscilante e inestable es el sistema." },
    { u: "SMYR T4", q: "Un sistema totalmente estable se caracteriza por:", opts: ["Tener mucho sobrepico.", "Llegar a la estabilidad rápido, sin sobrepico excesivo ni sobresocilaciones.", "Tener márgenes de fase negativos.", "Ser de lazo abierto."], ans: 1, exp: "Respuesta rápida, precisa y con una amortiguación adecuada." },
    { u: "SMYR T4", q: "¿Qué significa un margen de fase o de ganancia negativo?", opts: ["El sistema es muy robusto.", "El sistema es directamente inestable.", "El sistema es de primer orden.", "La señal tiene poco ruido."], ans: 1, exp: "Si el margen es negativo, el sistema ya cruzó el límite y es inestable." },
    { u: "SMYR T4", q: "¿Cuándo se produce el error en régimen permanente?", opts: ["Al inicio del proceso (transitorio).", "Cuando hay una diferencia entre salida real y referencia en régimen estacionario.", "Solo si el controlador es PID.", "Cuando la señal de salida es cero."], ans: 1, exp: "Es la diferencia matemática residual una vez que el transitorio ha desaparecido." },
    { u: "SMYR T4", q: "¿Cuál de estas NO es una causa mencionada del error en régimen permanente?", opts: ["Características del sistema.", "Errores de modelado.", "Señal de referencia utilizada.", "Uso de energía solar en la planta."], ans: 3, exp: "La fuente de energía de la planta no determina los errores matemáticos de régimen permanente." },
    { u: "SMYR T4", q: "¿Qué tipo de señal de referencia suele provocar más errores en régimen estacionario?", opts: ["Un escalón unitario.", "Una señal sinusoidal de alta frecuencia.", "Una constante.", "Una señal apagada."], ans: 1, exp: "A mayor velocidad de cambio de la referencia (frecuencia), más le cuesta al sistema 'seguir' la señal, provocando error." },
    { u: "SMYR T4", q: "Para estudiar el error, ¿qué valor de s se evalúa en la función G_BA(s)?", opts: ["s=1", "s=0", "s=infinito", "s=-1"], ans: 1, exp: "El Teorema del Valor Final en Laplace evalúa el límite cuando 's' tiende a 0." },
    { u: "SMYR T4", q: "Según la tabla de errores, ¿qué error de posición tiene un sistema con 0 polos en el origen ante una entrada escalón?", opts: ["0", "1 / (1 + G_BA(0))", "Infinito.", "1 / G_BA(0)"], ans: 1, exp: "Un sistema de tipo 0 siempre tiene un error finito dependiente de su ganancia estática ante una entrada de escalón." },
    { u: "SMYR T4", q: "¿Cuál es el controlador más típico y usado dentro de la industria?", opts: ["Controlador P.", "Controlador PID.", "Controlador por lógica difusa.", "Controlador manual."], ans: 1, exp: "El controlador PID es el algoritmo más usado mundialmente en procesos industriales." },
    { u: "SMYR T4", q: "¿Cuál es la principal característica del control proporcional (P)?", opts: ["Elimina siempre el error estacionario.", "Se basa en una constante proporcional multiplicada por el error.", "No es sensible al ruido.", "Solo se usa en sistemas de segundo orden."], ans: 1, exp: "Genera una acción de control U(t) = Kp * E(t)." },
    { u: "SMYR T4", q: "¿Qué sucede en un controlador P cuando el error e(t) es cero?", opts: ["La salida u(t) es máxima.", "La salida u(t) es cero y la planta no actúa.", "El controlador se apaga permanentemente.", "El error aumenta bruscamente."], ans: 1, exp: "Si el error es cero, la multiplicación Kp * 0 da cero." },
    { u: "SMYR T4", q: "¿Cuál es el mayor inconveniente del controlador proporcional?", opts: ["No asegura la eliminación del error en estacionario.", "Es muy complejo de programar.", "Solo funciona con señales senoidales.", "Siempre hace al sistema inestable."], ans: 0, exp: "Deja un error residual, conocido como 'offset'." },
    { u: "SMYR T4", q: "¿Cómo afecta el aumento de la ganancia K_p al tiempo de subida?", opts: ["Lo incrementa.", "Lo decrementa.", "No produce cambios.", "Lo vuelve infinito."], ans: 1, exp: "Al ser más agresivo, el sistema alcanza la consigna mucho más rápido (decrementa el tiempo de subida)." },
    { u: "SMYR T4", q: "¿Cuál es la función principal de la parte integral (K_i) en un controlador PI?", opts: ["Aumentar el sobrepico.", "Eliminar el error en régimen estacionario.", "Predecir el futuro de la señal.", "Reducir la velocidad del sistema."], ans: 1, exp: "Suma los errores en el tiempo forzando a la válvula a moverse hasta que el error sea cero total." },
    { u: "SMYR T4", q: "¿Cómo se relaciona el término integral K_i con el tiempo integral T_i?", opts: ["De manera directa.", "De manera inversa (K_i aumenta si T_i disminuye).", "No tienen relación.", "Son el mismo valor."], ans: 1, exp: "K_i = K_p / T_i. Por lo tanto su relación es inversa." },
    { u: "SMYR T4", q: "¿Por qué la parte integral sigue actuando aunque el error sea cero?", opts: ["Porque tiene un fallo de diseño.", "Porque acumula el error generado anteriormente antes de la estabilidad.", "Porque el sensor siempre miente.", "Para generar ruido intencionadamente."], ans: 1, exp: "Mantiene la 'memoria' del esfuerzo que hizo para llegar hasta ese punto de equilibrio." },
    { u: "SMYR T4", q: "Al aumentar la constante integral K_i, ¿qué sucede con el sobrepico?", opts: ["Decrementa.", "Se elimina por completo.", "Incrementa.", "Permanece igual."], ans: 2, exp: "Un valor K_i alto acumula demasiado error y el sistema se 'pasa de largo', aumentando el sobrepico." },
    { u: "SMYR T4", q: "¿Cuál es la función de transferencia del controlador PI?", opts: ["C(s) = K_p + K_d * s", "C(s) = K_p + (K_i / s)", "C(s) = K_i / s", "C(s) = K_p * K_i * s"], ans: 1, exp: "Suma la parte proporcional y la integral (1/s en Laplace)." },
    { u: "SMYR T4", q: "¿Para qué se añade el término derivativo (K_d) al controlador?", opts: ["Para eliminar el error final.", "Para agregar mayor control en el régimen transitorio y mejorar la estabilidad.", "Para reducir el coste del PLC.", "Para amplificar el ruido."], ans: 1, exp: "Al 'ver' la pendiente del error, frena el sistema si va demasiado rápido." },
    { u: "SMYR T4", q: "¿Cuál es el mayor problema de implementar la acción derivativa?", opts: ["Que es muy barata.", "Que es muy sensible al ruido de la señal.", "Que elimina el sobrepico.", "Que no tiene representación matemática."], ans: 1, exp: "Derivar el ruido de un sensor produce grandes picos de actuación destructivos." },
    { u: "SMYR T4", q: "¿Cómo afecta el aumento de la constante derivativa K_d a la estabilidad del sistema?", opts: ["La decrementa.", "No tiene efecto.", "La mejora.", "Vuelve al sistema oscilante."], ans: 2, exp: "K_d aporta amortiguamiento, lo que mejora la estabilidad (siempre que no haya ruido excesivo)." },
    { u: "SMYR T4", q: "¿Qué efecto tiene aumentar K_d sobre el tiempo de establecimiento?", opts: ["Lo incrementa significativamente.", "Produce un poco de decremento.", "Lo vuelve cero.", "Lo duplica."], ans: 1, exp: "Al amortiguar las oscilaciones, el sistema se queda quieto en su valor final un poco antes." },
    { u: "SMYR T4", q: "¿Qué acción del PID 'decrementa significativamente' el error en régimen estacionario?", opts: ["K_p", "K_i", "K_d", "Ninguna, el error es inevitable."], ans: 1, exp: "La acción Integral (Ki) es la única responsable de aplastar a cero el error estacionario." },
    { u: "SMYR T4", q: "En la fórmula en el dominio del tiempo del controlador PID, ¿a qué es igual u(t)?", opts: ["u(t) = Kp*e(t) + Ki∫e(t)dt + Kd*(de(t)/dt)", "u(t) = Kp+Ki+Kd", "u(t) = Kp / e(t)", "u(t) = ∫(Kp+Ki+Kd)dt"], ans: 0, exp: "Suma de los tres términos actuando sobre la señal de error." },
    { u: "SMYR T4", q: "¿Dónde se encuentran integrados los controladores PID hoy en día habitualmente?", opts: ["En los termómetros de mercurio.", "En los autómatas programables (PLC) de gama media y alta.", "Solo en ordenadores de la NASA.", "En las válvulas manuales."], ans: 1, exp: "Los PLC actuales tienen bloques de función PID preprogramados internamente." },
    { u: "SMYR T4", q: "¿Qué plataforma permite simular sistemas de control PID de velocidad de motor?", opts: ["Photoshop.", "Tinkercad (de Autodesk).", "WhatsApp.", "Excel."], ans: 1, exp: "Tinkercad permite usar Arduino virtual y programar lazos PID visualmente." },
    { u: "SMYR T4", q: "¿Qué término del PID no produce cambios en el error en régimen estacionario al aumentar?", opts: ["K_p", "K_i", "K_d", "Todos producen cambios."], ans: 2, exp: "En estado estacionario (constante), la derivada vale cero, por lo que K_d no afecta al error final." },
    { u: "SMYR T4", q: "Según las diapositivas, ¿qué se debe hacer si persisten las oscilaciones en un sistema con resistencias y PWM?", opts: ["Aumentar la potencia.", "Disminuir el ciclo total hasta eliminarlas.", "Cambiar el sensor.", "Apagar el sistema."], ans: 1, exp: "Si el ciclo es muy largo, la temperatura sube y baja. Acortar el ciclo mejora la estabilidad térmica." },
    { u: "SMYR T5", q: "¿Cómo se conoce de manera normalizada a la entrada principal del controlador?", opts: ["Variable de proceso PV", "Variable manipulada MV", "Valor de consigna SP", "Ninguna de las respuestas es correcta"], ans: 0, exp: "La entrada principal (valor medido que viene del proceso) se llama PV o Variable de Proceso." },
    { u: "SMYR T5", q: "¿Cómo se conoce de manera normalizada a la salida del controlador?", opts: ["Variable de proceso PV", "Variable manipulada MV", "Valor de consigna SP", "Ninguna de las respuestas es correcta"], ans: 1, exp: "La salida del controlador, que actúa sobre el proceso, se denomina MV o Variable Manipulada." },
    { u: "SMYR T5", q: "¿Cómo se conoce de manera normalizada a valor de referencia seleccionado en un equipo para un determinado valor de tensión o intensidad?", opts: ["Variable de proceso PV", "Variable manipulada MV", "Valor de consigna SP", "Ninguna de las respuestas es correcta"], ans: 2, exp: "El valor de referencia que nosotros seleccionamos como objetivo se denomina SP (Set Point) o consigna." },
    { u: "SMYR T5", q: "¿Cómo se denomina el diagrama de proceso más utilizado y representativo de un proceso industrial?", opts: ["Diagrama de secuencias", "Diagrama de Karnaugh", "Diagrama P e I", "Ninguno de los anteriores"], ans: 2, exp: "El Diagrama P&I (Piping and Instrumentation Diagram) es el estándar para representar tuberías e instrumentación." },
    { u: "SMYR T5", q: "¿Cuál de las siguientes es una estrategia de control avanzado?", opts: ["Control en bucle", "Control de extracción", "Control borroso", "Todas las respuestas son correctas"], ans: 2, exp: "El control borroso es una de las estrategias de control avanzado, frente al PID clásico." },
    { u: "SMYR T5", q: "¿Cuál de los siguientes no es uno de los parámetros fundamentales utilizados en la regulación de equipos?", opts: ["Banda proporcional", "Tiempo derivativo", "Tiempo integral", "Todos son parámetros fundamentales"], ans: 3, exp: "La banda proporcional, el tiempo integral y el tiempo derivativo son los tres parámetros fundamentales del PID." },
    { u: "SMYR T5", q: "¿Cuáles de las siguientes características no es importante en la selección de componentes?", opts: ["Intensidad lumínica instalada en planta", "Grado de protección IP", "Parámetros físicos del proceso como temperatura o humedad", "Condiciones ambientales especiales como atmósferas ATEX"], ans: 0, exp: "La intensidad de la luz en la planta no afecta al funcionamiento de los componentes de control, a diferencia del IP, las atmósferas o los parámetros físicos." },
    { u: "SMYR T5", q: "¿Qué separan los separadores galvánicos?", opts: ["Elementos que trabajan con distintas intensidades", "Elementos de distintos materiales conductores", "Equipos con distintas tensiones", "Octoacopladores de diferentes fabricantes"], ans: 2, exp: "Los separadores galvánicos aíslan equipos con distintas tensiones mediante optoacopladores para evitar que un fallo eléctrico de potencia dañe al sistema de control." },
    { u: "SMYR T5", q: "En el control borroso es la parte que se encarga de asignar a un valor preciso, un grado de pertenencia a un conjunto borroso a través de funciones de pertenencia.", opts: ["Borrosificador o fuzzyfier", "Desborrosificador o defuzzyfier", "Dispositivo de inferencia borrosa", "Ninguna de las respuestas es correcta"], ans: 0, exp: "El Borrosificador convierte las entradas físicas en grados de pertenencia borrosa." },
    { u: "SMYR T5", q: "En el control borroso, es la parte encargada de interpretar la base de las reglas lógicas para que se obtengan unos valores numéricos a partir de los grados de pertenencia.", opts: ["Borrosificador o fuzzyfier", "Desborrosificador o defuzzyfier", "Dispositivo de inferencia borrosa", "Ninguna de las respuestas es correcta"], ans: 2, exp: "El dispositivo de inferencia es el 'cerebro' que procesa las reglas lógicas borrosas." },
    { u: "SMYR T5", q: "¿Qué factores se deben considerar al seleccionar los componentes de un sistema de medida y regulación?", opts: ["El coste del equipo y su disponibilidad comercial en el mercado actual.", "La precisión requerida así como las condiciones de instalación y el entorno.", "El tipo de fluido que circula por la tubería y su temperatura máxima de diseño.", "El color del armario eléctrico y sus dimensiones exteriores completas."], ans: 1, exp: "La selección depende de factores técnicos, operativos y ambientales (entorno)." },
    { u: "SMYR T5", q: "¿Qué norma establece los grados de protección IP para equipos industriales?", opts: ["Norma internacional ISA-S5.1.", "Estándar europeo UNE-EN 50102.", "Norma UNE 20324 o su actual UNE-60529.", "Teorema de Nyquist-Shannon para equipos."], ans: 2, exp: "Los códigos IP se rigen clásicamente por la norma UNE 20324 y su actualización UNE-60529." },
    { u: "SMYR T5", q: "En un grado de protección IP, ¿a qué corresponde el primer dígito?", opts: ["Protección contra el agua.", "Protección ante cuerpos sólidos.", "Protección contra impactos mecánicos.", "Nivel de precisión del sensor."], ans: 1, exp: "El primer número del IP define la protección contra la intrusión de cuerpos sólidos (polvo, herramientas, dedos)." },
    { u: "SMYR T5", q: "¿Qué grado de protección IP es recomendable en el sector alimentario para evitar bacterias?", opts: ["Grado de protección IP20.", "Grado de protección IP44.", "Grado de protección IP65.", "Grado de protección IPX8."], ans: 2, exp: "IP65 asegura estanqueidad total al polvo y protección contra chorros de agua a presión, permitiendo lavados industriales." },
    { u: "SMYR T5", q: "Si un elemento no tiene una protección específica contra el agua, ¿por qué letra se sustituye el dígito en el código IP?", opts: ["Letra O.", "Letra Z.", "Letra X.", "Letra W."], ans: 2, exp: "La letra X se usa cuando no se especifica protección para uno de los criterios." },
    { u: "SMYR T5", q: "¿Qué representa el segundo dígito en un grado de protección IP?", opts: ["Protección ante cuerpos sólidos.", "Protección contra impactos mecánicos.", "Protección contra el agua.", "El tiempo de respuesta del equipo."], ans: 2, exp: "El segundo dígito indica el grado de protección contra la entrada perjudicial de agua." },
    { u: "SMYR T5", q: "¿Qué norma regula la protección contra impactos mecánicos nocivos IK?", opts: ["Norma UNE 20324.", "Norma UNE-EN 50102.", "Norma ISA-S5.1.", "Norma UNE-60529."], ans: 1, exp: "La norma UNE-EN 50102 especifica el código IK para la resistencia a impactos." },
    { u: "SMYR T5", q: "¿Cuál es el nivel de energía de choque para una protección IK10?", opts: ["Un impacto de 1 julio.", "Un impacto de 5 julios.", "Un impacto de 20 julios.", "Un impacto de 100 julios."], ans: 2, exp: "IK10 es la máxima protección de la tabla estándar, soportando un impacto de 20 julios." },
    { u: "SMYR T5", q: "¿Qué dispositivo de protección contra sobretensiones es lento en respuesta pero soporta fuertes descargas en kiloamperios?", opts: ["Los varistores.", "Los diodos supresores.", "Los descargadores de gas.", "Los separadores galvánicos."], ans: 2, exp: "Los descargadores de gas soportan las mayores corrientes de descarga, aunque tardan más en activarse." },
    { u: "SMYR T5", q: "¿Cuál es la principal característica de los varistores en la protección eléctrica?", opts: ["Son los elementos de protección más rápidos del mercado industrial.", "Son un punto intermedio en velocidad y absorción de energía de descarga.", "Sirven exclusivamente para aislar señales analógicas de sensores.", "Aíslan galvánicamente la señal de control mediante un optoacoplador."], ans: 1, exp: "Son el punto intermedio: más rápidos que el gas, pero con menor capacidad de absorción de energía." },
    { u: "SMYR T5", q: "¿Qué dispositivos son muy rápidos limitando picos de tensión pero tienen un poder de descarga menor?", opts: ["Descargadores de gas.", "Varistores de óxido metálico.", "Diodos supresores.", "Relés térmicos convencionales."], ans: 2, exp: "Los diodos supresores son ultrarrápidos, ideales para proteger electrónica delicada ante picos pequeños." },
    { u: "SMYR T5", q: "¿Para qué se utilizan los separadores galvánicos en la industria?", opts: ["Para registrar la variación de temperatura en procesos críticos.", "Para aislar circuitos con distintas tensiones usando un optoacoplador.", "Para incrementar gradualmente la presión en las tuberías del sistema.", "Para almacenar el programa de usuario del PLC en memoria no volátil."], ans: 1, exp: "Aíslan eléctricamente dos circuitos para que un cortocircuito en uno no afecte al otro." },
    { u: "SMYR T5", q: "¿En qué consisten básicamente los controladores industriales modernos?", opts: ["Sistemas mecánicos basados en resortes y palancas neumáticas.", "Sistemas digitales con un microprocesador que ejecuta un algoritmo.", "Termómetros analógicos de mercurio con contactos eléctricos.", "Interruptores manuales con enclavamiento mecánico de seguridad."], ans: 1, exp: "Utilizan procesadores para calcular continuamente la acción de control." },
    { u: "SMYR T5", q: "¿Qué dispositivo incorpora habitualmente la función de controlador dentro de sus capacidades?", opts: ["El sensor de proceso.", "El actuador final.", "El controlador lógico programable PLC.", "El variador de frecuencia del motor."], ans: 2, exp: "Los PLCs actuales llevan integrados bloques de control PID listos para usar." },
    { u: "SMYR T5", q: "¿Qué norma estandariza los diagramas P e I de tuberías e instrumentación?", opts: ["Norma UNE-EN 50102.", "Norma ISA-S5.1.", "Teorema de Nyquist-Shannon.", "Norma UNE 20324."], ans: 1, exp: "La norma ISA-S5.1 es el estándar global para la simbología de diagramas de instrumentación." },
    { u: "SMYR T5", q: "En la identificación de instrumentos, ¿qué representa la primera letra?", opts: ["El tipo de instrumento.", "La función del equipo.", "La variable medida o inicial.", "El número de lazo."], ans: 2, exp: "La primera letra define qué estamos midiendo (ej. T para Temperatura, P para Presión)." },
    { u: "SMYR T5", q: "Según la norma ISA-S5.1, ¿qué variable representa la letra L?", opts: ["Temperatura.", "Caudal.", "Nivel.", "Presión."], ans: 2, exp: "La letra L proviene de Level que significa Nivel." },
    { u: "SMYR T5", q: "¿Qué significa la letra T como primera letra en una etiqueta de instrumento?", opts: ["Tiempo.", "Tensión eléctrica.", "Temperatura.", "Transmisor."], ans: 2, exp: "La letra T como primera inicial significa Temperature o Temperatura." },
    { u: "SMYR T5", q: "¿Qué representa la letra V cuando aparece como letra sucesiva?", opts: ["Vacío del sistema.", "Voltaje de alimentación.", "Válvula respiradero o amortiguador.", "Velocidad del fluido."], ans: 2, exp: "Como letra sucesiva, la V indica que es una Válvula de control." },
    { u: "SMYR T5", q: "¿Cómo se simboliza un instrumento montado en el campo en un diagrama de tuberías e instrumentación?", opts: ["Un círculo con una línea continua en medio.", "Un círculo simple sin líneas internas.", "Un círculo dentro de un cuadrado.", "Un círculo con dos líneas horizontales."], ans: 1, exp: "El círculo simple vacío significa que el instrumento está instalado a pie de máquina o planta." },
    { u: "SMYR T5", q: "¿Qué indica un círculo con una línea continua horizontal en un diagrama P e I?", opts: ["Que es un instrumento montado en el campo a pie de máquina.", "Que es un instrumento montado en el panel de control y accesible al operador.", "Que es un instrumento montado dentro de un armario no accesible.", "Que es el PLC de reserva del sistema principal."], ans: 1, exp: "Indica que está montado en el panel principal y es accesible por el operario." },
    { u: "SMYR T5", q: "¿Cómo se representa un instrumento montado dentro de un armario que no es accesible directamente?", opts: ["Círculo con línea continua.", "Círculo con línea discontinua.", "Círculo con doble línea continua.", "Hexágono simple."], ans: 1, exp: "La línea de trazos discontinua indica montaje detrás del panel, no accesible directamente." },
    { u: "SMYR T5", q: "¿Para qué se aconseja separar galvánicamente la tarjeta de salida de los autómatas programables?", opts: ["Para reducir drásticamente el consumo energético general del sistema.", "Para aislar el sistema de control de posibles fallos de potencia.", "Para multiplicar la velocidad de lectura de los sensores analógicos.", "Para disipar el calor generado por el microprocesador principal."], ans: 1, exp: "Aísla el 'cerebro' del PLC de las fuertes corrientes que manejan los actuadores." },
    { u: "SMYR T5", q: "¿Qué define el término Variable de Proceso en un controlador?", opts: ["El valor de consigna.", "La salida del controlador.", "La entrada principal medida.", "El error de cálculo."], ans: 2, exp: "PV es el valor real medido que se intenta controlar." },
    { u: "SMYR T5", q: "¿A qué se refiere el término Variable Manipulada?", opts: ["Al valor que desea alcanzar el sistema en régimen estacionario.", "A la salida del controlador que actúa de manera directa sobre el proceso.", "A la medida exacta de la temperatura de la sala de calderas.", "Al tiempo de muestreo necesario para realizar la medición digital."], ans: 1, exp: "Es la señal que el controlador envía a la válvula o actuador." },
    { u: "SMYR T5", q: "¿Qué es el Set Point o punto de ajuste?", opts: ["La variable de proceso.", "El valor de consigna o referencia.", "El tiempo derivativo.", "La protección contra sólidos."], ans: 1, exp: "Es el objetivo al que queremos que llegue el proceso." },
    { u: "SMYR T5", q: "¿Qué sucede si la Banda Proporcional de un sistema de control es muy grande?", opts: ["El sistema comienza a oscilar de manera muy violenta y descontrolada.", "El sistema se aproxima al objetivo de forma lenta evitando oscilaciones.", "El error estacionario del sistema tiende a volverse un valor infinito.", "La salida del controlador se satura instantáneamente al valor máximo."], ans: 1, exp: "Una Banda Proporcional grande significa una Ganancia pequeña, el control es suave y lento." },
    { u: "SMYR T5", q: "¿Cuál es la relación matemática entre la Banda Proporcional y la ganancia proporcional?", opts: ["Banda Proporcional igual a la ganancia por cien", "Banda Proporcional igual a cien entre la ganancia", "Banda Proporcional igual a la ganancia al cuadrado", "No tienen ningún tipo de relación matemática directa."], ans: 1, exp: "Son inversamente proporcionales: Banda Proporcional = 100 / Ganancia Proporcional." },
    { u: "SMYR T5", q: "¿Qué efecto tiene aumentar el Tiempo Integral en un sistema?", opts: ["Aumenta drásticamente la precisión general del sistema de control.", "El sistema se vuelve más oscilante y tarda más en corregir los errores.", "Filtra completamente todo el ruido de alta frecuencia del sensor.", "Actúa como un freno direccional reduciendo los cambios muy rápidos."], ans: 1, exp: "Al aumentar el tiempo integral la acción integral disminuye, haciendo al sistema más lento para eliminar el error, lo que puede causar desvíos." },
    { u: "SMYR T5", q: "¿Cómo se conoce también al Tiempo Derivativo en algunos dispositivos comerciales?", opts: ["Modo Reset.", "Modo Bias.", "Modo Rate.", "Modo Lag."], ans: 2, exp: "Rate o Tasa porque actúa según la velocidad de variación del error." },
    { u: "SMYR T5", q: "¿Qué sucede al aumentar el Tiempo Derivativo?", opts: ["El lazo de control se vuelve extremadamente rápido y muy oscilante.", "Aumenta el freno del sistema haciéndolo más lento pero estable.", "El error estacionario en régimen permanente desaparece por completo.", "La memoria del integrador se satura causando inestabilidad total."], ans: 1, exp: "Aumenta la fuerza de la acción derivativa, frenando bruscamente al sistema para que no oscile." },
    { u: "SMYR T5", q: "¿Para qué sirve el parámetro Bias o polarización en el control de procesos?", opts: ["Para registrar el nivel exacto de agua en un tanque de almacenamiento.", "Para compensar desplazamientos o rechazar perturbaciones constantes.", "Para establecer el grado de protección contra agentes ambientales.", "Para incrementar la velocidad de procesamiento del autómata."], ans: 1, exp: "El Bias añade una constante a la salida para que el controlador actúe en un punto medio óptimo de la válvula." },
    { u: "SMYR T5", q: "¿Qué es el fenómeno conocido como Windup del integrador?", opts: ["Un subsistema automático de seguridad y extinción de incendios.", "La saturación del término integral por un error persistente en el tiempo.", "El periodo necesario para que un sensor térmico se enfríe por completo.", "Una técnica moderna de control predictivo basada en redes neuronales."], ans: 1, exp: "Es el exceso de 'carga' en la integral porque la válvula no da más de sí y el error sigue acumulándose." },
    { u: "SMYR T5", q: "¿Qué función cumple el sistema Bumpless o de transferencia sin saltos?", opts: ["Bloquea la interfaz para evitar que el operario toque el panel por error.", "Garantiza una transición suave y sin saltos entre modo manual y automático.", "Aumenta significativamente la velocidad del fluido dentro de las tuberías.", "Refuerza la envolvente exterior para proteger contra fuertes impactos mecánicos."], ans: 1, exp: "Garantiza una transición suave entre control manual y automático sin pegar un 'tirón' a la válvula." },
    { u: "SMYR T5", q: "¿Qué define el Sampling Time o periodo de muestreo?", opts: ["El periodo total requerido para la fabricación e instalación del autómata.", "El tiempo transcurrido entre dos lecturas consecutivas de una misma señal.", "La profundidad máxima permitida para sumergir el equipo sin que sufra daños.", "El ángulo de desfase crítico representado en un diagrama polar de Bode."], ans: 1, exp: "Es la frecuencia con la que el sistema digital 'mira' el sensor." },
    { u: "SMYR T5", q: "Según el teorema de Nyquist-Shannon, ¿cuál debe ser la frecuencia de muestreo mínima?", opts: ["Debe ser exactamente igual al ancho de banda del sistema.", "Debe ser al menos el doble del ancho de banda de la señal.", "Debe ser diez veces más lenta que la velocidad de la planta.", "Debe ser un valor calculado mediante funciones de lógica borrosa."], ans: 1, exp: "Es necesario muestrear al doble de la frecuencia máxima para no perder información." },
    { u: "SMYR T5", q: "En la práctica, ¿qué valor se toma para el sampling time respecto a la constante de tiempo más rápida de la planta?", opts: ["Dos veces más rápido.", "Diez veces más rápido.", "Igual a la constante.", "Cien veces más lento."], ans: 1, exp: "Para control industrial, muestrear 10 veces más rápido que la dinámica de la planta garantiza un buen desempeño continuo." },
    { u: "SMYR T5", q: "¿Cuándo es preferible usar un algoritmo incremental en un control PID?", opts: ["Cuando el error registrado por el sistema es siempre de signo positivo.", "Cuando los valores de error estacionario pueden llegar a ser cero absoluto.", "Se aplica principalmente en sistemas de control diseñados en lazo abierto.", "Resulta ideal cuando el nivel de ruido electromagnético es muy elevado."], ans: 1, exp: "El algoritmo incremental calcula variaciones sobre la salida anterior, lo cual es útil para evitar el windup." },
    { u: "SMYR T5", q: "¿En qué consiste el Control en Adelante o control Feedforward?", opts: ["Esperar pacientemente a que se detecte el error y proceder a corregirlo.", "Medir las perturbaciones para compensarlas antes de que afecten al proceso.", "Utilizar exclusivamente algoritmos de control basados en lógica difusa.", "Desconectar totalmente la alimentación del sistema si se detecta un fallo."], ans: 1, exp: "Se anticipa al problema midiendo la perturbación antes de que llegue a desestabilizar la salida." },
    { u: "SMYR T5", q: "¿Cuál es el principal inconveniente que presenta el sistema feedforward?", opts: ["Presenta un tiempo de respuesta excesivamente lento ante los cambios.", "Solo se puede aplicar si las perturbaciones externas son fácilmente medibles.", "Genera oscilaciones continuas que provocan inestabilidad en la planta.", "Requiere de forma obligatoria la programación de modelos matemáticos borrosos."], ans: 1, exp: "Si la perturbación no se puede medir con un sensor, el feedforward no puede actuar." },
    { u: "SMYR T5", q: "¿Qué caracteriza estructuralmente al Control en Cascada?", opts: ["Emplea un único sensor centralizado para gobernar todo el proceso industrial completo.", "Usa un lazo de control secundario anidado dentro de las acciones de un lazo principal.", "Está diseñado de forma exclusiva para el control de sistemas oleohidráulicos pesados.", "Consiste en una estricta secuencia de pasos operados de forma totalmente manual."], ans: 1, exp: "El controlador primario da la consigna a un controlador secundario." },
    { u: "SMYR T5", q: "En un control en cascada, ¿cómo debe ser la rapidez del lazo interno respecto al externo?", opts: ["La velocidad debe ser igual.", "El lazo interno debe ser más rápido.", "El lazo externo debe ser más rápido.", "La rapidez no tiene ninguna importancia."], ans: 1, exp: "El lazo interno debe reaccionar inmediatamente para aislar las perturbaciones antes de que lleguen al externo." },
    { u: "SMYR T5", q: "¿Qué es exactamente un Control de Relación en los sistemas industriales?", opts: ["Sincronizar de forma precisa los perfiles de temperatura y de tiempo de cocción.", "Mantener una proporción fija entre una variable primaria de referencia y otra secundaria.", "Ajustar el ritmo de producción industrial basándose en los costes actuales del mercado.", "Gobernar los actuadores finales utilizando de manera exclusiva múltiples señales digitales."], ans: 1, exp: "Típico en mezclas, donde un caudal secundario debe ser un porcentaje fijo del caudal principal." },
    { u: "SMYR T5", q: "¿Cuándo es interesante aplicar una estrategia de Control Selectivo en nuestra planta?", opts: ["Solamente cuando hay una única variable a controlar.", "Cuando existen varios límites en el proceso que no deben sobrepasarse bajo ningún concepto.", "Es una estrategia óptima para sistemas de riego muy simples.", "Únicamente se aplica para medir el caudal volumétrico de agua potable."], ans: 1, exp: "Selecciona entre varias señales de control para proteger la planta de sobrepresiones o sobrecalentamientos." },
    { u: "SMYR T5", q: "¿Qué hace la técnica denominada Control Adaptativo?", opts: ["Se adapta automáticamente a los cambios bruscos de la meteorología en el exterior.", "Reajusta de forma autónoma sus constantes según el trabajo que se esté realizando.", "Funciona exclusivamente en modo de supervisión y control de forma manual.", "Emplea lógica binaria pura para decidir el estado de apertura de todas las válvulas."], ans: 1, exp: "Afinan automáticamente el PID cuando el proceso cambia de comportamiento." },
    { u: "SMYR T5", q: "¿En qué se basa el principio de funcionamiento del Control Predictivo?", opts: ["En la experiencia empírica y la intuición del operario para anticipar posibles fallos en máquina.", "En usar un modelo matemático interno para calcular anticipadamente el comportamiento futuro.", "En registrar de forma continua y analizar el error estacionario después de una hora de marcha.", "En instalar potentes y rápidos descargadores de gas para predecir las fuertes sobretensiones."], ans: 1, exp: "Usa un modelo matemático interno para calcular qué pasará si aplica cierta energía ahora." },
    { u: "SMYR T5", q: "¿Quién introdujo la conocida teoría de conjuntos borrosos en el año 1965?", opts: ["El matemático Nyquist.", "El ingeniero Lofti A. Zadeh.", "El científico Shannon.", "El físico Isaac Newton."], ans: 1, exp: "Zadeh propuso la Lógica Difusa para lidiar con conceptos lingüísticos vagos." },
    { u: "SMYR T5", q: "¿Qué tipo de lógica utiliza internamente el Control Borroso?", opts: ["Lógica binaria clásica de ceros y unos.", "Lógica multivalor con infinitos valores entre cero y uno.", "Lógica neumática de válvulas distribuidoras.", "Lógica de contactos eléctricos o relés electromecánicos."], ans: 1, exp: "A diferencia del booleano, un estado puede ser 0.7 verdadero y 0.3 falso al mismo tiempo." },
    { u: "SMYR T5", q: "¿Cuáles son las tres partes principales de una estructura con lógica borrosa?", opts: ["Fase de Entrada, Fase de Proceso y Fase de Salida.", "Borrosificador, Dispositivo de inferencia y Desborrosificador.", "Bloque del Sensor, Bloque del PLC y Bloque del Actuador.", "Término Proporcional, Término Integral y Término Derivativo."], ans: 1, exp: "Fuzzifier, Inferencia y Defuzzifier." },
    { u: "SMYR T5", q: "¿Qué hace específicamente la etapa del Desborrosificador?", opts: ["Transforma cualquier magnitud física real del proceso en una variable lingüística borrosa.", "Traduce el resultado lógico difuso a un valor de control físico analógico concreto y preciso.", "Actúa como barrera primaria de protección frente a los picos de intensidad y sobretensiones severas.", "Calcula matemáticamente el volumen exacto de líquido que permanece almacenado en el tanque."], ans: 1, exp: "Traduce la decisión difusa a un valor analógico concreto." },
    { u: "SMYR T5", q: "En un diagrama de instrumentación, ¿qué indica la letra P como primera letra?", opts: ["Variable de Potencia.", "Variable de Presión o vacío.", "Modo Proporcional puro.", "Elemento Posicionador mecánico."], ans: 1, exp: "En la norma ISA-S5.1, la letra P como primera inicial hace referencia a Presión." },
    { u: "SMYR T5", q: "¿Qué significa la etiqueta TIC en un diagrama estandarizado de instrumentación industrial?", opts: ["Transmisor de Intensidad y de Caudal.", "Controlador Indicador de Temperatura.", "Tanque de Inmersión Continua.", "Test de Inspección de Control de Calidad."], ans: 1, exp: "T de Temperatura, I de Indicador y C de Controlador." },
    { u: "SMYR T6", q: "¿Cómo conocemos a la relación entre el incremento del valor real que se está midiendo y el incremento de la medida leída por el sensor?:", opts: ["Fondo de escala", "Alcance", "Sensibilidad", "Resolución"], ans: 2, exp: "La sensibilidad relaciona la variación de la magnitud física con la variación de la señal que entrega el sensor." },
    { u: "SMYR T6", q: "¿Cuál de los siguientes errores habituales debemos tener en cuenta en los equipos de medida y regulación?", opts: ["Error de cero", "Error de span", "Error de histéresis", "Todas las respuestas son correctas"], ans: 3, exp: "En la calibración de instrumentos se deben considerar y corregir los errores de cero, span (alcance) e histéresis." },
    { u: "SMYR T6", q: "¿Cuál debería ser el primer paso en la puesta en servicio de un equipo de medida y regulación?", opts: ["Ensayo en carga", "Ensayo en vacío", "Prueba de control o mando", "Comprobar posibles desperfectos del transporte"], ans: 3, exp: "Antes de aplicar cualquier tensión o presión, siempre se debe realizar una inspección visual para descartar daños físicos o partes móviles sueltas." },
    { u: "SMYR T6", q: "¿Qué calibración es más compleja?", opts: ["La de equipos de medida con señal analógica", "La de equipos de medida con señal digital", "Ambos comparten el mismo procedimiento de calibración", "La calibración no se debe realizar en estos equipos"], ans: 0, exp: "Los equipos analógicos requieren ajustes físicos manuales, mientras que los digitales suelen autoajustarse por software." },
    { u: "SMYR T6", q: "Cuando un equipo instalado precisa de un voltaje concreto, en la instalación suelen utilizarse:", opts: ["Variadores de frecuencia", "Calibradores de tensión", "Voltímetros", "Transformadores"], ans: 3, exp: "Los transformadores de medida o de alimentación se usan para adaptar el voltaje de la red al que necesita el equipo." },
    { u: "SMYR T6", q: "El alcance de un sensor:", opts: ["Se refiere a la distancia máxima absoluta a la que el equipo mantiene toda su sensibilidad nominal intacta", "Se calcula mediante la diferencia de los límites inferior y superior del rango", "Se refiere a la distancia de trabajo en la que el sensor ofrece una fiabilidad mínima garantizada del 90 por ciento", "Ninguna de las anteriores opciones de respuesta es la correcta"], ans: 1, exp: "El alcance o SPAN es la diferencia matemática entre el valor máximo y el valor mínimo del rango de medida." },
    { u: "SMYR T6", q: "El rango del sensor:", opts: ["Indica las lecturas estadísticas más habituales que el dispositivo va a ofrecer durante su vida útil", "Se refiere a las dimensiones físicas exteriores del dispositivo instalado en planta", "Se refiere a los límites máximo y mínimo que puede leer", "Ninguna de las respuestas proporcionadas anteriormente es correcta"], ans: 2, exp: "El rango especifica desde qué valor hasta qué valor es capaz de medir el instrumento." },
    { u: "SMYR T6", q: "Es la mínima variación que debe darse en la magnitud observada para que se produzca una variación en el valor medido:", opts: ["Sensibilidad", "Resolución", "Fondo de escala", "Rango del sensor"], ans: 1, exp: "La resolución es el escalón más pequeño que el instrumento es capaz de detectar y mostrar." },
    { u: "SMYR T6", q: "Operación por la que ajustamos la veracidad de los valores de medida obtenidos por los sensores a partir de unos patrones de medida:", opts: ["Calibración", "Ajuste de rango", "Ajuste general", "Ninguna de las respuestas es correcta"], ans: 0, exp: "La calibración consiste en comparar las lecturas del instrumento con un patrón estándar exacto y ajustar las desviaciones." },
    { u: "SMYR T6", q: "Un sensor de temperatura es capaz de medir desde -20ºC hasta 180ºC, ¿Cuál es su fondo de escala?", opts: ["200ºC", "180ºC", "180%", "200%"], ans: 1, exp: "El fondo de escala siempre es el valor máximo absoluto que marca la escala del instrumento, en este caso 180ºC." },
    { u: "SMYR T6", q: "¿Qué se suele utilizar en instalaciones donde se requiere medir parámetros eléctricos de potencia?", opts: ["Termistores de platino.", "Transformadores de medida de corriente y tensión.", "Solo interruptores manuales.", "Caudalímetros ultrasónicos."], ans: 1, exp: "Reducen las altas corrientes o tensiones a niveles medibles y seguros para los instrumentos." },
    { u: "SMYR T6", q: "¿Cómo se define el Rango de un sensor?", opts: ["Es el valor máximo absoluto de lectura que se registra en el visor numérico principal.", "Es el conjunto de valores comprendidos entre los límites superior e inferior de capacidad.", "Es la diferencia matemática exacta calculada entre la señal de salida y la señal de entrada.", "Es el tiempo total medido en milisegundos que tarda el equipo en responder al estímulo."], ans: 1, exp: "Especifica los límites dentro de los cuales el sensor puede trabajar." },
    { u: "SMYR T6", q: "¿Qué es el Alcance de un sensor?", opts: ["El resultado de la suma matemática de los límites superior e inferior de la escala de funcionamiento.", "La diferencia entre el límite superior y el inferior del rango.", "El valor mínimo absoluto que el equipo es capaz de detectar en condiciones de ruido extremo.", "La distancia física real a la que llega el cableado de conexión hacia el PLC central."], ans: 1, exp: "Alcance = Límite Superior - Límite Inferior." },
    { u: "SMYR T6", q: "¿Qué representa el Fondo de escala?", opts: ["El valor central estadístico que se obtiene calculando la media aritmética del rango del dispositivo.", "El valor máximo de lectura de la escala en uso.", "El nivel de error total que se va acumulando de forma progresiva al final de la jornada de trabajo.", "El tamaño físico completo de la carcasa exterior del sensor una vez montado."], ans: 1, exp: "Es el tope máximo que marca la lectura del instrumento." },
    { u: "SMYR T6", q: "¿Qué indica la Precisión de referencia?", opts: ["La velocidad de estabilización de la respuesta frente a una entrada de tipo escalón unitario.", "El error de medida máximo en condiciones nominales.", "La cantidad exacta de bits que es capaz de procesar internamente el microcontrolador principal.", "La resistencia mecánica probada frente a la entrada de polvo y chorros de agua a presión."], ans: 1, exp: "Indica el error máximo garantizado por el fabricante en condiciones normales." },
    { u: "SMYR T6", q: "¿Cómo se define la Sensibilidad de un sensor?", opts: ["La capacidad estructural del equipo para no sufrir daños frente a impactos mecánicos severos.", "La relación entre el incremento del valor real medido y el incremento de la medida leída.", "El periodo de tiempo de muestreo mínimo exigido por el convertidor analógico a digital.", "El ángulo de desfase crítico registrado al representar la respuesta en un diagrama polar de Bode."], ans: 1, exp: "Cuánto cambia la salida por cada unidad que cambia la entrada." },
    { u: "SMYR T6", q: "¿Qué es la Resolución en instrumentación?", opts: ["La densidad de píxeles y la nitidez visual que es capaz de ofrecer la pantalla de cuarzo líquido del equipo.", "La variación mínima de la magnitud observada para producir un cambio en el valor medido.", "El error sistemático derivado de una mala calibración inicial en el punto de cero absoluto.", "El grado estandarizado de protección física frente a la exposición de choques y vibraciones mecánicas."], ans: 1, exp: "Es el salto mínimo detectable." },
    { u: "SMYR T6", q: "¿A qué se refiere la Repetibilidad de medida?", opts: ["Al procedimiento estadístico de registrar la misma medida un número muy elevado de veces por minuto.", "A la variación de las medidas tomadas por un sensor bajo condiciones iguales.", "Al hecho comprobado de que un sensor mal calibrado tiende a fallar sistemáticamente de la misma manera.", "Al porcentaje de tiempo que una resistencia calefactora permanece activa durante su ciclo de trabajo completo."], ans: 1, exp: "La capacidad de dar el mismo resultado al medir repetidamente la misma magnitud." },
    { u: "SMYR T6", q: "¿Qué es la Zona muerta?", opts: ["El área geográfica de la planta industrial donde no llega adecuadamente la señal inalámbrica de red.", "El rango de valores de la magnitud medida que no hace variar la salida.", "El punto de funcionamiento exacto de un motor asíncrono en el momento que su deslizamiento es nulo.", "La posición de seguridad que adopta una válvula de compuerta manual cuando está totalmente cerrada."], ans: 1, exp: "Es una zona donde el cambio de la entrada no provoca ninguna reacción en la salida." },
    { u: "SMYR T6", q: "¿Cuál es el primer paso recomendado para el correcto calibrado de un equipo analógico?", opts: ["Realizar un ajuste preciso de la curva de linealidad a lo largo de todo su recorrido útil.", "Aplicar el ajuste cero del sensor proporcionando una señal de entrada equivalente a ese nivel.", "Girar el potenciómetro de ajuste de span hasta alcanzar el tope máximo permitido por el fabricante.", "Limpiar exhaustivamente la placa de circuitos y la carcasa exterior aplicando barniz dieléctrico."], ans: 1, exp: "Siempre se ajusta primero el cero (punto más bajo) antes de ajustar la pendiente o span." },
    { u: "SMYR T6", q: "¿En qué consiste el ajuste SPAN del sensor?", opts: ["En medir con un polímetro de alta precisión la resistencia óhmica total del cableado instalado.", "En suministrar la señal de entrada exacta que corresponda con el tope de la escala.", "En calcular matemáticamente el error final dividiendo la desviación entre la ganancia del lazo.", "En reajustar los parámetros del controlador disminuyendo progresivamente el tiempo derivativo."], ans: 1, exp: "Fija el tope máximo (ej. asegurar que al máximo de presión entregue el valor máximo eléctrico)." },
    { u: "SMYR T6", q: "¿Cuándo se debe realizar el ajuste de LINEALIDAD?", opts: ["De forma obligatoria y estricta como el primer paso de cualquier procedimiento de calibración estándar.", "Siempre que el equipo lo permita inyectando una señal de entrada correspondiente al valor medio del rango.", "Única y exclusivamente en aquellas aplicaciones donde se implemente un control en lazo abierto.", "En aquellos casos especiales donde el error registrado en el punto cero es superior al error de fondo."], ans: 1, exp: "Ajusta la 'barriga' de la curva para que sea lo más recta posible, fijando el punto medio." },
    { u: "SMYR T6", q: "¿Qué tipo de error ocurre cuando la curva real de medida está desplazada paralelamente respecto a la ideal?", opts: ["Error de span.", "Error de cero.", "Error de histéresis.", "Error de resolución."], ans: 1, exp: "El error de cero desplaza toda la curva hacia arriba o hacia abajo en la misma proporción." },
    { u: "SMYR T6", q: "¿Qué caracteriza al Error de Span?", opts: ["El valor inicial marca bien pero la pendiente de la curva real difiere de la ideal.", "La representación gráfica de las medidas tomadas muestra un desplazamiento fijo y constante hacia arriba.", "El elemento primario de captación no es capaz de responder frente a las pequeñas variaciones de la planta.", "La señal de salida se mantiene estancada en cero independientemente de los estímulos de la entrada."], ans: 0, exp: "Empieza bien en cero, pero al ir subiendo se desvía cada vez más por tener distinta pendiente." },
    { u: "SMYR T6", q: "¿Qué es el Error de no linealidad?", opts: ["Ocurre únicamente en transmisiones donde la información viaja codificada en formato puramente digital.", "Cuando la relación entre entrada y salida forma una curva respecto a la línea ideal.", "Aparece justo en el instante en el que el registro de memoria del autómata programable alcanza la saturación.", "Se produce en entornos industriales severos donde hay una elevada presencia de ruidos electromagnéticos."], ans: 1, exp: "La respuesta del sensor hace 'barriga' separándose de la línea recta ideal." },
    { u: "SMYR T6", q: "¿Cómo se define el Error de histéresis?", opts: ["Como la diferencia de valor que da el equipo según si la medición se alcanza por una vía ascendente o descendente.", "Como el bloqueo repentino de los cálculos internos debido al sobrecalentamiento del chip principal.", "Como la condición de inestabilidad absoluta que lleva al proceso a oscilar de manera incontrolable.", "Como el periodo de tiempo muerto o de retardo inherente que transcurre antes de notar los primeros cambios."], ans: 0, exp: "La lectura no es la misma cuando vas subiendo la magnitud que cuando vas bajando." },
    { u: "SMYR T6", q: "En la puesta en servicio, ¿qué es lo primero que se debe hacer al recibir el material?", opts: ["Conectarlo inmediatamente a la red trifásica de 400 voltios para verificar si enciende el piloto indicador.", "Realizar una inspección visual en busca de posibles golpes o manipulaciones tras el viaje.", "Proceder de manera directa con el ajuste fino del potenciómetro para calibrar el valor del cero.", "Descargar mediante el cable de red el bloque de datos que contiene la configuración de parámetros del PID."], ans: 1, exp: "La revisión ocular previene accidentes si el equipo ha sufrido daños ocultos en el transporte." },
    { u: "SMYR T6", q: "¿Qué se debe comprobar específicamente tras el traslado de material con partes móviles?", opts: ["El logotipo y la marca troquelada del fabricante para comprobar que no se trata de una falsificación del equipo.", "La posición de las partes móviles así como la integridad de la estanqueidad de las diversas juntas.", "El código de colores estandarizado utilizado en las regletas de bornes de la caja de conexiones exterior.", "La estabilidad y el valor exacto de la frecuencia suministrada por la red eléctrica de baja tensión."], ans: 1, exp: "Las vibraciones del transporte pueden desajustar vástagos o romper sellos." },
    { u: "SMYR T6", q: "¿Qué acción se recomienda para proteger los bornes en ambientes corrosivos o tropicales?", opts: ["Dejarlos al aire.", "Aplicarles barniz protector.", "Envolverlos en papel.", "Usar cables más finos."], ans: 1, exp: "El barniz dieléctrico sella las conexiones contra la oxidación y la humedad." },
    { u: "SMYR T6", q: "¿Qué es el Ensayo en vacío?", opts: ["Probar la instalación completa asegurándose primero de que no exista aire comprimido dentro de las tuberías.", "Alimentar únicamente el circuito de mando y control para testear la respuesta lógica del programa informático.", "Hacer funcionar el motor de accionamiento principal a su máxima potencia durante al menos quince minutos.", "Vaciar por completo el tanque de agua de la instalación abriendo todas las válvulas de purga inferiores."], ans: 1, exp: "Consiste en dar tensión solo a la electrónica para probar el programa sin peligro de mover máquinas." },
    { u: "SMYR T6", q: "¿Qué se verifica durante el Ensayo en carga?", opts: ["La continuidad e integridad de todos los cables que forman parte del circuito de protección de tierra.", "Se suministra potencia a los receptores para validar el comportamiento general bajo condiciones reales.", "Las condiciones de orden y limpieza del entorno de trabajo antes de realizar la entrega final de la obra.", "La correcta redacción técnica y las traducciones disponibles en el manual de instrucciones del usuario."], ans: 1, exp: "Es la prueba de fuego donde se da tensión de potencia a motores y actuadores." },
    { u: "SMYR T6", q: "En un ensayo en carga, ¿por qué elemento se recomienda sustituir temporalmente detectores críticos para pruebas?", opts: ["Por conjuntos de resistencias disipadoras de alta potencia montadas en paralelo.", "Por elementos como pulsadores manuales que permiten testear la lógica de manera segura.", "Por puentes de cable de cobre fijos instalados directamente sobre la regleta de conexiones.", "Por avanzados sensores ópticos de tecnología láser que ofrecen un tiempo de respuesta inmediato."], ans: 1, exp: "Sustituir los sensores por pulsadores manuales permite simular eventos a voluntad de forma segura." },
    { u: "SMYR T6", q: "¿Qué modelo de presostato se utiliza como ejemplo práctico en la Unidad 6?", opts: ["Siemens LOGO.", "SMC ISE30A.", "Omron E5CC.", "Schneider Altivar."], ans: 1, exp: "El manual detalla los códigos de configuración del presostato ISE30A de la marca SMC." },
    { u: "SMYR T6", q: "¿Qué botón se usa en el presostato ISE30A para la selección de opciones?", opts: ["Botón direccional de flecha superior", "Botón direccional de flecha inferior", "Botón central de confirmación y ajuste", "Pulsador de reinicio forzado a valores de fábrica"], ans: 2, exp: "El botón S o Set se utiliza para aceptar valores y navegar menús." },
    { u: "SMYR T6", q: "¿Cuánto tiempo se debe pulsar el botón S para acceder al menú de funciones?", opts: ["10 segundos.", "2 segundos.", "Solo un clic rápido.", "No hace falta pulsar, es automático."], ans: 1, exp: "Mantener 2 segundos abre el menú de configuración avanzada." },
    { u: "SMYR T6", q: "¿Qué función del ISE30A corresponde a la configuración de Autoajuste?", opts: ["FO.", "F3.", "F5.", "F9."], ans: 2, exp: "La función F5 permite que el sensor mida y memorice un umbral automáticamente." },
    { u: "SMYR T6", q: "¿Qué permite la función de autoajuste en el presostato?", opts: ["Modificar la paleta de colores del display para mejorar la legibilidad bajo luz intensa.", "Registrar y establecer de forma autónoma el valor de consigna tomando como base la medición actual.", "Activar el relé de corte general para apagar el equipo ante un inminente riesgo de sobrepresión.", "Habilitar el canal secundario de lectura para medir de manera continua la humedad del ambiente."], ans: 1, exp: "Facilita la calibración in situ al grabar la presión actual como referencia operativa." },
    { u: "SMYR T6", q: "¿Qué indica el código F0 en el menú del presostato ISE30A?", opts: ["Una alarma técnica bloqueante que indica un fallo grave de hardware en el interior del dispositivo.", "El parámetro que permite elegir la unidad de medida que se mostrará por la pantalla principal.", "El submenú dedicado en exclusiva a la calibración avanzada de la rampa de linealidad del sensor.", "La marca de finalización de ciclo que indica que el programa de control ha terminado su ejecución."], ans: 1, exp: "Permite cambiar la unidad de presión que se muestra en la pantalla." },
    { u: "SMYR T6", q: "¿Qué ajuste realiza la función F3?", opts: ["Ajuste del tiempo de respuesta.", "Ajuste del brillo.", "Ajuste del cero.", "Ajuste del PID."], ans: 0, exp: "F3 permite introducir un retardo para evitar que el presostato reaccione a picos falsos." },
    { u: "SMYR T6", q: "En el ejemplo del depósito de agua, ¿por qué se sustituye el sistema manual clásico?", opts: ["Por una robusta válvula de compuerta accionada por un volante giratorio manual.", "Por un transmisor avanzado que proporciona una señal eléctrica de salida de tipo proporcional.", "Por una sonda termométrica compuesta por dos metales distintos unidos por un extremo.", "Por un simple mecanismo de interruptor eléctrico que se enciende o apaga al detectar la presencia."], ans: 1, exp: "Los sensores analógicos modernos envían una lectura de nivel continua." },
    { u: "SMYR T6", q: "¿Qué componente sustituye al Operario en la modernización del sistema de nivel?", opts: ["Un preciso distanciómetro basado en la emisión y rebote de un haz de luz láser enfocado.", "Un autómata programable industrial equipado con tarjetas de lectura y escritura analógicas.", "Una bomba de achique accionada mediante una manivela para vaciar el tanque manualmente.", "Un cronómetro digital sincronizado diseñado para registrar los tiempos de llenado y vaciado."], ans: 1, exp: "El PLC asume la labor de observar el nivel y decidir cuánto abrir la válvula." },
    { u: "SMYR T6", q: "¿Qué cambio se realiza en la válvula para automatizar el proceso de nivel?", opts: ["Se elimina completamente del circuito para permitir que el fluido circule sin ningún tipo de restricción.", "Se reemplaza por una electroválvula proporcional equipada con un actuador neumático o eléctrico motorizado.", "Se sustituye por un tramo recto de tubería con una sección interior notablemente más amplia.", "Se pinta toda su superficie exterior de color rojo brillante para cumplir con las normativas contra incendios."], ans: 1, exp: "Se instala una válvula proporcional controlada eléctricamente." },
    { u: "SMYR T6", q: "En el diagrama P e I del ejemplo, ¿qué significan las siglas LT?", opts: ["Circuito cerrado de lazo de tensión diferencial.", "Elemento transmisor encargado de medir el nivel.", "Valor máximo fijado como límite de tiempo.", "Transformador de adaptación de impedancia de línea."], ans: 1, exp: "La L de Level y la T de Transmitter definen el sensor de nivel analógico." },
    { u: "SMYR T6", q: "¿Qué representa la etiqueta LCV en el diagrama de instrumentación?", opts: ["Dispositivo lector para la medición del caudal volumétrico.", "Válvula automatizada que se ocupa del control de nivel.", "Punto máximo establecido para el límite de carga variable.", "Configuración electrónica del lazo de corriente de vacío."], ans: 1, exp: "La V al final indica que es una Válvula." },
    { u: "SMYR T6", q: "¿Qué es un Transformador de tensión?", opts: ["Un equipo resistivo diseñado específicamente para generar calor en cuadros eléctricos fríos.", "Un transformador empleado para adaptar voltajes altos y mandar la señal a equipos de medida y protección.", "Un pequeño motor de corriente continua utilizado en mecanismos de servocontrol de baja potencia.", "Una gran bobina resistiva de carga dispuesta para absorber los picos de intensidad durante los arranques."], ans: 1, exp: "Aíslan y reducen el voltaje alto para poder medirlo de forma segura." },
    { u: "SMYR T6", q: "¿Cuál es el ajuste por defecto de la resolución del display en el ISE30A?", opts: ["10 líneas.", "1000 líneas.", "500 líneas.", "Infinito."], ans: 1, exp: "Viene configurado de fábrica para mostrar una resolución de 1000 pasos en pantalla." },
    { u: "SMYR T6", q: "Para desplazarse por el menú del presostato, se utilizan los botones:", opts: ["Se aprieta exclusivamente la tecla de selección central.", "Se hace uso constante de las teclas de dirección arriba y abajo.", "Se requiere enchufar una matriz de teclado numérico auxiliar.", "El sistema moderno opera mediante reconocimiento de voz."], ans: 1, exp: "Las flechas Arriba y Abajo permiten cambiar valores y opciones dentro del menú." },
    { u: "SMYR T6", q: "¿Qué indica un valor de F6 en el presostato ISE30A?", opts: ["Ajuste del cero.", "Ajuste preciso del valor de visualización.", "Reset de fábrica.", "Error de sensor."], ans: 1, exp: "Sirve para calibrar y compensar pequeñas desviaciones de la pantalla frente a un manómetro patrón." },
    { u: "SMYR T6", q: "¿A qué se refiere el término Calibración según los conceptos fundamentales?", opts: ["Al procedimiento regular de mantenimiento que exige desengrasar y limpiar la superficie del sensor.", "A la corrección matemática y mecánica que alinea las salidas del equipo con la magnitud física real.", "A la tarea periódica recomendada de sustituir los bancos de baterías que alimentan el instrumento.", "A la revisión obligatoria de las especificaciones detalladas que proporciona el manual de instrucciones."], ans: 1, exp: "Equiparar la lectura del equipo con la realidad." },
    { u: "SMYR T6", q: "¿Qué es el Error de medida?", opts: ["El coste económico de amortización asociado a la vida útil que le queda al dispositivo sensor.", "La discrepancia numérica que surge al restar el valor que lee el equipo del valor verdadero de la magnitud.", "La acumulación de milisegundos de retraso en los ciclos de barrido que ejecuta el autómata programable.", "Las alteraciones en la lectura provocadas de forma exclusiva por la acumulación de lodos en la tubería."], ans: 1, exp: "Es la desviación respecto a la lectura que daría un patrón perfecto." },
    { u: "SMYR T6", q: "¿Qué significa que un equipo tenga un alcance de cero a diez bares?", opts: ["Que la diferencia calculada entre el límite máximo y el límite mínimo de su escala es de diez unidades.", "Que el instrumento viene configurado de fábrica para mostrar las presiones exclusivamente en esa unidad.", "Que el fabricante asume una tolerancia máxima de fallo garantizado de diez bares en toda su curva.", "Que el bloque metálico principal del sensor cuenta con un peso aproximado de diez kilogramos en vacío."], ans: 0, exp: "El alcance se calcula restando el mínimo al máximo." },
    { u: "SMYR T6", q: "En sensores digitales, ¿qué es lo único que suele ajustarse en la puesta en marcha?", opts: ["El pequeño tornillo físico ubicado en la parte trasera que calibra el potenciómetro de cero.", "Los umbrales y rangos digitales de disparo para los que el usuario desea activar las salidas.", "El valor óhmico de la resistencia interna de polarización instalada en la placa electrónica.", "El enfoque de los espejos y de la lente convergente del cabezal láser mediante herramientas ópticas."], ans: 1, exp: "Se ajustan los umbrales o setpoints desde el teclado digital." },
    { u: "SMYR T6", q: "Durante la inspección visual tras la instalación, ¿qué se debe comprobar de los prensaestopas?", opts: ["La tonalidad cromática elegida para comprobar que armoniza con el color del armario.", "Que las tuercas de compresión abracen fuertemente la cubierta del cable para inmovilizarlo.", "El material de fabricación para certificar que están elaborados con polímeros termoplásticos.", "El peso de los racores para evitar someter la caja de derivación a un exceso de carga mecánica."], ans: 1, exp: "Los prensaestopas deben apretar el cable firmemente para garantizar el aislamiento IP." },
    { u: "SMYR T6", q: "¿Qué se verifica respecto a la sección de cables en la inspección visual?", opts: ["Que se hayan dejado bobinas de cable con varios metros de holgura de sobra.", "Que el diámetro transversal del conductor se corresponda exactamente con lo calculado en el plano eléctrico.", "Que los mazos de cables estén unificados utilizando una única tonalidad a lo largo de las canaletas.", "Que el revestimiento de los conductores no presente olores a sobrecalentamiento ni quemaduras."], ans: 1, exp: "La sección de hilo conductor debe coincidir con el diseño eléctrico." },
    { u: "SMYR T6", q: "En el ensayo en vacío, ¿qué se controla desde el software del controlador?", opts: ["La curva de subida de la presión del circuito hidráulico principal al arrancar las grandes bombas.", "La operatividad del circuito de mando incluyendo las secuencias lógicas y temporizaciones del software.", "Las revoluciones por minuto a las que gira el motor que acciona el gran ventilador de extracción.", "La intensidad del sistema de iluminación halógena para asegurar una buena visibilidad de la planta."], ans: 1, exp: "Se verifica la lógica de control, los PIDs y las alarmas de software." },
    { u: "SMYR T6", q: "¿Cuál es el fluido aplicable para el presostato ISE20 mencionado en las diapositivas?", opts: ["Fluidos acuosos que presentan un alto índice de alcalinidad o acidez corrosiva.", "Aire comprimido estándar y mezclas de gases que no sean corrosivos ni inflamables.", "Aceites lubricantes y fluidos oleohidráulicos presurizados de maquinaria pesada.", "Vapor de agua recalentado que alcance temperaturas por encima de los trescientos grados."], ans: 1, exp: "Este tipo de sensores digitales de presión están diseñados específicamente para neumática seca." },
    { u: "SMYR T6", q: "¿Qué unidad mínima de visualización tiene el modelo ISE20 para presión positiva?", opts: ["1 bar.", "0.001 MPa.", "100 kPa.", "0.5 bar."], ans: 1, exp: "Muestra la presión con tres decimales en Megapascales." },
    { u: "SMYR T6", q: "¿Cuál es la presión de prueba máxima para el modelo ISE20?", opts: ["100 kPa.", "1.5 MPa.", "10 bar.", "500 kPa."], ans: 1, exp: "Soporta una sobrepresión importante de hasta un megapascal y medio sin romperse." },
    { u: "SMYR T6", q: "¿Qué representa la Especificación de un sistema?", opts: ["El compendio de deseos y expectativas no escritas que transmite el cliente durante las reuniones previas.", "El conjunto de características técnicas y los límites de operación garantizados bajo la firma del fabricante.", "El volumen impreso que contiene el calendario de mantenimientos preventivos dictado por el servicio técnico.", "El documento administrativo donde se recogen los costes detallados de adquisición de cada pieza del equipo."], ans: 1, exp: "La hoja de especificaciones marca las capacidades y fronteras del dispositivo." },
    { u: "SMYR T6", q: "Si un sistema de nivel usa una palanca con un operario, se considera un sistema:", opts: ["Un circuito regulado de manera totalmente automática gracias al cierre del lazo informático.", "Un control en lazo cerrado donde el ser humano cierra el ciclo actuando físicamente como el controlador.", "Un simple montaje de lazo abierto en el que las acciones no dependen de la medición del nivel real.", "Un entorno de regulación avanzado basado exclusivamente en el uso de microprocesadores digitales."], ans: 1, exp: "El ser humano mira el agua y mueve la palanca, formando un lazo de control cerrado biológico." },
    { u: "SMYR T6", q: "¿Qué significa LS en un diagrama de nivel?", opts: ["Terminal de conexión para el lazo de salida de datos.", "Componente electromecánico que actúa como interruptor de nivel.", "Valor máximo configurado como límite de seguridad estricta.", "Cable trenzado empleado exclusivamente como línea de señal."], ans: 1, exp: "La S indica que funciona como un interruptor todo o nada, por ejemplo una boya." },
    { u: "SMYR T7", q: "¿Cómo se denomina el mantenimiento que consiste en reparar fallos detectados sin una programación previa?", opts: ["Mantenimiento preventivo.", "Mantenimiento correctivo.", "Mantenimiento predictivo.", "Mantenimiento reactivo manual."], ans: 1, exp: "El mantenimiento correctivo reacciona ante un fallo ya producido, sin planificación previa para evitarlo." },
    { u: "SMYR T7", q: "¿Qué técnica de mantenimiento busca planificar acciones para alargar la vida útil de los equipos mediante el estudio de procesos?", opts: ["Mantenimiento correctivo.", "Mantenimiento de emergencia.", "Mantenimiento preventivo.", "Mantenimiento fortuito."], ans: 2, exp: "El mantenimiento preventivo se programa y planifica para realizar tareas (como lubricación o limpieza) que alargan la vida útil del equipo." },
    { u: "SMYR T7", q: "¿En qué consiste el mantenimiento predictivo?", opts: ["En reparar piezas cuando se rompen definitivamente.", "En sustituir los componentes por sistema cada seis meses.", "En usar datos del proceso para predecir fallos.", "En ignorar las alarmas si el sistema sigue activo."], ans: 2, exp: "El predictivo usa datos (vibraciones, temperatura, etc.) para predecir el fallo antes de que suceda." },
    { u: "SMYR T7", q: "¿Qué software es el más utilizado para la gestión de mantenimiento industrial mencionado en el temario?", opts: ["TIA Portal.", "Módulo SAP PM.", "AutoCAD Industrial.", "Hojas de Microsoft Excel."], ans: 1, exp: "El módulo PM (Plant Maintenance) de SAP es el estándar industrial para la Gestión del Mantenimiento Asistida por Ordenador." },
    { u: "SMYR T7", q: "¿Cuál es el primer paso en el procedimiento para diagnosticar y localizar averías?", opts: ["Aislar el fallo rápidamente.", "Observación y detección de anomalías.", "Solucionar el problema detectado.", "Cambiar las tarjetas de salida del PLC."], ans: 1, exp: "Antes de tocar nada, siempre se debe observar el sistema para detectar síntomas, ruidos, luces u olores inusuales." },
    { u: "SMYR T7", q: "¿Cuál es el orden correcto del protocolo de actuación ante una avería?", opts: ["Solucionar -> Aislar -> Localizar -> Observar.", "Observar -> Localizar -> Aislar -> Solucionar.", "Localizar -> Observar -> Solucionar -> Aislar.", "Aislar -> Observar -> Localizar -> Solucionar."], ans: 1, exp: "La secuencia lógica es: observar los síntomas, localizar la fuente del problema, aislarla por seguridad y finalmente solucionarla." },
    { u: "SMYR T7", q: "¿Qué se debe hacer una vez localizado el problema en un sistema automatizado?", opts: ["Reiniciar el PLC inmediatamente.", "Aislar el fallo para trabajar con seguridad.", "Ignorar el fallo si no detiene la máquina.", "Llamar al fabricante sin revisar el equipo."], ans: 1, exp: "Aislar el fallo garantiza que no haya daños colaterales y permite a los técnicos intervenir sin riesgo eléctrico o mecánico." },
    { u: "SMYR T7", q: "¿Cuál es un sistema reactivo automático de seguridad ante disfunciones?", opts: ["Un sensor que detiene la máquina ante anomalías.", "El botón general de encendido del cuadro.", "El informe diario de incidencias del turno.", "El protocolo de limpieza de los bornes eléctricos."], ans: 0, exp: "Es una medida automática donde la propia máquina reacciona parando su ciclo si detecta peligro." },
    { u: "SMYR T7", q: "¿Qué dispositivo se utiliza comúnmente para el apagado manual de emergencia?", opts: ["Un pequeño interruptor de palanca.", "Un pulsador de emergencia tipo seta.", "Un teclado matricial numérico.", "Un sensor óptico de proximidad."], ans: 1, exp: "La 'seta' de emergencia es un botón grande y muy visible, fácil de golpear en caso de necesidad." },
    { u: "SMYR T7", q: "¿Qué significa la redundancia de sistemas en un plan de actuación?", opts: ["Eliminar directamente los sistemas que sobran.", "Duplicar componentes para seguir operando ante fallos.", "Utilizar cableado más corto en las conexiones.", "Realizar intervenciones solo en horario nocturno."], ans: 1, exp: "La redundancia es tener equipos de respaldo listos para entrar en acción si falla el equipo principal." },
    { u: "SMYR T7", q: "¿Dónde se localizan con mayor frecuencia las averías en un sistema automatizado?", opts: ["En el interior de la CPU del PLC.", "En la periferia de sensores y actuadores.", "En los módulos de software de gestión.", "En los sistemas de iluminación del cuadro."], ans: 1, exp: "El 80-90% de los fallos ocurren en la periferia debido al desgaste mecánico, golpes o cables rotos." },
    { u: "SMYR T7", q: "¿Cuál es una causa habitual de fallos en la periferia?", opts: ["El desgaste mecánico o rotura de cables.", "Los fallos de la red Ethernet interna.", "Las interferencias por herramientas manuales.", "La falta de refrigeración del cuadro."], ans: 0, exp: "Los componentes a pie de máquina sufren desgastes y acumulan suciedad." },
    { u: "SMYR T7", q: "¿Por qué es fundamental revisar las conexiones a tierra ante una avería?", opts: ["Porque evita que entre polvo al interior del PLC.", "Porque drena las interferencias electromagnéticas.", "Porque mejora el rendimiento del procesador.", "Porque reduce el consumo energético general."], ans: 1, exp: "La tierra drena el ruido eléctrico. Si falla, las interferencias alteran el PLC." },
    { u: "SMYR T7", q: "¿Qué técnica se recomienda para mejorar la conexión a tierra en suelos muy secos?", opts: ["Sustituir el conductor por uno de aluminio.", "Humedecer la conexión con agua salina.", "Utilizar exclusivamente cables con funda plástica.", "Desconectar la toma temporalmente."], ans: 1, exp: "El agua salina mejora la conductividad del terreno y reduce la resistencia." },
    { u: "SMYR T7", q: "¿Qué problema pueden causar los motores y variadores de frecuencia en la alimentación eléctrica?", opts: ["Aumentar el calor en el ambiente de trabajo.", "Introducir ruidos y armónicos en la red.", "Incrementar la presión de las tuberías.", "Desconfigurar los parámetros del PLC."], ans: 1, exp: "La conmutación rápida inyecta armónicos destructivos a la red eléctrica." },
    { u: "SMYR T7", q: "¿Qué efecto tiene una alta temperatura en el interior de un armario eléctrico?", opts: ["Mejora la velocidad de respuesta del sistema.", "Provoca bloqueos y fallos electrónicos aleatorios.", "Elimina totalmente el riesgo de condensación.", "No tiene efectos sobre equipos industriales."], ans: 1, exp: "El exceso de calor hace que las fuentes y los PLC se sobrecalienten y se cuelguen." },
    { u: "SMYR T7", q: "¿Qué fallo es el más común dentro de un autómata programable?", opts: ["El quemado completo de la placa base.", "Fallos en tarjetas de entrada y salida por sobretensión.", "La pérdida de memoria del programa.", "El desgaste físico de los conectores frontales."], ans: 1, exp: "La CPU rara vez falla, el daño suele concentrarse en los bornes E/S por culpa de cortocircuitos de planta." },
    { u: "SMYR T7", q: "¿Cómo puede afectar un daño en el cable de comunicación a la instalación?", opts: ["Afecta únicamente a las balizas luminosas.", "Causa paradas o errores de comunicación intermitentes.", "Disminuye la velocidad de procesamiento.", "Incrementa la seguridad de los operarios."], ans: 1, exp: "Un bus cortado aísla por completo a la red de autómatas, deteniendo la producción." },
    { u: "SMYR T7", q: "¿Cuál es el protocolo de comunicación de más rápido crecimiento en la industria actual?", opts: ["Las redes Modbus serie.", "Los buses Ethernet industrial.", "Los circuitos lógicos neumáticos.", "Los enlaces analógicos directos."], ans: 1, exp: "Las redes basadas en Ethernet (Profinet, EtherCAT) dominan debido a su gran velocidad." },
    { u: "SMYR T7", q: "Ante una avería intermitente, ¿qué factor ambiental deberíamos verificar además de la temperatura?", opts: ["Los niveles de ruido acústico ambiental.", "La humedad relativa por posibles condensaciones.", "La presión atmosférica del recinto cerrado.", "La radiación ultravioleta de las lámparas."], ans: 1, exp: "La condensación dentro de los cuadros eléctricos crea cortos pasajeros que provocan averías difíciles de detectar." },
    { u: "SMYR T7", q: "¿Qué instrumento es esencial para un técnico de automatización para medir magnitudes eléctricas?", opts: ["El analizador de redes avanzado.", "El polímetro o multímetro.", "La pinza de corriente continua.", "El osciloscopio portátil digital."], ans: 1, exp: "El multímetro es la herramienta universal para medir Voltajes, Amperios y Ohmios." },
    { u: "SMYR T7", q: "Al medir tensión en Corriente Alterna, ¿cómo se deben colocar las puntas de prueba?", opts: ["En configuración serie con la carga.", "En paralelo con los puntos a medir.", "Con una punta en fase y otra desconectada.", "Interrumpiendo el paso de los electrones."], ans: 1, exp: "La tensión o diferencia de potencial siempre se mide en configuración de paralelo." },
    { u: "SMYR T7", q: "¿Qué precaución es vital al medir tensión en Corriente Continua?", opts: ["Colocar las puntas en cualquier posición libre.", "Identificar y respetar la polaridad correcta.", "Usar protección dieléctrica extra.", "Desconectar previamente la alimentación general."], ans: 1, exp: "Identificar correctamente el positivo y negativo es fundamental en circuitos de 24V de automatización." },
    { u: "SMYR T7", q: "¿Cómo se debe conectar el multímetro para medir intensidad de forma tradicional?", opts: ["En paralelo a la carga principal.", "En serie abriendo el circuito físico.", "Midiendo los dos extremos del componente.", "Con la máquina totalmente apagada."], ans: 1, exp: "El polímetro debe intercalarse en el circuito para que los electrones fluyan a través de él." },
    { u: "SMYR T7", q: "¿Qué ventaja ofrece una pinza amperimétrica para medir intensidad en alterna?", opts: ["Mide la caída de tensión en resistencias.", "Mide por inducción sin abrir el circuito.", "Mide potencias aparentes y reactivas.", "Es más precisa que un multímetro en serie."], ans: 1, exp: "Permite medir cientos de amperios abrazando el cable con la mordaza, sin desconectarlo." },
    { u: "SMYR T7", q: "En un motor trifásico equilibrado, ¿cuál debe ser la suma de la intensidad de las tres fases medida con una pinza?", opts: ["La corriente nominal del motor.", "Cero amperios al medir las tres juntas.", "La suma directa de las tres fases.", "Un valor cercano al infinito."], ans: 1, exp: "Por la Ley de Kirchhoff, la suma vectorial de las tres corrientes de un sistema equilibrado es cero." },
    { u: "SMYR T7", q: "¿Qué nos indica una medida de resistencia muy alta en un cable que debería estar conectado?", opts: ["Que el conductor está en perfecto estado.", "Que existe un corte o contacto abierto.", "Que la intensidad circulante es muy alta.", "Que el equipo de medida requiere calibración."], ans: 1, exp: "Open Loop o infinito indica que el circuito está físicamente cortado." },
    { u: "SMYR T7", q: "¿Bajo qué condición se debe realizar siempre la medida de continuidad?", opts: ["Con el motor a máxima carga nominal.", "En ausencia total de tensión eléctrica.", "Mientras se activa el interruptor general.", "Con el sistema en modo de diagnóstico."], ans: 1, exp: "Medir resistencia o continuidad en un circuito con tensión quemará el fusible interno del tester." },
    { u: "SMYR T7", q: "¿Qué símbolo representa la medida de resistencia en un multímetro?", opts: ["La letra V.", "La letra A.", "El símbolo Omega.", "Las siglas Hz."], ans: 2, exp: "La letra griega Omega es el símbolo universal para los Ohmios." },
    { u: "SMYR T7", q: "¿Qué es un fallo en la periferia?", opts: ["Errores en el código de programación central.", "Averías en sensores o actuadores externos.", "Manipulaciones indebidas por parte del operario.", "Fugas en los sistemas neumáticos principales."], ans: 1, exp: "Cualquier elemento de campo fuera del cuadro eléctrico central forma parte de la periferia." },
    { u: "SMYR T7", q: "¿Qué se debe incluir siempre en un Plan Anual de Mantenimiento?", opts: ["El listado de técnicos de la planta.", "Las tareas preventivas y registros correctivos.", "Los planos eléctricos actualizados del cuadro.", "El stock de repuestos del almacén principal."], ans: 1, exp: "Permite ordenar las revisiones y auditar el historial de lo que se ha ido rompiendo." },
    { u: "SMYR T7", q: "En el diagnóstico de averías, ¿qué significa aislar el fallo?", opts: ["Cubrir las partes vivas con material aislante.", "Separar físicamente el componente defectuoso.", "Trasladar el equipo a la zona de taller.", "Bloquear el acceso general al área de trabajo."], ans: 1, exp: "Desconectarlo evita averías en cadena, por ejemplo, aislar un motor cortocircuitado." },
    { u: "SMYR T7", q: "¿Qué riesgo principal existe al medir intensidad en serie si se sobrepasa el límite del multímetro?", opts: ["Fundir el fusible de protección interno.", "Provocar la caída del diferencial de planta.", "Invertir el giro del motor bajo prueba.", "Dañar irreversiblemente los cables de prueba."], ans: 0, exp: "Si tratas de medir 15A en la toma de 10A, fundirás inmediatamente el fusible de cristal interno." },
    { u: "SMYR T7", q: "¿Qué puede indicar un desequilibrio de intensidades entre las fases de un motor trifásico?", opts: ["Un excelente estado de las bobinas interiores.", "Un problema en la marcha o en los devanados.", "Una sobretensión temporal en la red general.", "El correcto equilibrado del consumo eléctrico."], ans: 1, exp: "Un motor sin averías consume la misma intensidad en las 3 fases. El desequilibrio augura avería." },
    { u: "SMYR T7", q: "Muchos multímetros incorporan un avisador acústico para la función de:", opts: ["La medición de altos voltajes continuos.", "Comprobar la continuidad del circuito.", "La detección automática de armónicos de red.", "El aviso de fin de rango de medida analógica."], ans: 1, exp: "El pitido confirma que el cable está íntegro sin tener que mirar la pantalla." },
    { u: "SMYR T7", q: "¿Qué factor puede causar una mala maniobra en una planta industrial?", opts: ["Errores lógicos del operario en control manual.", "El exceso de condensación en el armario eléctrico.", "Desgastes prematuros en rodamientos mecánicos.", "La presencia constante de corrientes parasitarias."], ans: 0, exp: "Son errores humanos u operacionales que producen bloqueos de maquinaria." },
    { u: "SMYR T7", q: "¿Cuál es la función del módulo SAP PM?", opts: ["Auditar el consumo energético de la planta.", "Gestionar órdenes de mantenimiento general.", "Simular procesos industriales críticos en 3D.", "Supervisar la asistencia de los empleados locales."], ans: 1, exp: "El módulo Plant Maintenance organiza integralmente las tareas del departamento." },
    { u: "SMYR T7", q: "Un sistema que tiene componentes duplicados para activarse si el principal falla es:", opts: ["Un sistema redundante.", "Un sistema secuencial.", "Un circuito oscilante.", "Una configuración en anillo."], ans: 0, exp: "La redundancia garantiza alta disponibilidad ante fallos, como por ejemplo tener bombas de agua gemelas." },
    { u: "SMYR T7", q: "¿Qué se recomienda usar para testear funciones automáticas de forma segura durante una prueba?", opts: ["Puentes directos sobre las regletas de bornes.", "Pulsadores manuales provisionales de prueba.", "Conexiones forzadas desde el software central.", "Anulación temporal de las protecciones térmicas."], ans: 1, exp: "Un pulsador en mano permite al técnico ordenar un stop inmediatamente si algo sale mal." },
    { u: "SMYR T7", q: "¿A qué tipo de mantenimiento pertenece la sustitución de un rodamiento cada 2000 horas de uso por recomendación del fabricante?", opts: ["Intervención de emergencia.", "Mantenimiento preventivo.", "Reparación tras avería técnica.", "Diagnóstico predictivo de fallos."], ans: 1, exp: "Al sustituirlo por el tiempo transcurrido, antes de que falle, es mantenimiento preventivo puro." },
    { u: "SMYR T7", q: "¿Qué indica un pitido constante en la prueba de continuidad de un fusible?", opts: ["Que el elemento de protección ha saltado.", "Que se encuentra en buen estado conductor.", "Que hay un voltaje peligroso presente.", "Que el rango de medición seleccionado es incorrecto."], ans: 1, exp: "Un fusible funcional es un trozo de cable, por lo que pitará al dar casi 0 Ohmios." },
    { u: "SMYR T7", q: "¿Qué causa suele producir un fallo total de la CPU de un PLC?", opts: ["La acumulación de polvo superficial en la carcasa.", "Picos de tensión graves o cortocircuitos.", "Errores continuos en la programación lógica.", "El uso prolongado sin reinicios del sistema."], ans: 1, exp: "Los rayos o picos no filtrados de la red queman instantáneamente la microelectrónica de la CPU." },
    { u: "SMYR T7", q: "Ante un problema de interferencias en una señal analógica, ¿qué deberíamos revisar primero?", opts: ["La longitud total del cableado instalado.", "El apantallamiento y su conexión a tierra.", "La marca específica del transductor de señal.", "El nivel de tensión de la fuente principal."], ans: 1, exp: "La malla de cobre del cable drena a tierra todo el ruido externo." },
    { u: "SMYR T7", q: "El informe de incidencias es una herramienta fundamental del mantenimiento:", opts: ["Preventivo basado en inspección visual.", "Correctivo al registrar fallos y reparaciones.", "Predictivo para inventariar repuestos del taller.", "Programa estricto de mantenimiento anual."], ans: 1, exp: "Registrar las averías pasadas ahorra mucho tiempo cuando se vuelve a repetir el fallo en el futuro." },
    { u: "SMYR T7", q: "¿Qué ventaja tiene el uso de software de Gestión de Mantenimiento Asistida por Ordenador?", opts: ["Sustituir el trabajo de los especialistas en planta.", "Coordinar y digitalizar las intervenciones anuales.", "Eliminar el riesgo de paradas imprevistas futuras.", "Reducir masivamente los costes en piezas de recambio."], ans: 1, exp: "Digitaliza y estandariza los calendarios, manuales y repuestos de los técnicos." },
    { u: "SMYR T7", q: "En corriente continua, si conectamos las puntas del multímetro al revés:", opts: ["El aparato de medida sufrirá daños irreparables.", "Se mostrará un valor negativo en pantalla.", "El circuito bajo prueba se desconectará enseguida.", "El fusible interno de protección saltará inmediatamente."], ans: 1, exp: "Un multímetro digital simplemente invertirá el signo mostrándote que la polaridad está cruzada." },
    { u: "SMYR T7", q: "¿Qué componente se debe verificar si hay interrupciones en la alimentación eléctrica?", opts: ["El desgaste de los actuadores neumáticos finales.", "Malas conexiones en bornes o en fuentes.", "Los fallos en el sistema de iluminación local.", "Errores de comunicación en el bus de red de datos."], ans: 1, exp: "Los fallos de alimentación suelen derivar de conexiones flojas o fuentes de 24V defectuosas." },
    { u: "SMYR T7", q: "La observación de anomalías incluye detectar de forma temprana:", opts: ["Ruidos, olores extraños o vibraciones inusuales.", "El código de barras de los equipos instalados.", "La facturación eléctrica mensual de la planta.", "El desgaste físico de las herramientas manuales."], ans: 0, exp: "Debe hacerse uso de todos los sentidos humanos para intuir de dónde proviene la avería." },
    { u: "SMYR T7", q: "¿Qué sistema de actuación permite seguir trabajando aunque un sensor automático falle?", opts: ["La pulsación directa de la seta de parada de emergencia.", "El paso del sistema a un modo de funcionamiento manual.", "La desconexión general del seccionador principal de planta.", "La activación repetida de las alarmas sonoras de aviso."], ans: 1, exp: "Pasar la máquina a control manual permite al operario mover bombas y cintas mediante pulsadores, salvando la producción." },
    { u: "SMYR T7", q: "¿Cuál es el objetivo final del diagnóstico de averías?", opts: ["Identificar rápidamente a los responsables del incidente.", "Localizar y solucionar el fallo en el menor tiempo posible.", "Agotar las piezas defectuosas disponibles en el almacén.", "Elaborar complejos informes para la dirección técnica central."], ans: 1, exp: "El fin último del departamento es mantener la planta productiva la mayor cantidad de horas posibles." },
    { u: "SMYR T7", q: "El mantenimiento correctivo es, por definición, un mantenimiento:", opts: ["Completamente planificado e integrado en el calendario.", "No programado al reaccionar ante una rotura imprevista.", "Una revisión rutinaria según dictamine el fabricante.", "Una estrategia basada siempre en modelos matemáticos."], ans: 1, exp: "Es 'apagar fuegos', reparar la máquina que ya se ha roto de forma imprevista." },
    { u: "SMYR T7", q: "¿Qué medida se usa para comprobar si una bobina de un contactor está cortada?", opts: ["Midiendo el nivel de voltaje de entrada principal.", "Comprobando la resistencia interna en ohmios.", "Verificando el consumo amperimétrico general de la planta.", "Analizando cuidadosamente la frecuencia de conmutación."], ans: 1, exp: "Midiendo los Ohmios entre el borne A1 y A2 certificamos la salud interna de la bobina." },
    { u: "SMYR T7", q: "¿Cómo se debe medir la intensidad en un circuito de corriente alterna?", opts: ["En derivación con la carga instalada.", "En serie interrumpiendo el circuito.", "Abriendo completamente el panel general.", "Usando exclusivamente pinzas de tensión."], ans: 1, exp: "Con multímetros tradicionales, la intensidad siempre requiere colocar el aparato en serie dentro del circuito de corriente." },
    { u: "SMYR T7", q: "¿Cuál de las siguientes acciones deben aparecer en el plan de mantenimiento?", opts: ["Engrasado periódico de las cadenas dentadas de tracción.", "Informe detallado de averías tras paradas del sistema.", "Análisis termográfico predictivo sobre el cuadro eléctrico.", "Todas las respuestas mostradas anteriormente son correctas."], ans: 3, exp: "El plan es integral, por lo que alberga las pautas periódicas y sirve de archivo para los reportes de incidentes correctivos y predictivos." },
    { u: "SMYR T7", q: "¿Cuál de las siguientes fases de un mantenimiento correctivo debería suceder primero?", opts: ["La observación atenta y detección de cualquier anomalía.", "El aislamiento eléctrico seguro del equipo defectuoso.", "La sustitución inmediata del elemento dañado en la máquina.", "El reporte técnico detallado de la avería para los superiores."], ans: 0, exp: "El protocolo dicta que la observación debe ser siempre el primer contacto con la máquina averiada." },
    { u: "SMYR T7", q: "¿Cuál de los siguientes no es un fallo común en sistemas de medida y regulación?", opts: ["Desgastes progresivos en el cableado de la periferia exterior.", "Problemas intermitentes de sobretensión en la red eléctrica.", "Fallos de programación y calibración en componentes nuevos.", "Errores de comunicación derivados de las redes Ethernet internas."], ans: 2, exp: "Los componentes industriales salen comprobados de fábrica; los errores suelen radicar en el entorno físico, redes, picos eléctricos y montajes." },
    { u: "SMYR T7", q: "¿Cuál de los siguientes es un plan de actuación ante una disfunción de un sistema de medida y regulación?", opts: ["El apagado de seguridad automático activado por sensores.", "La caída manual y voluntaria del disyuntor principal de la sala.", "El rearme forzoso de todos los variadores de frecuencia instalados.", "La sustitución rápida de tarjetas de red sin aislamiento previo."], ans: 0, exp: "Los equipos modernos paran de forma segura y automatizada al detectar fallos, evitando el error humano." },
    { u: "SMYR T7", q: "¿Cuál de los siguientes no es un plan de actuación ante una disfunción de un sistema de medida y regulación?", opts: ["Apagar manualmente de forma controlada el sistema averiado.", "Pasar la máquina afectada directamente a control manual.", "Disponer de componentes redundantes de alta fiabilidad listos.", "Desconectar los equipos de medida y seguir con la producción."], ans: 3, exp: "Desconectar los sensores y continuar 'a ciegas' es una negligencia que puede ocasionar accidentes graves." },
    { u: "SMYR T7", q: "¿Cuál es el protocolo de comunicaciones más aplicado a nivel industrial en la actualidad?", opts: ["Los sistemas de comunicación Modbus RTU.", "Las redes basadas en el estándar Ethernet.", "El protocolo orientado a sensores de campo ASI.", "Las comunicaciones clásicas directas en serie."], ans: 1, exp: "Ethernet Industrial es actualmente la red líder mundial en automatización por su ancho de banda e interconexión IT." },
    { u: "SMYR T7", q: "¿Cuál es el tipo de mantenimiento por el cual se realizan una serie de tareas de manera periódica y programada?", opts: ["El mantenimiento rutinario general tras un incidente grave.", "El mantenimiento preventivo basado en calendarios estrictos.", "Las reparaciones correctivas urgentes solicitadas por operarios.", "La monitorización predictiva de datos de vibraciones mecánicas."], ans: 1, exp: "El Mantenimiento Preventivo establece rondas periódicas por tiempos o fechas para retrasar averías." },
    { u: "SMYR T7", q: "¿En qué consiste el mantenimiento predictivo?", opts: ["En recopilar datos del proceso productivo para prever fallos futuros.", "En contratar técnicos con gran experiencia visual sobre maquinaria.", "En reemplazar piezas sistemáticamente antes del fin de su vida útil.", "En reaccionar velozmente ante detenciones críticas del sistema."], ans: 0, exp: "Mide variables (ej. vibraciones) para aplicar modelos matemáticos y predecir cuándo se romperá la pieza." }, ,
    { u: "SMYR T7", q: "Si tenemos una avería común que ocurre siempre en la primera hora de trabajo de la máquina, y nos preparamos para reparar el equipo de manera rápida, se trata de un mantenimiento:", opts: ["Preventivo", "Correctivo", "Predictivo", "Repetitivo"], ans: 1, exp: "Aunque nos preparemos para actuar rápido, si estamos esperando a que se estropee el equipo es, por definición, correctivo." },
    { u: "SMYR T8", q: "¿Qué intensidad mínima ocasiona fibrilación ventricular?", opts: ["Entre 25 y 30 miliamperios de corriente continua", "Una intensidad siempre superior a 1 amperio", "Superiores a 30 mA", "A partir de 10 amperios sostenidos"], ans: 2, exp: "Las corrientes superiores a 30 mA que atraviesan el corazón son suficientes para provocar fibrilación ventricular, siendo potencialmente mortales." },
    { u: "SMYR T8", q: "¿Qué es un contacto eléctrico con una masa en tensión por fallo de aislamiento?", opts: ["Se denomina contacto eléctrico de tipo directo", "Es un fallo grave de masa estructural", "Contacto indirecto", "Derivación peligrosa de conexión a tierra"], ans: 2, exp: "El contacto indirecto se produce cuando tocamos la carcasa o chasis metálico de un equipo que accidentalmente tiene tensión por un defecto interno." },
    { u: "SMYR T8", q: "¿Cómo se denomina el peligro de sufrir daños por la energía de una instalación?", opts: ["Peligro inminente de corte superficial", "Riesgo de contacto con partes en movimiento", "Peligro severo de exposición a descargas", "Riesgo eléctrico"], ans: 3, exp: "Cualquier posibilidad de daño derivado del uso de la energía eléctrica se denomina genéricamente Riesgo Eléctrico." },
    { u: "SMYR T8", q: "¿Cuál es un estándar voluntario de protección del medio ambiente?", opts: ["Certificación oficial de Sistema de Gestión Ambiental", "Estándar regulatorio de Gestión Medio Ambiental", "Norma Verde para empresas industriales", "Ninguna de las opciones propuestas"], ans: 3, exp: "El nombre específico de la norma internacional es ISO 14001 o el reglamento EMAS, los términos 'Sistema de Gestión Ambiental' son el concepto genérico." },
    { u: "SMYR T8", q: "¿Cuál de los siguientes NO es un equipo de protección laboral?", opts: ["Crema solar", "Tapones protectores para ruidos de alta frecuencia", "Guantes aislantes de protección dieléctrica", "Casco de seguridad industrial homologado"], ans: 0, exp: "En el contexto industrial estándar, la crema solar no se considera un EPI convencional, al contrario que los aislamientos, tapones o cascos." },
    { u: "SMYR T8", q: "¿Cuál es la ley principal de prevención de riesgos en España?", opts: ["Ley 31/1995", "Ley 22/2012 de prevención de accidentes graves", "Ley 14/1991 de vigilancia exhaustiva de la salud", "La Constitución Española aprobada en el año 1978"], ans: 0, exp: "La Ley 31/1995 es el pilar fundamental que rige toda la normativa de prevención en España." },
    { u: "SMYR T8", q: "¿Qué indica una señal de color rojo rectangular?", opts: ["Prohibición estricta de paso al personal", "Advertencia de peligro por riesgo mecánico", "Peligro inminente de electrocución por alta tensión", "Lucha contra incendios"], ans: 3, exp: "Las señales rojas rectangulares indican ubicación de equipos de lucha contra incendios. La prohibición usa el rojo pero en forma circular." },
    { u: "SMYR T8", q: "¿Qué pasos exactos rigen la desconexión de una instalación eléctrica?", opts: ["Informar al superior, delimitar el área y asegurar", "Cortar la corriente principal, informar al equipo y actuar", "Preparar las herramientas, asegurar el entorno y actuar", "Ninguna de las opciones"], ans: 3, exp: "El protocolo exacto para trabajar sin tensión está estandarizado en las 'Cinco Reglas de Oro', ninguna de las opciones anteriores refleja fielmente ese orden estricto." },
    { u: "SMYR T8", q: "¿Quién debe garantizar por ley la prevención de riesgos laborales?", opts: ["El empresario", "Todo el conjunto de trabajadores de la planta", "El delegado sindical de prevención y seguridad", "Un recurso preventivo externo contratado"], ans: 0, exp: "La Ley 31/1995 exige al empresario garantizar la salud y seguridad de sus trabajadores en todos los aspectos de su labor." },
    { u: "SMYR T8", q: "Las señales de seguridad y salud se clasifican en:", opts: ["De prohibición general, advertencia térmica e información visual.", "De prohibición, contra incendios, obligación, emergencia e información.", "Señales de advertencia, obligación ineludible y emergencia médica.", "Obligación de paso, advertencia luminosa e información corporativa."], ans: 1, exp: "La clasificación general abarca: prohibición, advertencia/peligro, obligación, salvamento/emergencia y lucha contra incendios." },
    { u: "SMYR T8", q: "¿Qué documento integra la prevención en la gestión de la empresa?", opts: ["El informe mensual de incidencias y accidentes corporativos.", "El plan de prevención de riesgos laborales.", "El certificado internacional de calidad operativa ISO 9001.", "El manual de instrucciones proporcionado por el fabricante."], ans: 1, exp: "El Plan de Prevención es la herramienta matriz de integración operativa." },
    { u: "SMYR T8", q: "¿Qué Real Decreto regula la protección frente al riesgo eléctrico?", opts: ["Real Decreto 485 de 1997 sobre señalética industrial.", "RD 614/2001.", "Real Decreto 1627 de 1997 sobre obras de construcción.", "Normativa estándar europea para baja tensión."], ans: 1, exp: "El RD 614/2001 especifica las normativas y precauciones para proteger a los trabajadores del riesgo eléctrico." },
    { u: "SMYR T8", q: "¿Qué efecto cardíaco produce un choque eléctrico severo?", opts: ["Tetanización progresiva de los músculos dorsales.", "Fibrilación ventricular.", "Asfixia por bloqueo directo de los conductos respiratorios.", "Electrólisis completa del torrente sanguíneo circulante."], ans: 1, exp: "La fibrilación ventricular descoordina los latidos del corazón, impidiendo bombear sangre." },
    { u: "SMYR T8", q: "¿Qué es la tetanización muscular?", opts: ["Una quemadura grave de tercer grado en la epidermis.", "El movimiento incontrolado que impide soltar el conductor.", "La pérdida temporal de la memoria tras el accidente.", "El aumento súbito de la temperatura corporal interna."], ans: 1, exp: "Los músculos se contraen al paso de la corriente, 'pegando' a la víctima al cable." },
    { u: "SMYR T8", q: "¿Cuál es el riesgo indirecto más habitual tras un choque eléctrico?", opts: ["Caídas de altura o golpes contra objetos contiguos.", "La destrucción de los equipos de medida y verificación.", "El daño auditivo por el ruido de la descarga eléctrica.", "La intoxicación por inhalación de gases derivados del ozono."], ans: 0, exp: "A menudo el espasmo hace que el trabajador caiga de una escalera o se golpee contra una máquina." },
    { u: "SMYR T8", q: "¿Qué factor NO determina la gravedad de un accidente eléctrico?", opts: ["La intensidad total de la corriente que circula por el cuerpo.", "El trayecto físico de la corriente a través de los órganos.", "El color del plástico aislante del conductor afectado.", "La resistencia eléctrica natural que opone el cuerpo humano."], ans: 2, exp: "La gravedad depende de factores físicos y fisiológicos, no del color del plástico." },
    { u: "SMYR T8", q: "¿Cuál es la primera regla de oro eléctrica?", opts: ["Comprobar minuciosamente la ausencia total de voltaje.", "Desconectar las posibles fuentes de tensión.", "Poner a tierra y en cortocircuito todas las líneas.", "Bloquear mecánicamente los interruptores principales."], ans: 1, exp: "El primer paso indispensable es efectuar el corte visible y aislar la instalación." },
    { u: "SMYR T8", q: "¿Qué exige el segundo paso de las Reglas de Oro?", opts: ["Limpiar cuidadosamente el interior del cuadro eléctrico.", "Bloquear y señalizar los dispositivos de corte.", "Llamar por radio al supervisor general de planta.", "Medir con exactitud la resistencia de la pica de tierra."], ans: 1, exp: "Consiste en poner candados y carteles en los interruptores para que nadie los vuelva a activar." },
    { u: "SMYR T8", q: "¿En qué consiste la tercera Regla de Oro?", opts: ["En colocarse todos los equipos de protección individual necesarios.", "En verificar la ausencia de tensión en los conductores.", "En cortocircuitar de forma segura todas las fases vivas.", "En avisar a los compañeros del inicio de las maniobras."], ans: 1, exp: "Se utiliza un polímetro o detector de voltaje para confirmar que no queda energía residual." },
    { u: "SMYR T8", q: "¿Cuál es la cuarta Regla de Oro?", opts: ["Desconectar manualmente el interruptor magnetotérmico general.", "Puesta a tierra y cortocircuito.", "Señalizar todo el perímetro de la zona de trabajo con conos.", "Limpiar los bornes de conexión para evitar falsos contactos."], ans: 1, exp: "Protege al técnico drenando la corriente a tierra si por error alguien reconecta la luz." },
    { u: "SMYR T8", q: "¿Qué indica la quinta Regla de Oro?", opts: ["Que el trabajo de reparación ha terminado exitosamente.", "Señalizar para delimitar la zona de trabajo.", "Que se puede restaurar el suministro eléctrico general.", "Que es el momento adecuado para recoger las herramientas."], ans: 1, exp: "Balizar físicamente la zona previene que un trabajador despistado toque partes contiguas con tensión." },
    { u: "SMYR T8", q: "¿Qué requisito exige el trabajo en tensión en zonas complejas?", opts: ["Que sea realizado por un único operario altamente experto.", "Al menos dos operarios cualificados.", "Que la zona de trabajo disponga de iluminación natural directa.", "Que el personal utilice exclusivamente herramientas de acero puro."], ans: 1, exp: "Nunca se trabaja solo en tensión; un segundo operario puede socorrer o cortar la luz en caso de accidente." },
    { u: "SMYR T8", q: "¿Qué material aísla los elementos activos en trabajos bajo tensión?", opts: ["Planchas de material altamente conductor.", "Material aislante como alfombras o banquetas.", "Recubrimientos provisionales de papel de aluminio grueso.", "Cinta adhesiva común de embalaje industrial transparente."], ans: 1, exp: "Tanto el entorno como las herramientas deben ser dieléctricos para aislar al técnico." },
    { u: "SMYR T8", q: "¿Qué significa el acrónimo EPI?", opts: ["Elementos de Producción Industrial automatizada.", "Equipo de Protección Individual.", "Estándar de Protección Integral para trabajadores.", "Estructura de Prevención Interna corporativa."], ans: 1, exp: "Es todo equipo destinado a ser llevado por el trabajador para su seguridad personal." },
    { u: "SMYR T8", q: "¿Cuál es un EPI básico ante riesgos eléctricos?", opts: ["Pulseras o relojes con eslabones de metal templado.", "Guantes y calzado dieléctrico.", "Auriculares de protección auditiva con música ambiental.", "Camisetas de algodón transpirable de manga corta ligera."], ans: 1, exp: "Las manos y los pies son los puntos de entrada y salida habituales, necesitan aislamiento total." },
    { u: "SMYR T8", q: "¿Qué normativa rige las señales de seguridad en el trabajo?", opts: ["La normativa medioambiental internacional ISO 14001.", "ISO 7010 y RD 485/1997.", "El reglamento electrotécnico de baja tensión UNE 20324.", "La estandarización americana de instrumentación ISA-S5.1."], ans: 1, exp: "La ISO 7010 estandariza los pictogramas a nivel internacional." },
    { u: "SMYR T8", q: "¿Qué indica el color rojo en la señalización industrial?", opts: ["Advertencia clara de un peligro mecánico inminente.", "Prohibición o material contra incendios.", "Obligación ineludible de utilizar equipos de protección individual.", "Situación general de seguridad y vías de evacuación despejadas."], ans: 1, exp: "Se asocia a PARO, prohibición estricta o sistemas de extinción de fuego." },
    { u: "SMYR T8", q: "¿Qué forma y color tienen las señales de advertencia?", opts: ["Círculo azul con un pictograma de color blanco brillante.", "Triángulo amarillo con borde negro.", "Cuadrado verde con bordes e ilustraciones en blanco puro.", "Círculo rojo con una gruesa banda diagonal restrictiva."], ans: 1, exp: "El triángulo amarillo es el estándar mundial para advertir un riesgo." },
    { u: "SMYR T8", q: "¿Qué indican las señales circulares de fondo azul?", opts: ["Prohibición estricta de manipulación de maquinaria pesada.", "Obligación.", "Rutas de evacuación rápida hacia las salidas de socorro.", "Peligro grave por exposición directa a la corriente eléctrica."], ans: 1, exp: "El azul circular indica un mandato de seguridad." },
    { u: "SMYR T8", q: "¿Qué señalizan los carteles rectangulares de fondo verde?", opts: ["Peligro inminente de muerte por electrocución severa.", "Vías de evacuación y botiquines.", "Ubicación exacta de los extintores de polvo químico seco.", "Uso estrictamente obligatorio de casco en la zona de trabajo."], ans: 1, exp: "El verde se reserva para las vías de escape, botiquines y duchas de emergencia." },
    { u: "SMYR T8", q: "¿Qué significan las siglas SGA en el entorno medioambiental?", opts: ["Sistema de Gestión de Activos corporativos y financieros.", "Sistema de Gestión Ambiental.", "Servicio de Generación Automática de energía renovable.", "Supervisión de Guardia Ambiental en turnos nocturnos."], ans: 1, exp: "Es el marco de trabajo para alcanzar los objetivos medioambientales de la empresa." },
    { u: "SMYR T8", q: "¿Qué norma certifica internacionalmente la gestión ambiental?", opts: ["La norma de calidad organizativa e industrial ISO 9001.", "ISO 14001.", "La regulación técnica de prevención y salud ISO 45001.", "El reglamento estricto de certificación de emisiones EMAS."], ans: 1, exp: "La familia ISO 14000 define las buenas prácticas mundiales en ecología corporativa." },
    { u: "SMYR T8", q: "¿Qué es exactamente el Reglamento EMAS?", opts: ["Una ley nacional obligatoria para comercios minoristas y tiendas.", "Instrumento europeo voluntario de auditoría.", "Un dispositivo electrónico para medir la humedad relativa del aire.", "Una señalización gráfica que prohíbe el vertido de líquidos tóxicos."], ans: 1, exp: "El EMAS es la máxima acreditación europea, un peldaño más exigente que la ISO 14001." },
    { u: "SMYR T8", q: "¿Cuál es un beneficio tangible de implementar EMAS?", opts: ["La mejora considerable de la imagen corporativa en el mercado.", "Ahorro económico por menor consumo.", "El incremento general de la motivación y felicidad del personal.", "Una relación mucho más fluida con las autoridades gubernamentales."], ans: 1, exp: "Un beneficio tangible es aquel que se traduce en ahorro directo de dinero o materiales." },
    { u: "SMYR T8", q: "¿Qué requisito documental es fundamental para obtener el EMAS?", opts: ["Presentar un presupuesto detallado de ventas para el próximo año.", "Declaración medioambiental pública validada.", "Un contrato de alquiler en regla de las instalaciones industriales.", "Una lista exhaustiva con todos los empleados contratados en nómina."], ans: 1, exp: "Requiere total transparencia haciendo públicos sus objetivos medioambientales anuales." },
    { u: "SMYR T8", q: "Sobre las herramientas portátiles, las normas de plata recomiendan:", opts: ["Adquirir siempre los equipos más económicos del mercado actual.", "Vigilar sus aislamientos de cable.", "Utilizarlas sin restricciones operativas bajo condiciones de lluvia.", "Prohibir completamente el uso de regletas o cables alargadores largos."], ans: 1, exp: "Un cable pelado de un taladro o radial es una de las causas más comunes de accidentes." },
    { u: "SMYR T8", q: "¿Qué debes hacer antes de ayudar a un compañero electrocutado?", opts: ["Tirarle del brazo rápidamente para apartarlo de la fuente eléctrica.", "Desconectar la tensión general.", "Llamar por teléfono móvil inmediatamente a sus familiares cercanos.", "Verter agua limpia sobre él para enfriar rápidamente las quemaduras."], ans: 1, exp: "Tocar a una persona tetanizada te incluirá en el circuito eléctrico, electrocutándote a ti también." },
    { u: "SMYR T8", q: "¿Qué es una medida de protección colectiva?", opts: ["Un casco de seguridad que comparten varios técnicos distintos.", "Barandillas o redes.", "El sistema organizativo de la seguridad social en toda la empresa.", "Una póliza de seguro de vida contratada de manera grupal y conjunta."], ans: 1, exp: "Tienen prioridad legal frente al EPI individual porque blindan el entorno entero." },
    { u: "SMYR T8", q: "¿Qué normativa trata sobre la señalización de seguridad?", opts: ["La ley que estipula el precio oficial de los equipos extintores.", "RD 485/1997.", "El reglamento interno que define los horarios de las oficinas técnicas.", "La directriz europea para la gestión integral de residuos nucleares."], ans: 1, exp: "Transpuso la directiva europea sobre cómo señalizar correctamente los peligros." },
    { u: "SMYR T8", q: "¿Qué Real Decreto regula la manipulación de cargas?", opts: ["El Real Decreto 485 del año 1997 sobre la señalización en planta.", "RD 487/1997.", "El Real Decreto 614 del año 2001 sobre el riesgo eléctrico industrial.", "El Real Decreto 1627 del año 1997 sobre seguridad en la construcción."], ans: 1, exp: "Define los pesos máximos y posturas para evitar lesiones músculo-esqueléticas en la espalda." },
    { u: "SMYR T8", q: "¿Qué se debe hacer con los restos plásticos de los automatismos?", opts: ["Depositarlos directamente en el cubo de la basura común del taller.", "Separarlos por tipo.", "Enterrarlos bajo tierra en zonas ajardinadas alejadas de la planta.", "Quemarlos de forma controlada en bidones habilitados en el exterior."], ans: 1, exp: "Metales, plásticos o componentes electrónicos deben reciclarse en contenedores adecuados." },
    { u: "SMYR T8", q: "¿Qué advierte el color amarillo en un entorno industrial?", opts: ["Información general sobre el uso correcto de las herramientas de mano.", "Atención y peligro.", "La localización exacta de un equipo extintor de incendios cercano.", "La prohibición estricta de paso a zonas de alta radiación magnética."], ans: 1, exp: "El amarillo y negro son los colores elegidos visualmente para alertar de atención o peligro inminente." },
    { u: "SMYR T8", q: "¿Qué efecto agudo produce la corriente en los músculos pectorales?", opts: ["Una mejora temporal en la capacidad de dilatación de los pulmones.", "Paro respiratorio por contracción extrema.", "La caída fulminante de todo el cabello en la zona superior de la cabeza.", "Un aumento descontrolado del apetito en las horas posteriores al evento."], ans: 1, exp: "Al atravesar el pecho, la corriente bloquea el diafragma, cortando la respiración." },
    { u: "SMYR T8", q: "¿Por qué es crucial el Plan de Prevención de Riesgos Laborales?", opts: ["Es simplemente un trámite burocrático innecesario para la producción.", "Es la herramienta de integración preventiva.", "Sirve exclusivamente como elemento decorativo en la sala de inspecciones.", "Indica a los empleados por dónde salir cuando finaliza su turno laboral."], ans: 1, exp: "Sistematiza y organiza la prevención desde la misma dirección corporativa de la empresa." },
    { u: "SMYR T8", q: "Para intervenir en instalaciones con tensión, el trabajador debe:", opts: ["Haber descansado al menos doce horas continuas antes de la maniobra.", "Estar autorizado por escrito.", "Realizar la operación completamente descalzo para mejorar su agarre al suelo.", "Asegurarse de no llevar ninguna herramienta de mano durante el proceso."], ans: 1, exp: "Requiere cursos específicos y autorización por escrito para actuar bajo tensión." },
    { u: "SMYR T8", q: "¿Cómo debe ser el calzado en trabajos de riesgo eléctrico?", opts: ["Zapatillas deportivas ligeras que permitan mayor movilidad al operario.", "Aislante o dieléctrico.", "Botas de goma muy fina especialmente diseñadas para ambientes húmedos.", "Sandalias de cuero abierto para mantener los pies secos y ventilados siempre."], ans: 1, exp: "Debe aislar la suela para no cerrar el circuito hacia el suelo." },
    { u: "SMYR T8", q: "¿A qué se refiere la simplificación administrativa del EMAS?", opts: ["A la exención total del pago de impuestos medioambientales a nivel europeo.", "Facilidades en licencias y trámites.", "A la eliminación completa de los informes anuales de estado y producción.", "A la posibilidad de operar prescindiendo del personal de oficinas técnicas."], ans: 1, exp: "Los ayuntamientos confían más en empresas EMAS, otorgándoles licencias de forma ágil." },
    { u: "SMYR T8", q: "¿Cuál es el objetivo de colocar un candado en un disyuntor?", opts: ["Que nadie pueda encender la máquina mientras el técnico repara los cables.", "Garantizar que la cubierta frontal de la máquina no se llene de polvo.", "Indicar al operario el lugar exacto donde se han dejado las herramientas.", "Demostrar visiblemente a la dirección general de la planta que se está trabajando."], ans: 0, exp: "Un candado físico impide que un tercero suba el automático por error." },
    { u: "SMYR T8", q: "¿Con qué se comprueba la ausencia de tensión en la regla tres?", opts: ["Golpeando levemente los cables con el mango de goma de un martillo duro.", "Con un detector de voltaje certificado.", "Acercando el dorso de la mano del compañero al cuadro de distribución principal.", "Haciendo un corto intencionado con un destornillador de punta plana metálica."], ans: 1, exp: "Un comprobador de ausencia de tensión certificado es vital para confirmar el corte." },
    { u: "SMYR T8", q: "¿Por qué se cortocircuita y pone a tierra la instalación?", opts: ["Para poder reutilizar posteriormente los cables de cobre que sobran del montaje.", "Para drenar la corriente si hay realimentación.", "Para evitar vibraciones mecánicas indeseadas y asegurar que la máquina no se mueva.", "Para proporcionar una masa estable que permita iluminar el cuadro eléctrico oscuro."], ans: 1, exp: "Si la línea recibe tensión por error, la corriente fluirá a tierra activando la protección." },
    { u: "SMYR T8", q: "¿Cuál es un claro beneficio intangible de la certificación EMAS?", opts: ["La reducción sustancial de multas y sanciones económicas por incumplimientos.", "Mejora de la imagen de marca.", "El ahorro mensual comprobado en la factura general de consumo de agua potable.", "La recuperación económica derivada de la venta de subproductos industriales."], ans: 1, exp: "La imagen de marca no se cuenta en euros directamente pero mejora sustancialmente a largo plazo." },
    { u: "SMYR T8", q: "¿Qué caracteriza los denominados trabajos en tensión?", opts: ["Son aquellas intervenciones que el operario realiza bajo gran presión laboral y estrés.", "Se hacen usando protección especial aislante.", "Se basan en inspecciones visuales realizadas a varios metros de distancia de la zona.", "Están permitidos únicamente durante los meses estivales con condiciones muy secas."], ans: 1, exp: "Requieren el uso de mantas, pértigas, cascos y herramientas aisladas de 1000V." },
    { u: "SMYR T8", q: "¿Qué equipo ampara la cabeza ante roces con cables aéreos vivos?", opts: ["Una gorra convencional de tela gruesa con visera rígida y sin componentes metálicos.", "Casco de seguridad dieléctrico.", "Un sombrero ancho fabricado con paja trenzada para ambientes de extremado calor.", "Un pasamontañas de lana gruesa que cubra íntegramente las orejas y el cráneo interno."], ans: 1, exp: "Un casco de obra dieléctrico no lleva remaches metálicos y aísla la cabeza de cables." },
    { u: "SMYR T8", q: "¿Qué significa un panel azul redondo con un rostro y gafas?", opts: ["Indica la prohibición terminante de utilizar gafas de sol graduadas en el área.", "Uso obligatorio de gafas protectoras.", "Avisa de la proximidad de una tienda de equipos ópticos dentro de las instalaciones.", "Señaliza el peligro constante de deslumbramiento severo provocado por soldaduras."], ans: 1, exp: "El azul circular indica siempre un equipo de protección obligatorio." },
    { u: "SMYR T8", q: "¿Cómo se debe proceder ante unos guantes dieléctricos agrietados?", opts: ["Continuar usándolos con normalidad operativa hasta que el plástico se rompa del todo.", "Desecharlos y sustituirlos.", "Reparar la zona dañada utilizando cinta adhesiva aislante de altas prestaciones técnicas.", "Almacenarlos en un cajón seco y seguro para utilizarlos en caso de extrema emergencia."], ans: 1, exp: "Unos guantes aislantes con un pequeño poro ya no te protegen de la electricidad." },
    { u: "SMYR T8", q: "¿Qué nivel de obligación tiene la normativa ISO 14001?", opts: ["Es un requisito obligatorio impuesto por la ley europea para absolutamente todas las empresas.", "Es una certificación voluntaria.", "Únicamente es un requisito indispensable para las grandes plantas de fabricación de automóviles.", "Es una normativa de carácter estrictamente secreto y confidencial en el ámbito industrial."], ans: 1, exp: "Ninguna ley obliga a certificar la ISO 14001, las empresas la implementan libremente." },
    { u: "SMYR T8", q: "¿Qué acción cierra el ciclo de las Cinco Reglas de Oro?", opts: ["Abandonar de inmediato las instalaciones una vez finalizadas las reparaciones requeridas.", "Balizar y delimitar la zona.", "Proceder al encendido general y sincronizado de toda la maquinaria pesada de la planta.", "Realizar la pausa correspondiente y estipulada legalmente para el desayuno de los operarios."], ans: 1, exp: "Es la quinta regla, y acota el espacio seguro aislando las zonas contiguas que sigan teniendo tensión." },
    { u: "SMYR T8", q: "¿Qué síntoma genera el flujo de 10 mA por el sistema muscular?", opts: ["La muerte celular fulminante e instantánea de la gran mayoría de los tejidos internos expuestos.", "Contracciones dolorosas.", "Ningún efecto destacable, ya que la corriente eléctrica es imperceptible a niveles tan bajos.", "Un ligero cosquilleo continuo y relativamente agradable en las terminaciones nerviosas externas."], ans: 1, exp: "A partir de 10 mA los músculos se contraen dolorosamente y la víctima puede quedarse 'pegada'." }
];
